    trocaTermicaLenta = 0.01;

    semTermo = 0;

    dtCicMin = sp.dtCicMin;

    monitConvPerm = 1000.;
    monitConvPermBase = 1.;

    alteraTempo = 0;
    redeParalelaCCsecundario = sp.redeParalelaCCsecundario;
    redeParalelaP = sp.redeParalelaP;
    redeParalelaS = sp.redeParalelaS;

    presVet.clear();
    jVet.clear();
    alfVet.clear();
    tVet.clear();
    dtSim.clear();
    dtCFL.clear();
