                MultPd = celula[i + 1].QL * (1 - betI1) * (1 - bsw1) / bo1;
            residuoP = (volpesFim - celula[i].VolPesaST) * at / dt + (MultPd - MultPe) / dx - fonteP / dx;
            MultAe = 0.;
