                VISCH[i] = (dt * (viscHF * fonteP / dx + 1. * viscHini * residuoP - (viscH1 * MultPd - viscH0 * MultPe) / dx) + viscHini * celula[i].VolPesaST * at) / (volpesFim * at - 0. * residuoP * dt);
