            celula[ncel - 1].term2R = 0;
            celula[ncel].MC = celula[ncel].MC - celula[ncel].Mliqini;
            celula[ncel].Mliqini = 0;
            celula[ncel].term1 = 0;
            celula[ncel].term2 = 0;
