double SProd::marchaProdPerm1(double pchute) {

    int corrigechute = 1;
    double alfini = 0.;
    double betini = 0.;

    // estimativa da fracao de vazio na primeira celula do sistema
    if (celula[0].acsr.tipo == 0) { // sem nenhuma fonte
        celula[0].temp = arq.celp[0].textern;
        alfini = 1.;
        betini = 0.;
        if (arq.flashCompleto == 2) {
            if (arq.tabelaDinamica == 0)
                celula[0].flui.atualizaPropComp(pchute, celula[0].temp);
        }
    } else if (celula[0].acsr.tipo == 1) { // fonte de gas
        celula[0].temp = celula[0].acsr.injg.temp;
        if (arq.flashCompleto == 2) {
            if (arq.tabelaDinamica == 0)
                celula[0].flui.atualizaPropComp(pchute, celula[0].temp);
            celula[0].acsr.injg.FluidoPro.atualizaPropComp(pchute, celula[0].temp, -1, NULL, NULL, celula[0].acsr.injg.seco);
        }
        if (celula[0].acsr.injg.seco == 1) {
            alfini = 1.;
            betini = 0.;
        } else {
            double masgas = celula[0].acsr.injg.VMas(pchute, celula[0].temp);
            double tit;
            if (arq.flashCompleto != 2)
                tit = celula[0].acsr.injg.FluidoPro.FracMassHidra(1., 20.);
            else
                tit = celula[0].acsr.injg.FluidoPro.dStockTankVaporMassFraction;
            double masT = masgas / tit;
            tit = celula[0].acsr.injg.FluidoPro.FracMassHidra(pchute, celula[0].temp);
            double qgas = masT * tit /
                          celula[0].acsr.injg.FluidoPro.MasEspGas(pchute, celula[0].temp);
            double qliq = masT * (1. - tit) /
                          celula[0].acsr.injg.FluidoPro.MasEspLiq(pchute, celula[0].temp);
            double qcomp = celula[0].acsr.injg.razCompGas *
                           celula[0].acsr.injg.QGas * celula[0].acsr.injg.fluidocol.MasEspFlu(1., 20.) /
                           celula[0].acsr.injg.fluidocol.MasEspFlu(pchute, celula[0].temp);
            qcomp /= 86400.;
            alfini = qgas / (qliq + qcomp + qgas);
            if ((fabs(qcomp) + fabs(qliq)) > 1e-15)
                betini = fabs(qcomp) / (fabs(qcomp) + fabs(qliq));
            else
                betini = 0.;
        }
    } else if (celula[0].acsr.tipo == 2) { // fonte de liquido, faz-se uma estimativa a partir
        // da vazÃƒÂ£o volumÃƒÂ©trica das fases, fracao de vazio = fracao de vazio sem escorregamento
        celula[0].temp = celula[0].acsr.injl.temp;
        if (arq.flashCompleto == 2) {
            if (arq.tabelaDinamica == 0)
                celula[0].flui.atualizaPropComp(pchute, celula[0].temp);
            celula[0].acsr.injl.FluidoPro.atualizaPropComp(pchute, celula[0].temp);
        }
        double qgas = celula[0].acsr.injl.QLiq * (1 - celula[0].acsr.injl.bet) *
                      (1. - celula[0].acsr.injl.FluidoPro.BSW) *
                      (celula[0].acsr.injl.FluidoPro.RGO -
                       celula[0].acsr.injl.FluidoPro.rDgD * celula[0].acsr.injl.FluidoPro.RS(pchute, celula[0].temp) * 6.29 / 35.31467) *
                      celula[0].acsr.injl.FluidoPro.Deng * 1.225 / celula[0].acsr.injl.FluidoPro.MasEspGas(pchute, celula[0].temp);
        double qliq = celula[0].acsr.injl.QLiq * (1 - celula[0].acsr.injl.bet) *
                          (1. - celula[0].acsr.injl.FluidoPro.BSW) * celula[0].acsr.injl.FluidoPro.BOFunc(pchute, celula[0].temp) +
                      celula[0].acsr.injl.QLiq * (1 - celula[0].acsr.injl.bet) *
                          celula[0].acsr.injl.FluidoPro.BSW * celula[0].acsr.injl.FluidoPro.BAFunc(pchute, celula[0].temp) +
                      celula[0].acsr.injl.QLiq * celula[0].acsr.injl.bet;
        alfini = qgas / (qliq + qgas);
        betini = celula[0].acsr.injl.bet;
    } else if (celula[0].acsr.tipo == 3) { // IPR no inicio da tubulacao
        // da mesma maneira que no caso de fonte de liquido, fracao de vazio= sem escorregamento
        celula[0].temp = celula[0].acsr.ipr.Tres;
        if (arq.flashCompleto == 2) {
            if (arq.tabelaDinamica == 0)
                celula[0].flui.atualizaPropComp(pchute, celula[0].temp);
            celula[0].acsr.ipr.FluidoPro.atualizaPropComp(pchute, celula[0].temp);
        }
        double qgas = celula[0].acsr.ipr.MasG(pchute, celula[0].temp) /
                      celula[0].acsr.ipr.FluidoPro.MasEspGas(pchute, celula[0].temp);
        double qliq = celula[0].acsr.ipr.MasL(pchute, celula[0].temp) /
                      celula[0].acsr.ipr.FluidoPro.MasEspLiq(pchute, celula[0].temp);
        alfini = qgas / (qliq + qgas);
        betini = 0.;
    } else if (celula[0].acsr.tipo == 15) { // IPR no inicio da tubulacao
        // da mesma maneira que no caso de fonte de liquido, fracao de vazio= sem escorregamento
        celula[0].temp = celula[0].acsr.radialPoro.tRes;
        celula[0].pres = pchute;
        if (arq.flashCompleto == 2) {
            if (arq.tabelaDinamica == 0)
                celula[0].flui.atualizaPropComp(pchute, celula[0].temp);
            celula[0].acsr.radialPoro.flup.atualizaPropComp(pchute, celula[0].temp);
        }
        renovaFonte(0);
        double qgas = celula[0].acsr.radialPoro.fluxIniG /
                      celula[0].acsr.radialPoro.flup.MasEspGas(pchute, celula[0].temp);
        double qliq = (celula[0].acsr.radialPoro.fluxIni + celula[0].acsr.radialPoro.fluxIniA) /
                      celula[0].acsr.radialPoro.flup.MasEspLiq(pchute, celula[0].temp);
        alfini = qgas / (qliq + qgas);
        betini = 0.;
    } else if (celula[0].acsr.tipo == 16) { // IPR no inicio da tubulacao
        // da mesma maneira que no caso de fonte de liquido, fracao de vazio= sem escorregamento
        celula[0].temp = celula[0].acsr.poroso2D.dados.tRes;
        celula[0].pres = pchute;
        if (arq.flashCompleto == 2) {
            if (arq.tabelaDinamica == 0)
                celula[0].flui.atualizaPropComp(pchute, celula[0].temp);
            celula[0].acsr.poroso2D.dados.flup.atualizaPropComp(pchute, celula[0].temp);
        }
        renovaFonte(0);
        double qgas = celula[0].acsr.poroso2D.dados.transfer.fluxIniG /
                      celula[0].acsr.poroso2D.dados.flup.MasEspGas(pchute, celula[0].temp);
        double qliq = (celula[0].acsr.poroso2D.dados.transfer.fluxIni + celula[0].acsr.poroso2D.dados.transfer.fluxIniA) /
                      celula[0].acsr.poroso2D.dados.flup.MasEspLiq(pchute, celula[0].temp);
        alfini = qgas / (qliq + qgas);
        betini = 0.;
    } else if (celula[0].acsr.tipo == 10) { // fonte de massa no inicio da tubulacao
        // da mesma maneira que no caso de fonte de liquido, fracao de vazio= sem escorregamento
        celula[0].temp = celula[0].acsr.injm.temp;
        if (arq.flashCompleto == 2) {
            if (arq.tabelaDinamica == 0)
                celula[0].flui.atualizaPropComp(pchute, celula[0].temp);
            celula[0].acsr.injm.FluidoPro.atualizaPropComp(pchute, celula[0].temp);
        }
        if (celula[0].acsr.injm.condTermo == 0) {
            celula[0].pres = pchute;
            renovaFonte(0);
        }
        double qgas = celula[0].acsr.injm.MassG /
                      celula[0].acsr.injm.FluidoPro.MasEspGas(pchute, celula[0].temp);
        double qliq = celula[0].acsr.injm.MassP /
                          celula[0].acsr.injm.FluidoPro.MasEspLiq(pchute, celula[0].temp) +
                      celula[0].acsr.injm.MassC /
                          celula[0].acsr.injm.fluidocol.MasEspFlu(pchute, celula[0].temp);
        alfini = qgas / (qliq + qgas);
        betini = 0.;
    } else { // se nenhuma das opcoes, fracao de vazio=1
        celula[0].temp = arq.celp[0].textern;
        if (arq.flashCompleto == 2) {
            if (arq.tabelaDinamica == 0)
                celula[0].flui.atualizaPropComp(pchute, celula[0].temp);
        }
        alfini = 1.;
        betini = 0.;
    }
    if (celula[0].acsr.tipo == 15) {
        celula[0].flui.BSW = celula[0].acsr.radialPoro.BSW;
    } else if (celula[0].acsr.tipo == 16) {
        celula[0].flui.BSW = celula[0].acsr.poroso2D.dados.transfer.BSW;
    }
    if (fabs(alfini) < 1e-6)
        alfini = 0.;
    if (fabs(betini) < 1e-6)
        betini = 0.;

    // esta marcha e feita para quando se tem alguma fonte no inicio da tubulacao,
    // portanto, admite-se que o duto esta fechado e coloca-se uma fonte no centro da
    // primeira celula. As vazoes na fronteira esquerda da celula sÃ£o portanto = 0
    celula[0].tempL = celula[0].temp;
    celula[1].tempL = celula[0].temp;
    celula[0].tempini = celula[0].temp;

    celula[0].ML = 0.;
    celula[0].MC = 0.;
    celula[1].ML = 0.;
    celula[0].MliqiniL = 0.;
    celula[0].Mliqini = 0.;
    celula[1].MliqiniL = 0.;
    celula[0].MComp = 0.;
    celula[0].QLL = 0.;
    celula[0].QL = 0;
    celula[1].QLL = 0.;
    celula[0].QG = 0.;
    double masfim = 1.;
    double masfim0 = -10;
    double presteste = 1.;
    double presteste0 = -10;
    iterperm = 0;

    int limIter = 2; // limite de iteracoes quando a opcao de aceleracao da convergencia esta desligado. desaconselhavel
    // desligar esta opcao, os ganhos sao pouco e a convergencia se torna instavel, principalmente
    // quando o tramo faz perte de um sistema de redes
    if (arq.AceleraConvergPerm == 1) { // opcao aceleracao de convergencia ligada
        limIter = 1;                   // em geral faz-se apenas duas iteracoes de marcha para um determinado chute
        if (arq.lingas == 1 && celulaG[0].tipoCC == 0)
            limIter = 1; // no caso de se ter
        // uma condicao de contorno na injecao de gas = pressao, observou-se que o acoplamento dinamico
        // entre a linha de gas e de producao e mais difoicil, para se conseguir um sistema
        // melhor acoplado, deve-se fazer uma marcha iterativa a mais
    }
    // arq.CriterioConvergPerm Ã© um criterio de convergencia da marcha, so faz sentido
    // quando a aceleracao de convergencia esta desligada. Observe que esta convergencia nÃ£o
    // e de fato a conevregencia do problema, e apenas um repeticao de marcha para um determinado
    // chute de pressao ou de vazao no inicio da tubulacao. O que a convergencia busca de fato e
    // determinar qual a pressao ou vazao de fundo que satisfaz as condicoes de contorno no fim
    // da tubulacao, esta busca e feita nos metodos de busca.
    while ((fabs(masfim - masfim0) / fabs(masfim) > arq.CriterioConvergPerm ||
            fabs(presteste - presteste0) / fabs(presteste) > arq.CriterioConvergPerm) &&
           iterperm < limIter) {

        masfim0 = masfim;
        presteste0 = presteste;
        if (iterperm == 0 && arq.lingas > 0 && arq.nvalvgas > 0 && verificaAcop == 1)
            IniciaconectaColunaPerm(); // antes de iniciar a primeira iteracao de marcha,
        // faz-se uma estimativa inicial de como se da o acopamento termico entre a coluna e o anular,
        // caso se tenha linha de gas
        else if (arq.lingas > 0 && arq.nvalvgas > 0 && verificaAcop == 1)
            conectaColunaPerm(); // acoplamento termico feito com valores de pressao e temperatura
        // obtidas na primeira iteracao de marcha
        int i;
        corrigechute = 1;
        while (corrigechute == 1) { // opcao antiga, ja nao tem mais efeito
            // efetivamente, este while sempre so e feito uma vez, quando a marcha consegue ir ate
            // a ultima celula sem problemas, caso ocorra algum problema, a marcha e finalizada e
            // sai do metodo retornando ou 1e10 ou -1e10

            // inicializando as pressoes e fracoes volumetricas das celulas iniciais, centro de celula
            // e fronteira de celula
            celula[0].presauxL = pchute;
            celula[0].presLini = pchute;
            celula[0].presL = pchute;
            celula[0].pres = pchute;
            celula[1].presL = pchute;
            celula[0].presini = pchute;
            celula[1].presLini = pchute;
            celula[0].presaux = pchute;
            celula[1].presauxL = pchute;

            celula[0].alf = alfini;
            celula[0].alfini = alfini;
            celula[0].bet = betini;
            celula[0].betini = betini;
            celula[1].alfL = celula[0].alf;
            celula[1].alfLini = celula[0].alf;
            celula[0].alfPigD = celula[0].alf;
            celula[0].alfPigDini = celula[0].alf;
            celula[0].alfPigE = celula[0].alf;
            celula[0].alfPigEini = celula[0].alf;
            celula[1].betL = celula[0].bet;
            celula[1].betLini = celula[0].bet;
            celula[0].betPigD = celula[0].bet;
            celula[0].betPigDini = celula[0].bet;
            celula[0].betPigE = celula[0].bet;
            celula[0].betPigEini = celula[0].bet;
            celula[0].betI = celula[0].bet;
            celula[1].betLI = celula[0].bet;
            // verifica se ja existe algum problema no inicio da marcha
            if (celula[0].pres <= 0.1 ||
                (arq.usaTabela == 1 && (arq.tabent.pmin - celula[0].pres) > (*vg1dSP).localtiny))
                return -1e10;
            else if ((celula[0].acsr.tipo == 3 &&
                      (celula[0].acsr.ipr.Pres - celula[0].pres) < (*vg1dSP).localtiny))
                return 1e10;
            // IniciaVazValvGasPerm e um metodo que faz uma estimativa da vazao na valvula de GL
            // quando ainda nao foi feita a marcha na linha de gas. Neste caso, ele recebe o
            // indice da celula de producao e verifica se nesta celula existe uma VGL, se existir,
            // caso a condicao na linha de gas seja vazao injetada, divide a vazao injetada pelo numero de
            // valvulas e indica este valor para a VGL relacionada a celula de producao
            // caso a condicao seja pressao de injecao, faz-se uma estimativa da pressao na linha de gas
            // na posicao da VGL por hidrotatica e com isto se calcula a vazao de injecao da VGL
            if (arq.lingas > 0 && arq.nvalvgas > 0 && iterperm == 0 && monitConvPerm > 0.1) {
                if (celulaG[0].tipoCC == 0)
                    hidroLinServ();
                IniciaVazValvGasPerm(0);
            }
            i = 1;
            // inicio da marcha propriamente dita
            while (i <= ncel && celula[i - 1].pres >= 0.1 && fabs(pchute - celula[0].pres) < (*vg1dSP).localtiny) {

                RenovaPresPermMon(i, 0); // avanco da marcha para obter a pressao na fronteira esquerda
                // da celula i
                // teste para ver se ocorreu algum problema:
                if (arq.usaTabela == 1 && (arq.tabent.pmax - celula[i].presaux) < (*vg1dSP).localtiny)
                    return 1e10;
                if (celula[i].presaux <= 0.1 ||
                    (arq.usaTabela == 1 && (arq.tabent.pmin - celula[i].presaux) > (*vg1dSP).localtiny)) {
                    return -1e10;
                }
                atualizaPeriPmonProd(i); // atualizacao da pressao da fronteira esquerda,
                // caso exista alguma BCS ou incremento de pressao
                if (i == 312) {
                    int para;
                    para = 0;
                }
                if (arq.flashCompleto != 2)
                    RenovaMassPerm(i); // verifica se existe alguma fonte na celula anterior, com isto, atualiza
                // as vazoes massica na fronteira a esquerda, alÃ©m das propriedades dos fluidos,
                // densidade do gas, RGO, API, BSW, beta
                else
                    RenovaMassPermComp(i);

                if (arq.acopColAnulPermForte == 0 || arq.lingas == 0 || monitConvPerm > 0.1)
                    RenovaTempPerm(i, 0); // faz o avanco da temperatura, da celula i-1 para a celula i
                // verifica se teve algum problema nos limites de temperatura
                // caso se esteja trabalhando com tabela PVTSim
                if (arq.usaTabela == 1 && (celula[i].temp - arq.tabent.tmin) < (*vg1dSP).localtiny)
                    celula[i].temp = arq.tabent.tmin;
                atualizaPeriTempProd(i); // mera atualizacao de atributos de temperatura a esquerda e a direita
                RenovaPresPermJus(i, 0); // evolui a pressao  fronteira a esquerda da celula i para o
                // seu centro de celula
                // verifica se ocorreu algum problema nesta evolucao de de pressao no centro da
                // celula
                if (arq.usaTabela == 1 && (arq.tabent.pmax - celula[i].pres) < (*vg1dSP).localtiny) {
                    return 1e10;
                }
                if (celula[i].pres <= 0.1 ||
                    (arq.usaTabela == 1 && (arq.tabent.pmin - celula[i].pres) > (*vg1dSP).localtiny)) {
                    return -1e10;
                }
                atualizaPeriPjusProd(i); // mera atualizacao de atributos que guardam valores de pressao
                // das celulas a esquerda e a direita
                for (int j = 0; j < arq.nvalvgas; j++) { // reavaliacao da vazao da valvula de gas lift, quando
                    // a celula tem uma.
                    // P.S. parece uma acao desnecessÃ¡ria e talvez atÃ© um complicador
                    // densecessario, em vavliacao
                    if (posicVGLP[j] == i) {
                        int k = posicVGLG[j];
                        calcVazGasPerm(k);
                    }
                }
                if (arq.tipoFluido == 0)
                    RenovaTransMassPerm(i - 1);
                else
                    RenovaTransMassPermGas(i - 1); // caso seja uma tabela PVTSim, calcula-se a
                // taxa de transferÃªncia de massa entre as fases para o uso no calculo de
                // calor latente da equacao de energia
                if (arq.ordperm > 1) { // correcao de segunda ordem
                    double D0presaux = celula[i].presaux - celula[i - 1].pres;
                    double D0pres = celula[i].pres - celula[i].presaux;
                    double D0temp = celula[i].temp - celula[i - 1].temp;
                    RenovaPresPermMon(i, 1);
                    atualizaPeriPmonProd(i);
                    RenovaMassPerm(i);
                    RenovaTempPerm(i, 1);
                    if (isnan(celula[i].temp)) {
                        if (arq.transiente == 0 && arq.AP == 0)
                            // neste caso, se finaliza a simulacao, nao tem um transiente
                            // a ser feito a seguir e nem se estÃ¡ em uma rede
                            NumError(
                                "Temperatrura na linha de producao com valor NaN em marchaProdPerm1");
                        else {
                            // apresenta apenas um aviso
                            cout << "#################PERMANENTE FALHOU EM SUA CONVERGÃŠNCIA##############################" << endl;
                            // se for em uma iteracao de rede, apos a primeira iteracao
                            if ((*vg1dSP).iterRede > 0)
                                return -1.1e10;
                            // se logo apos tem uma simulacao transiente ou se esta na primeira iteracao de rede
                            else
                                return 1.1e10;
                        }
                    }
                    RenovaPresPermJus(i, 1);
                    celula[i].pres = 0.5 * (celula[i].presaux + D0pres + celula[i].pres);
                    celula[i].presaux = 0.5 * (celula[i - 1].pres + D0presaux + celula[i].presaux);
                    celula[i].temp = 0.5 * (celula[i - 1].temp + D0temp + celula[i].temp);
                    atualizaPeriPjusProd(i);
                    atualizaPeriPmonProd(i);
                    atualizaPeriTempProd(i);
                    RenovaMassPerm(i);
                    if (arq.tipoFluido == 0)
                        RenovaTransMassPerm(i - 1);
                    else
                        RenovaTransMassPermGas(i - 1);
                }

                // apÃ³s se atingir a pressao no centro da celula i, primeira iteracao de marcha
                // verifica-se se existe uma VGL em i e faz-se uma estimativa inicial da Vazao de
                // GL (caso exista linha de gas). Observar que isto sÃ³ Ã© feito para a iteracao zero.
                if (arq.lingas > 0 && arq.nvalvgas > 0 && iterperm == 0 && monitConvPerm > 0.1)
                    IniciaVazValvGasPerm(i);
                i++;

                if (isnan(celula[i - 1].pres) || isnan(celula[i - 1].temp) || isnan(celula[i - 1].alf)) {
                    return 1e10;
                }

                // teste para verificar se a pressao do centro de celula ficou acima
                // da pressao estatica de uma eventual IPR
                if (celula[i - 1].pres <= 0.1 ||
                    (arq.usaTabela == 1 && (arq.tabent.pmin - celula[i - 1].pres) > (*vg1dSP).localtiny)) {
                    return -1e10;
                } else if ((celula[i - 1].acsr.tipo == 3 &&
                            ((celula[i - 1].acsr.ipr.Pres - celula[i - 1].pres) < (*vg1dSP).localtiny) && i == 1)) {
                    return 1e10;
                }
            }
            if (i == ncel + 1)
                corrigechute = 0; // fim da marcha
        }
        // apÃ³s o fim da marcha da linha de produÃ§Ã£o, Ã© feita a marcha da linha de gas
        // caso exista
        if (pchute > 0 && arq.lingas > 0 && arq.nvalvgas > 0) {
            if (celulaG[0].tipoCC == 0) {            // marcha para o caso, pressao de injecao
                if (arq.chokes.abertura[0] >= 0.2) { // choke de injecao inativo
                    for (int iter = 0; iter < 1; iter++) {
                        marchaGasPerm1();
                    }
                } else
                    buscaGasPresPerm3(); // choke de injecao ativo
            } else
                buscaGasPresPerm2(); // marcha na linha de gas para o caso de vazao de injecao
        }

        if (arq.acopColAnulPermForte > 0 && arq.lingas > 0 && semTermo == 0) {
            atualizaProp();
            atualizaVelTermPerm();
            calcDTPseudoTrans();
            conectaColuna();
            for (int kontaPseudo = 0; kontaPseudo < arq.acopColAnulPermForte; kontaPseudo++) {
                for (int iterm = 0; iterm <= ncelGas; iterm++)
                    celulaG[iterm].tempini = celulaG[iterm].temp;
                for (int iterm = 1; iterm <= ncelGas; iterm++) {
                    calctempGas(iterm, celulaG[iterm - 1].tempini, 1);
                }
                celula[0].tempini = celula[0].temp;
                celula[1].tempLini = celula[1].tempL;
                celula[1].tempL = celula[0].temp;
                for (int iterm = 1; iterm <= ncel; iterm++) {
                    celula[iterm].tempini = celula[iterm].temp;
                }
                for (int iterm = 1; iterm <= ncel; iterm++) {
                    calctemp(iterm, celula[iterm].tempini, 1);
                }
                atualizaProp();
                calcDTPseudoTrans();
                conectaColuna();
            }
        }

        masfim = celula[ncel - 1].MC; // guarda valor de vazao para se calcular o erro, quando a
        // opcao de acelerador de convergencia esta desligado
        presteste = celula[ncel].pres; // guarda valor de pressao para se calcular o erro, quando a
        // opcao de acelerador de convergencia esta desligado
        iterperm++; // atualiza a ieteracao da marcha
        if (iterperm > 200 && arq.AP == 0)
            NumError("ConvergÃƒÂªncia em marchaProdPerm1 atingiu maximo de iteracoes");
        else if (iterperm > 200)
            return 1.1e10;
    }

    double corrigePresF = 0.;
    if (((*vg1dSP).chaverede == 0 || noextremo == 1 || (*vg1dSP).chaveRedeParalela == 1) && arq.corrigeContSep == 1)
        corrigePresF = RenovaPresPermNcel();

    monitConvPermBase = pGSup;
    return pGSup - (celula[ncel].pres + corrigePresF); // caso a marcha tenha conseguido ir atÃ© a Ãºltima celula,
    // retorna a diferenca entre a pressao a montante do choke e a pressao da ultima celula
    // calculada pela marcha
}

double SProd::marchaProdPerm1Rev(double pchute) {

    int corrigechute = 1;
    double alfini = 0.;
    double betini = 0.;
    trocaTermicaLenta = 0.1;

    // estimativa da fracao de vazio na primeira celula do sistema
    if (celula[0].acsr.tipo == 0) { // sem nenhuma fonte
        celula[0].temp = arq.celp[0].textern;
        alfini = 1.;
        betini = 0.;
        if (arq.flashCompleto == 2) {
            if (arq.tabelaDinamica == 0)
                celula[0].flui.atualizaPropComp(pchute, celula[0].temp);
        }
    } else if (celula[0].acsr.tipo == 1) { // fonte de gas
        celula[0].temp = celula[0].acsr.injg.temp;
        if (arq.flashCompleto == 2) {
            if (arq.tabelaDinamica == 0)
                celula[0].flui.atualizaPropComp(pchute, celula[0].temp);
            celula[0].acsr.injg.FluidoPro.atualizaPropComp(pchute, celula[0].temp, -1, NULL, NULL, celula[0].acsr.injg.seco);
        }
        if (celula[0].acsr.injg.seco == 1) {
            alfini = 1.;
            betini = 0.;
        } else {
            double masgas = celula[0].acsr.injg.VMas(pchute, celula[0].temp);
            double tit;
            if (arq.flashCompleto != 2)
                tit = celula[0].acsr.injg.FluidoPro.FracMassHidra(1., 20.);
            else
                tit = celula[0].acsr.injg.FluidoPro.dStockTankVaporMassFraction;
            double masT = masgas / tit;
            tit = celula[0].acsr.injg.FluidoPro.FracMassHidra(pchute, celula[0].temp);
            double qgas = masT * tit /
                          celula[0].acsr.injg.FluidoPro.MasEspGas(pchute, celula[0].temp);
            double qliq = masT * (1. - tit) /
                          celula[0].acsr.injg.FluidoPro.MasEspLiq(pchute, celula[0].temp);
            double qcomp = celula[0].acsr.injg.razCompGas *
                           celula[0].acsr.injg.QGas * celula[0].acsr.injg.fluidocol.MasEspFlu(1., 20.) /
                           celula[0].acsr.injg.fluidocol.MasEspFlu(pchute, celula[0].temp);
            qcomp /= 86400.;
            alfini = qgas / (qliq + qcomp + qgas);
            if ((fabs(qcomp) + fabs(qliq)) > 1e-15)
                betini = fabs(qcomp) / (fabs(qcomp) + fabs(qliq));
            else
                betini = 0.;
        }
    } else if (celula[0].acsr.tipo == 2) { // fonte de liquido, faz-se uma estimativa a partir
        // da vazÃƒÂ£o volumÃƒÂ©trica das fases, fracao de vazio = fracao de vazio sem escorregamento
        celula[0].temp = celula[0].acsr.injl.temp;
        if (arq.flashCompleto == 2) {
            if (arq.tabelaDinamica == 0)
                celula[0].flui.atualizaPropComp(pchute, celula[0].temp);
            celula[0].acsr.injl.FluidoPro.atualizaPropComp(pchute, celula[0].temp);
        }
        double qgas = celula[0].acsr.injl.QLiq * (1 - celula[0].acsr.injl.bet) *
                      (1. - celula[0].acsr.injl.FluidoPro.BSW) *
                      (celula[0].acsr.injl.FluidoPro.RGO -
                       celula[0].acsr.injl.FluidoPro.rDgD * celula[0].acsr.injl.FluidoPro.RS(pchute, celula[0].temp) * 6.29 / 35.31467) *
                      celula[0].acsr.injl.FluidoPro.Deng * 1.225 / celula[0].acsr.injl.FluidoPro.MasEspGas(pchute, celula[0].temp);
        double qliq = celula[0].acsr.injl.QLiq * (1 - celula[0].acsr.injl.bet) *
                          (1. - celula[0].acsr.injl.FluidoPro.BSW) * celula[0].acsr.injl.FluidoPro.BOFunc(pchute, celula[0].temp) +
                      celula[0].acsr.injl.QLiq * (1 - celula[0].acsr.injl.bet) *
                          celula[0].acsr.injl.FluidoPro.BSW * celula[0].acsr.injl.FluidoPro.BAFunc(pchute, celula[0].temp) +
                      celula[0].acsr.injl.QLiq * celula[0].acsr.injl.bet;
        alfini = qgas / (qliq + qgas);
        betini = celula[0].acsr.injl.bet;
    } else if (celula[0].acsr.tipo == 3) { // IPR no inicio da tubulacao
        // da mesma maneira que no caso de fonte de liquido, fracao de vazio= sem escorregamento
        celula[0].temp = celula[0].acsr.ipr.Tres;
        if (arq.flashCompleto == 2) {
            if (arq.tabelaDinamica == 0)
                celula[0].flui.atualizaPropComp(pchute, celula[0].temp);
            celula[0].acsr.ipr.FluidoPro.atualizaPropComp(pchute, celula[0].temp);
        }
        double qgas = celula[0].acsr.ipr.MasG(pchute, celula[0].temp) /
                      celula[0].acsr.ipr.FluidoPro.MasEspGas(pchute, celula[0].temp);
        double qliq = celula[0].acsr.ipr.MasL(pchute, celula[0].temp) /
                      celula[0].acsr.ipr.FluidoPro.MasEspLiq(pchute, celula[0].temp);
        alfini = qgas / (qliq + qgas);
        betini = 0.;
    } else if (celula[0].acsr.tipo == 10) { // fonte de massa no inicio da tubulacao
        // da mesma maneira que no caso de fonte de liquido, fracao de vazio= sem escorregamento
        celula[0].temp = celula[0].acsr.injm.temp;
        if (arq.flashCompleto == 2) {
            if (arq.tabelaDinamica == 0)
                celula[0].flui.atualizaPropComp(pchute, celula[0].temp);
            celula[0].acsr.injm.FluidoPro.atualizaPropComp(pchute, celula[0].temp);
        }
        if (celula[0].acsr.injm.condTermo == 0) {
            celula[0].pres = pchute;
            renovaFonte(0);
        }
        double qgas = celula[0].acsr.injm.MassG /
                      celula[0].acsr.injm.FluidoPro.MasEspGas(pchute, celula[0].temp);
        double qliq = celula[0].acsr.injm.MassP /
                          celula[0].acsr.injm.FluidoPro.MasEspLiq(pchute, celula[0].temp) +
                      celula[0].acsr.injm.MassC /
                          celula[0].acsr.injm.fluidocol.MasEspFlu(pchute, celula[0].temp);
        alfini = qgas / (qliq + qgas);
        betini = 0.;
    } else if (celula[0].acsr.tipo == 15) { // IPR no inicio da tubulacao
        // da mesma maneira que no caso de fonte de liquido, fracao de vazio= sem escorregamento
        celula[0].temp = celula[0].acsr.radialPoro.tRes;
        celula[0].pres = pchute;
        if (arq.flashCompleto == 2) {
            if (arq.tabelaDinamica == 0)
                celula[0].flui.atualizaPropComp(pchute, celula[0].temp);
            celula[0].acsr.radialPoro.flup.atualizaPropComp(pchute, celula[0].temp);
        }
        renovaFonte(0);
        double qgas = celula[0].acsr.radialPoro.fluxIniG /
                      celula[0].acsr.radialPoro.flup.MasEspGas(pchute, celula[0].temp);
        double qliq = (celula[0].acsr.radialPoro.fluxIni + celula[0].acsr.radialPoro.fluxIniA) /
                      celula[0].acsr.radialPoro.flup.MasEspLiq(pchute, celula[0].temp);
        alfini = qgas / (qliq + qgas);
        betini = 0.;
    } else if (celula[0].acsr.tipo == 16) { // IPR no inicio da tubulacao
        // da mesma maneira que no caso de fonte de liquido, fracao de vazio= sem escorregamento
        celula[0].temp = celula[0].acsr.poroso2D.dados.tRes;
        celula[0].pres = pchute;
        if (arq.flashCompleto == 2) {
            if (arq.tabelaDinamica == 0)
                celula[0].flui.atualizaPropComp(pchute, celula[0].temp);
            celula[0].acsr.poroso2D.dados.flup.atualizaPropComp(pchute, celula[0].temp);
        }
        renovaFonte(0);
        double qgas = celula[0].acsr.poroso2D.dados.transfer.fluxIniG /
                      celula[0].acsr.poroso2D.dados.flup.MasEspGas(pchute, celula[0].temp);
        double qliq = (celula[0].acsr.poroso2D.dados.transfer.fluxIni + celula[0].acsr.poroso2D.dados.transfer.fluxIniA) /
                      celula[0].acsr.poroso2D.dados.flup.MasEspLiq(pchute, celula[0].temp);
        alfini = qgas / (qliq + qgas);
        betini = 0.;
    } else { // se nenhuma das opcoes, fracao de vazio=1
        celula[0].temp = arq.celp[0].textern;
        if (arq.flashCompleto == 2) {
            if (arq.tabelaDinamica == 0)
                celula[0].flui.atualizaPropComp(pchute, celula[0].temp);
        }
        alfini = 1.;
        betini = 0.;
    }

    if (celula[0].acsr.tipo == 15) {
        celula[0].flui.BSW = celula[0].acsr.radialPoro.BSW;
    } else if (celula[0].acsr.tipo == 16) {
        celula[0].flui.BSW = celula[0].acsr.poroso2D.dados.transfer.BSW;
    }
    // esta marcha e feita para quando se tem alguma fonte no inicio da tubulacao,
    // portanto, admite-se que o duto esta fechado e coloca-se uma fonte no centro da
    // primeira celula. As vazoes na fronteira esquerda da celula sÃ£o portanto = 0
    celula[0].tempL = celula[0].temp;
    celula[1].tempL = celula[0].temp;
    celula[0].tempini = celula[0].temp;

    celula[0].ML = 0.;
    celula[0].MC = 0.;
    celula[1].ML = 0.;
    celula[0].MliqiniL = 0.;
    celula[0].Mliqini = 0.;
    celula[1].MliqiniL = 0.;
    celula[0].MComp = 0.;
    celula[0].QLL = 0.;
    celula[0].QL = 0;
    celula[1].QLL = 0.;
    celula[0].QG = 0.;
    double masfim = 1.;
    double masfim0 = -10;
    double presteste = 1.;
    double presteste0 = -10;
    double tempteste = celula[0].temp;
    double tempteste0 = -1000;
    iterperm = 0;

    double pchute0 = pchute;
    int limIter = 2; // limite de iteracoes quando a opcao de aceleracao da convergencia esta desligado. desaconselhavel
    // desligar esta opcao, os ganhos sao pouco e a convergencia se torna instavel, principalmente
    // quando o tramo faz perte de um sistema de redes
    if (arq.AceleraConvergPerm == 1) { // opcao aceleracao de convergencia ligada
        limIter = 1;                   // em geral faz-se apenas duas iteracoes de marcha para um determinado chute
        if (arq.lingas == 1 && arq.gasinj.tipoCC == 0)
            limIter = 1; // no caso de se ter
        // uma condicao de contorno na injecao de gas = pressao, observou-se que o acoplamento dinamico
        // entre a linha de gas e de producao e mais difoicil, para se conseguir um sistema
        // melhor acoplado, deve-se fazer uma marcha iterativa a mais
    }
    // arq.CriterioConvergPerm Ã© um criterio de convergencia da marcha, so faz sentido
    // quando a aceleracao de convergencia esta desligada. Observe que esta convergencia nÃ£o
    // e de fato a conevregencia do problema, e apenas um repeticao de marcha para um determinado
    // chute de pressao ou de vazao no inicio da tubulacao. O que a convergencia busca de fato e
    // determinar qual a pressao ou vazao de fundo que satisfaz as condicoes de contorno no fim
    // da tubulacao, esta busca e feita nos metodos de busca.
    while ((fabs(masfim - masfim0) / fabs(masfim) > arq.CriterioConvergPerm ||
            fabs(presteste - presteste0) / fabs(presteste) > arq.CriterioConvergPerm) &&
           (iterperm < limIter || fabs(tempteste - tempteste0) / ((tempteste) + 273) > 0.001)) {

        masfim0 = masfim;
        presteste0 = presteste;
        tempteste0 = tempteste;
        if (iterperm == 0 && arq.lingas > 0 && arq.nvalvgas > 0 && verificaAcop == 1)
            IniciaconectaColunaPerm(); // antes de iniciar a primeira iteracao de marcha,
        // faz-se uma estimativa inicial de como se da o acopamento termico entre a coluna e o anular,
        // caso se tenha linha de gas
        else if (arq.lingas > 0 && arq.nvalvgas > 0 && verificaAcop == 1)
            conectaColunaPerm(); // acoplamento termico feito com valores de pressao e temperatura
        // obtidas na primeira iteracao de marcha
        int i;
        corrigechute = 1;
        while (corrigechute == 1) { // opcao antiga, ja nao tem mais efeito
            // efetivamente, este while sempre so e feito uma vez, quando a marcha consegue ir ate
            // a ultima celula sem problemas, caso ocorra algum problema, a marcha e finalizada e
            // sai do metodo retornando ou 1e10 ou -1e10

            // inicializando as pressoes e fracoes volumetricas das celulas iniciais, centro de celula
            // e fronteira de celula
            celula[0].presauxL = pchute;
            celula[0].presLini = pchute;
            celula[0].presL = pchute;
            celula[0].pres = pchute;
            celula[1].presL = pchute;
            celula[0].presini = pchute;
            celula[1].presLini = pchute;
            celula[0].presaux = pchute;
            celula[1].presauxL = pchute;

            celula[0].alf = alfini;
            celula[0].alfini = alfini;
            celula[0].bet = betini;
            celula[0].betini = betini;
            celula[1].alfL = celula[0].alf;
            celula[1].alfLini = celula[0].alf;
            celula[0].alfPigD = celula[0].alf;
            celula[0].alfPigDini = celula[0].alf;
            celula[0].alfPigE = celula[0].alf;
            celula[0].alfPigEini = celula[0].alf;
            celula[1].betL = celula[0].bet;
            celula[1].betLini = celula[0].bet;
            celula[0].betPigD = celula[0].bet;
            celula[0].betPigDini = celula[0].bet;
            celula[0].betPigE = celula[0].bet;
            celula[0].betPigEini = celula[0].bet;
            celula[0].betI = celula[0].bet;
            celula[1].betLI = celula[0].bet;
            // verifica se ja existe algum problema no inicio da marcha
            if (celula[0].pres <= 0.1 ||
                (arq.usaTabela == 1 && (arq.tabent.pmin - celula[0].pres) > (*vg1dSP).localtiny))
                return -1e10;

            if (arq.lingas > 0 && arq.nvalvgas > 0 && iterperm == 0)
                IniciaVazValvGasPerm(0);
            i = 1;
            // inicio da marcha propriamente dita
            while (i <= ncel && celula[i - 1].pres >= 0.1 && fabs(pchute - celula[0].pres) < (*vg1dSP).localtiny) {

                RenovaPresPermMon(i, 0); // avanco da marcha para obter a pressao na fronteira esquerda
                // da celula i
                // teste para ver se ocorreu algum problema:
                if (arq.usaTabela == 1 && (arq.tabent.pmax - celula[i].presaux) < (*vg1dSP).localtiny)
                    return 1e10;
                if (celula[i].presaux <= 0.1 ||
                    (arq.usaTabela == 1 && (arq.tabent.pmin - celula[i].presaux) > (*vg1dSP).localtiny)) {
                    return -1e10;
                }
                atualizaPeriPmonProd(i); // atualizacao da pressao da fronteira esquerda,
                // caso exista alguma BCS ou incremento de pressao
                if (arq.flashCompleto != 2)
                    RenovaMassPerm(i); // verifica se existe alguma fonte na celula anterior, com isto, atualiza
                // as vazoes massica na fronteira a esquerda, alÃ©m das propriedades dos fluidos,
                // densidade do gas, RGO, API, BSW, beta
                else
                    RenovaMassPermComp(i);
                // RenovaTempPerm(i, 0);//faz o avanco da temperatura, da celula i-1 para a celula i
                // verifica se teve algum problema nos limites de temperatura
                // caso se esteja trabalhando com tabela PVTSim
                if (isnan(celula[i].temp))
                    NumError("Temperatrura na linha de producao com valor NaN");
                if (arq.usaTabela == 1 && (celula[i].temp - arq.tabent.tmin) < (*vg1dSP).localtiny)
                    celula[i].temp = arq.tabent.tmin;
                atualizaPeriTempProd(i); // mera atualizacao de atributos de temperatura a esquerda e a direita
                RenovaPresPermJus(i, 0); // evolui a pressao  fronteira a esquerda da celula i para o
                // seu centro de celula
                // verifica se ocorreu algum problema nesta evolucao de de pressao no centro da
                // celula
                if (arq.usaTabela == 1 && (arq.tabent.pmax - celula[i].pres) < (*vg1dSP).localtiny) {
                    return 1e10;
                }
                if (celula[i].pres <= 0.1 ||
                    (arq.usaTabela == 1 && (arq.tabent.pmin - celula[i].pres) > (*vg1dSP).localtiny)) {
                    return -1e10;
                }
                atualizaPeriPjusProd(i); // mera atualizacao de atributos que guardam valores de pressao
                // das celulas a esquerda e a direita
                if (arq.tipoFluido == 0)
                    RenovaTransMassPerm(i - 1);
                else
                    RenovaTransMassPermGas(i - 1); // caso seja uma tabela PVTSim, calcula-se a
                // taxa de transferÃªncia de massa entre as fases para o uso no calculo de
                // calor latente da equacao de energia
                if (arq.ordperm > 1) { // correcao de segunda ordem
                    double D0presaux = celula[i].presaux - celula[i - 1].pres;
                    double D0pres = celula[i].pres - celula[i].presaux;
                    double D0temp = celula[i].temp - celula[i - 1].temp;
                    RenovaPresPermMon(i, 1);
                    atualizaPeriPmonProd(i);
                    RenovaMassPerm(i);
                    RenovaPresPermJus(i, 1);
                    celula[i].pres = 0.5 * (celula[i].presaux + D0pres + celula[i].pres);
                    celula[i].presaux = 0.5 * (celula[i - 1].pres + D0presaux + celula[i].presaux);
                    celula[i].temp = 0.5 * (celula[i - 1].temp + D0temp + celula[i].temp);
                    atualizaPeriPjusProd(i);
                    atualizaPeriPmonProd(i);
                    atualizaPeriTempProd(i);
                    RenovaMassPerm(i);
                    if (arq.tipoFluido == 0)
                        RenovaTransMassPerm(i - 1);
                    else
                        RenovaTransMassPermGas(i - 1);
                }

                i++;

                if (celula[i - 1].pres <= 0.1 ||
                    (arq.usaTabela == 1 && (arq.tabent.pmin - celula[i - 1].pres) > (*vg1dSP).localtiny)) {
                    return -1e10;
                }
            }
            if (i == ncel + 1)
                corrigechute = 0; // fim da marcha
        }

        masfim = celula[ncel - 1].MC; // guarda valor de vazao para se calcular o erro, quando a
        // opcao de acelerador de convergencia esta desligado
        presteste = celula[ncel].pres; // guarda valor de pressao para se calcular o erro, quando a
        // opcao de acelerador de convergencia esta desligado
        iterperm++; // atualiza a ieteracao da marcha
        if (iterperm > 200 && arq.AP == 0)
            NumError("ConvergÃƒÂªncia em marchaProdPerm1 atingiu maximo de iteracoes");
        else if (iterperm > 200)
            return 1.1e10;
        if (arq.tipoFluido != 10000) {
            celula[ncel].temp = tempRev;
            if (iterperm < 100) {
                int lento = 0;
                double media = 0.;
                double desvio = 0;
                for (int ktemp = ncel - 1; ktemp >= 1; ktemp--) {

                    double area = celula[ktemp].duto.area;
                    double ugsmed;
                    ugsmed = fabs(celula[ktemp].QG) / area; // velocidade superficial de gas
                    double ulsmed;
                    ulsmed = fabs(celula[ktemp].QL) / area; // velocidade superficial de liquido
                    if (fabs(ugsmed + ulsmed) <= trocaTermicaLenta)
                        lento += 1;
                    media += fabs(ugsmed + ulsmed);
                }
                media /= (ncel - 1);
                desvio = (media - 0.1);
                if (lento > 0 && lento < ncel) {
                    int para;
                    para = 0;
                    trocaTermicaLenta = 100.;
                }
                for (int ktemp = ncel - 1; ktemp >= 0; ktemp--) {
                    RenovaTempPermRev(ktemp, 0); // faz o avanco da temperatura, da celula i-1 para a celula i
                    // verifica se teve algum problema nos limites de temperatura
                    // caso se esteja trabalhando com tabela PVTSim
                    if (arq.usaTabela == 1 && (celula[ktemp].temp - arq.tabent.tmin) < (*vg1dSP).localtiny)
                        celula[ktemp].temp = arq.tabent.tmin;
                    atualizaPeriTempProd(ktemp); // mera atualizacao de atributos de temperatura a esquerda e a direita
                }
            }
            tempteste = celula[0].temp; // 0.5*(celula[0].temp+tempteste);
        } else {
            atualizaProp();
            atualizaVelTermPerm();
            calcDTPseudoTrans();
            for (int kontaPseudo = 0; kontaPseudo < 20; kontaPseudo++) {
                celula[0].tempini = celula[0].temp;
                celula[1].tempLini = celula[1].tempL;
                celula[1].tempL = celula[0].temp;
                celula[ncel].temp = tempRev;
                for (int i = 0; i < ncel; i++) {
                    celula[i].tempini = celula[i].temp;
                }
                for (int itemp = 1; itemp <= ncel; itemp++) {
                    calctemp(itemp, celula[itemp].tempini, 1);
                }
                atualizaProp();
                calcDTPseudoTrans();
            }
        }
    }

    double corrigePresF = 0.;
    if (((*vg1dSP).chaverede == 0 || noextremo == 1 || (*vg1dSP).chaveRedeParalela == 1) && arq.corrigeContSep == 1)
        corrigePresF = RenovaPresPermNcel();

    monitConvPermBase = pGSup;
    return pGSup - (celula[ncel].pres + corrigePresF); // caso a marcha tenha conseguido ir atÃ© a Ãºltima celula,
    // retorna a diferenca entre a pressao a montante do choke e a pressao da ultima celula
    // calculada pela marcha
}

double SProd::marchaProdPerm2(double pchute) {

    int corrigechute = 1;

    double alfini = 0.;
    double betini = 0.;

    // estimativa da fracao de vazio na primeira celula do sistema
    if (celula[0].acsr.tipo == 0) { // sem nenhuma fonte
        celula[0].temp = arq.celp[0].textern;
        if (arq.flashCompleto == 2) {
            if (arq.tabelaDinamica == 0)
                celula[0].flui.atualizaPropComp(pchute, celula[0].temp);
        }
        alfini = 1.;
        betini = 0.;
    } else if (celula[0].acsr.tipo == 1) { // fonte de gas
        celula[0].temp = celula[0].acsr.injg.temp;
        if (arq.flashCompleto == 2) {
            if (arq.tabelaDinamica == 0)
                celula[0].flui.atualizaPropComp(pchute, celula[0].temp, -1, NULL, NULL, celula[0].acsr.injg.seco);
            celula[0].acsr.injg.FluidoPro.atualizaPropComp(pchute, celula[0].temp);
        }
        if (celula[0].acsr.injg.seco == 1) {
            alfini = 1.;
            betini = 0.;
        } else {
            double masgas = celula[0].acsr.injg.VMas(pchute, celula[0].temp);
            double tit;
            if (arq.flashCompleto != 2)
                tit = celula[0].acsr.injg.FluidoPro.FracMassHidra(1., 20.);
            else
                tit = celula[0].acsr.injg.FluidoPro.dStockTankVaporMassFraction;
            double masT = masgas / tit;
            tit = celula[0].acsr.injg.FluidoPro.FracMassHidra(pchute, celula[0].temp);
            double qgas = masT * tit /
                          celula[0].acsr.injg.FluidoPro.MasEspGas(pchute, celula[0].temp);
            double qliq = masT * (1. - tit) /
                          celula[0].acsr.injg.FluidoPro.MasEspLiq(pchute, celula[0].temp);
            double qcomp = celula[0].acsr.injg.razCompGas *
                           celula[0].acsr.injg.QGas * celula[0].acsr.injg.fluidocol.MasEspFlu(1., 20.) /
                           celula[0].acsr.injg.fluidocol.MasEspFlu(pchute, celula[0].temp);
            qcomp /= 86400.;
            alfini = qgas / (qliq + qcomp + qgas);
            if ((fabs(qcomp) + fabs(qliq)) > 1e-15)
                betini = fabs(qcomp) / (fabs(qcomp) + fabs(qliq));
            else
                betini = 0.;
        }
    } else if (celula[0].acsr.tipo == 2) { // fonte de liquido, faz-se uma estimativa a partir
        // da Vazao volumÃ©trica das fases, fracao de vazio = fracao de vazio sem escorregamento
        celula[0].temp = celula[0].acsr.injl.temp;
        if (arq.flashCompleto == 2) {
            if (arq.tabelaDinamica == 0)
                celula[0].flui.atualizaPropComp(pchute, celula[0].temp);
            celula[0].acsr.injl.FluidoPro.atualizaPropComp(pchute, celula[0].temp);
        }
        double qgas = celula[0].acsr.injl.QLiq * (1 - celula[0].acsr.injl.bet) *
                      (1. - celula[0].acsr.injl.FluidoPro.BSW) *
                      (celula[0].acsr.injl.FluidoPro.RGO -
                       celula[0].acsr.injl.FluidoPro.rDgD * celula[0].acsr.injl.FluidoPro.RS(pchute, celula[0].temp) * 6.29 / 35.31467) *
                      celula[0].acsr.injl.FluidoPro.Deng * 1.225 / celula[0].acsr.injl.FluidoPro.MasEspGas(pchute, celula[0].temp);
        double qliq = celula[0].acsr.injl.QLiq * (1 - celula[0].acsr.injl.bet) *
                          (1. - celula[0].acsr.injl.FluidoPro.BSW) * celula[0].acsr.injl.FluidoPro.BOFunc(pchute, celula[0].temp) +
                      celula[0].acsr.injl.QLiq * (1 - celula[0].acsr.injl.bet) *
                          celula[0].acsr.injl.FluidoPro.BSW * celula[0].acsr.injl.FluidoPro.BAFunc(pchute, celula[0].temp) +
                      celula[0].acsr.injl.QLiq * celula[0].acsr.injl.bet;
        alfini = qgas / (qliq + qgas);
        betini = celula[0].acsr.injl.bet;
    } else if (celula[0].acsr.tipo == 3) { // IPR no inicio da tubulacao
        // da mesma maneira que no caso de fonte de liquido, fracao de vazio= sem escorregamento
        celula[0].temp = celula[0].acsr.ipr.Tres;
        if (arq.flashCompleto == 2) {
            if (arq.tabelaDinamica == 0)
                celula[0].flui.atualizaPropComp(pchute, celula[0].temp);
            celula[0].acsr.ipr.FluidoPro.atualizaPropComp(pchute, celula[0].temp);
        }
        double qgas = celula[0].acsr.ipr.MasG(pchute, celula[0].temp) /
                      celula[0].acsr.ipr.FluidoPro.MasEspGas(pchute, celula[0].temp);
        double qliq = celula[0].acsr.ipr.MasL(pchute, celula[0].temp) /
                      celula[0].acsr.ipr.FluidoPro.MasEspLiq(pchute, celula[0].temp);
        alfini = qgas / (qliq + qgas);
        betini = 0.;
    } else if (celula[0].acsr.tipo == 15) { // IPR no inicio da tubulacao
        // da mesma maneira que no caso de fonte de liquido, fracao de vazio= sem escorregamento
        celula[0].temp = celula[0].acsr.radialPoro.tRes;
        celula[0].pres = pchute;
        if (arq.flashCompleto == 2) {
            if (arq.tabelaDinamica == 0)
                celula[0].flui.atualizaPropComp(pchute, celula[0].temp);
            celula[0].acsr.radialPoro.flup.atualizaPropComp(pchute, celula[0].temp);
        }
        renovaFonte(0);
        double qgas = celula[0].acsr.radialPoro.fluxIniG /
                      celula[0].acsr.radialPoro.flup.MasEspGas(pchute, celula[0].temp);
        double qliq = (celula[0].acsr.radialPoro.fluxIni + celula[0].acsr.radialPoro.fluxIniA) /
                      celula[0].acsr.radialPoro.flup.MasEspLiq(pchute, celula[0].temp);
        alfini = qgas / (qliq + qgas);
        betini = 0.;
    } else if (celula[0].acsr.tipo == 16) { // IPR no inicio da tubulacao
        // da mesma maneira que no caso de fonte de liquido, fracao de vazio= sem escorregamento
        celula[0].temp = celula[0].acsr.poroso2D.dados.tRes;
        celula[0].pres = pchute;
        if (arq.flashCompleto == 2) {
            if (arq.tabelaDinamica == 0)
                celula[0].flui.atualizaPropComp(pchute, celula[0].temp);
            celula[0].acsr.poroso2D.dados.flup.atualizaPropComp(pchute, celula[0].temp);
        }
        renovaFonte(0);
        double qgas = celula[0].acsr.poroso2D.dados.transfer.fluxIniG /
                      celula[0].acsr.poroso2D.dados.flup.MasEspGas(pchute, celula[0].temp);
        double qliq = (celula[0].acsr.poroso2D.dados.transfer.fluxIni + celula[0].acsr.poroso2D.dados.transfer.fluxIniA) /
                      celula[0].acsr.poroso2D.dados.flup.MasEspLiq(pchute, celula[0].temp);
        alfini = qgas / (qliq + qgas);
        betini = 0.;
    } else if (celula[0].acsr.tipo == 10) { // fonte de massa no inicio da tubulacao
        // da mesma maneira que no caso de fonte de liquido, fracao de vazio= sem escorregamento
        celula[0].temp = celula[0].acsr.injm.temp;
        if (arq.flashCompleto == 2) {
            if (arq.tabelaDinamica == 0)
                celula[0].flui.atualizaPropComp(pchute, celula[0].temp);
            celula[0].acsr.injm.FluidoPro.atualizaPropComp(pchute, celula[0].temp);
        }
        if (celula[0].acsr.injm.condTermo == 0) {
            celula[0].pres = pchute;
            renovaFonte(0);
        }
        double qgas = celula[0].acsr.injm.MassG /
                      celula[0].acsr.injm.FluidoPro.MasEspGas(pchute, celula[0].temp);
        double qliq = celula[0].acsr.injm.MassP /
                          celula[0].acsr.injm.FluidoPro.MasEspLiq(pchute, celula[0].temp) +
                      celula[0].acsr.injm.MassC /
                          celula[0].acsr.injm.fluidocol.MasEspFlu(pchute, celula[0].temp);
        alfini = qgas / (qliq + qgas);
        betini = 0.;
    } else { // se nenhuma das opcoes, fracao de vazio=1
        celula[0].temp = arq.celp[0].textern;
        if (arq.flashCompleto == 2) {
            if (arq.tabelaDinamica == 0)
                celula[0].flui.atualizaPropComp(pchute, celula[0].temp);
        }
        alfini = 1.;
        betini = 0.;
    }

    if (celula[0].acsr.tipo == 15) {
        celula[0].flui.BSW = celula[0].acsr.radialPoro.BSW;
    } else if (celula[0].acsr.tipo == 16) {
        celula[0].flui.BSW = celula[0].acsr.poroso2D.dados.transfer.BSW;
    }

    // esta marcha e feita para quando se tem alguma fonte no inicio da tubulacao,
    // portanto, admite-se que o duto esta fechado e coloca-se uma fonte no centro da
    // primeira celula. As vazoes na fronteira esquerda da celula sÃ£o portanto = 0
    celula[0].tempL = celula[0].temp;
    celula[1].tempL = celula[0].temp;
    celula[0].tempini = celula[0].temp;

    celula[0].ML = 0.;
    celula[0].MC = 0.;
    celula[1].ML = 0.;
    celula[0].MliqiniL = 0.;
    celula[0].Mliqini = 0.;
    celula[1].MliqiniL = 0.;
    celula[0].MComp = 0.;
    celula[0].QLL = 0.;
    celula[0].QL = 0;
    celula[1].QLL = 0.;
    celula[0].QG = 0.;
    double masfim = 1.;
    double masfim0 = -10;
    double presteste = 1.;
    double presteste0 = -10;
    iterperm = 0;

    int limIter = 2; // limite de iteracoes quando a opcao de aceleracao da convergencia esta desligado. desaconselhavel
    // desligar esta opcao, os ganhos sao pouco e a convergencia se torna instavel, principalmente
    // quando o tramo faz perte de um sistema de redes
    if (arq.AceleraConvergPerm == 1) { // opcao aceleracao de convergencia ligada
        limIter = 1;                   // em geral faz-se apenas duas iteracoes de marcha para um determinado chute
        if (arq.lingas == 1 && celulaG[0].tipoCC == 0)
            limIter = 1; // no caso de se ter
        // uma condicao de contorno na injecao de gas = pressao, observou-se que o acoplamento dinamico
        // entre a linha de gas e de producao e mais difoicil, para se conseguir um sistema
        // melhor acoplado, deve-se fazer uma marcha iterativa a mais
    }
    // arq.CriterioConvergPerm Ã© um criterio de convergencia da marcha, so faz sentido
    // quando a aceleracao de convergencia esta desligada. Observe que esta convergencia nÃ£o
    // e de fato a conevregencia do problema, e apenas um repeticao de marcha para um determinado
    // chute de pressao ou de vazao no inicio da tubulacao. O que a convergencia busca de fato e
    // determinar qual a pressao ou vazao de fundo que satisfaz as condicoes de contorno no fim
    // da tubulacao, esta busca e feita nos metodos de busca.
    while ((fabs(masfim - masfim0) / masfim > arq.CriterioConvergPerm ||
            fabs(presteste - presteste0) / fabs(presteste) > arq.CriterioConvergPerm) &&
           (iterperm < limIter)) {
        masfim0 = masfim;
        presteste0 = presteste;
        if (iterperm == 0 && arq.lingas > 0 && arq.nvalvgas > 0 && verificaAcop == 1)
            IniciaconectaColunaPerm(); // antes de iniciar a primeira iteracao de marcha,
        // faz-se uma estimativa inicial de como se da o acopamento termico entre a coluna e o anular,
        // caso se tenha linha de gas
        else if (arq.lingas > 0 && arq.nvalvgas > 0 && verificaAcop == 1)
            conectaColunaPerm(); // acoplamento termico feito com valores de pressao e temperatura
        // obtidas na primeira iteracao de marcha
        int i;
        corrigechute = 1;
        while (corrigechute == 1) { // opcao antiga, ja nao tem mais efeito
            // efetivamente, este while sempre so e feito uma vez, quando a marcha consegue ir ate
            // a ultima celula sem problemas, caso ocorra algum problema, a marcha e finalizada e
            // sai do metodo retornando ou 1e10 ou -1e10

            // inicializando as pressoes e fracoes volumetricas das celulas iniciais, centro de celula
            // e fronteira de celula
            celula[0].presauxL = pchute;
            celula[0].presLini = pchute;
            celula[0].presL = pchute;
            celula[0].pres = pchute;
            celula[1].presL = pchute;
            celula[0].presini = pchute;
            celula[1].presLini = pchute;
            celula[0].presaux = pchute;
            celula[1].presauxL = pchute;

            celula[0].alf = alfini;
            celula[0].alfini = alfini;
            celula[0].bet = betini;
            celula[0].betini = betini;
            celula[1].alfL = celula[0].alf;
            celula[1].alfLini = celula[0].alf;
            celula[0].alfPigD = celula[0].alf;
            celula[0].alfPigDini = celula[0].alf;
            celula[0].alfPigE = celula[0].alf;
            celula[0].alfPigEini = celula[0].alf;
            celula[1].betL = celula[0].bet;
            celula[1].betLini = celula[0].bet;
            celula[0].betPigD = celula[0].bet;
            celula[0].betPigDini = celula[0].bet;
            celula[0].betPigE = celula[0].bet;
            celula[0].betPigEini = celula[0].bet;
            celula[0].betI = celula[0].bet;
            celula[1].betLI = celula[0].bet;

            // verifica se ja existe algum problema no inicio da marcha
            if (celula[0].pres <= 0.1 ||
                (arq.usaTabela == 1 && (arq.tabent.pmin - celula[0].presaux) > (*vg1dSP).localtiny))
                return -1e10;
            else if ((celula[0].acsr.tipo == 3 && (celula[0].acsr.ipr.Pres - celula[0].pres) < 1e-15)) {
                return 1e10;
            } else if ((celula[0].acsr.tipo == 15 && (celula[0].acsr.radialPoro.pRes[0] - celula[0].pres) < 1e-15)) {
                return 1e10;
            } else if ((celula[0].acsr.tipo == 16 && (celula[0].acsr.poroso2D.dados.pRes - celula[0].pres) < 1e-15)) {
                return 1e10;
            }
            // IniciaVazValvGasPerm e um metodo que faz uma estimativa da vazao na valvula de GL
            // quando ainda nao foi feita a marcha na linha de gas. Neste caso, ele recebe o
            // indice da celula de producao e verifica se nesta celula existe uma VGL, se existir,
            // caso a condicao na linha de gas seja vazao injetada, divide a vazao injetada pelo numero de
            // valvulas e indica este valor para a VGL relacionada a celula de producao
            // caso a condicao seja pressao de injecao, faz-se uma estimativa da pressao na linha de gas
            // na posicao da VGL por hidrotatica e com isto se calcula a vazao de injecao da VGL
            if (arq.lingas > 0 && arq.nvalvgas > 0 && iterperm == 0 && monitConvPerm > 0.1) {
                if (celulaG[0].tipoCC == 0)
                    hidroLinServ();
                IniciaVazValvGasPerm(0);
            }
            i = 1;
            // inicio da marcha propriamente dita
            while (i <= ncel && celula[i - 1].pres >= 0.1 && fabs(pchute - celula[0].pres) < (*vg1dSP).localtiny) {

                if ((i) > ncel - 2) {
                    int val;
                    val = 0;
                }
                RenovaPresPermMon(i, 0); // avanco da marcha para obter a pressao na fronteira esquerda
                // da celula i
                // teste para ver se ocorreu algum problema:
                if (arq.usaTabela == 1 && (arq.tabent.pmax - celula[i].presaux) < (*vg1dSP).localtiny)
                    return 1e10;
                atualizaPeriPmonProd(i); // atualizacao da pressao da fronteira esquerda,
                // caso exista alguma BCS ou incremento de pressao
                if (arq.flashCompleto != 2)
                    RenovaMassPerm(i); // verifica se existe alguma fonte na celula anterior, com isto, atualiza
                // as vazoes massica na fronteira a esquerda, alÃ©m das propriedades dos fluidos,
                // densidade do gas, RGO, API, BSW, beta
                else
                    RenovaMassPermComp(i);

                if (arq.acopColAnulPermForte == 0 || arq.lingas == 0 || monitConvPerm > 0.1)
                    RenovaTempPerm(i, 0); // faz o avanco da temperatura, da celula i-1 para a celula i
                // verifica se teve algum problema nos limites de temperatura
                // caso se esteja trabalhando com tabela PVTSim
                if (isnan(celula[i].temp)) {
                    if (arq.transiente == 0 && arq.AP == 0)
                        // neste caso, se finaliza a simulacao, nao tem um transiente
                        // a ser feito a seguir e nem se estÃ¡ em uma rede
                        NumError(
                            "Temperatrura na linha de producao com valor NaN em marchaProdPerm2");
                    else {
                        // apresenta apenas um aviso
                        cout << "#################PERMANENTE FALHOU EM SUA CONVERGÃŠNCIA##############################" << endl;
                        // se for em uma iteracao de rede, apos a primeira iteracao
                        if ((*vg1dSP).iterRede > 0)
                            return -1.1e10;
                        // se logo apos tem uma simulacao transiente ou se esta na primeira iteracao de rede
                        else
                            return 1.1e10;
                    }
                }
                if (arq.usaTabela == 1 && (celula[i].temp - arq.tabent.tmin) < (*vg1dSP).localtiny)
                    celula[i].temp = arq.tabent.tmin;
                atualizaPeriTempProd(i); // mera atualizacao de atributos de temperatura a esquerda e a direita
                RenovaPresPermJus(i, 0); // evolui a pressao  fronteira a esquerda da celula i para o
                // seu centro de celula
                // verifica se ocorreu algum problema nesta evolucao de de pressao no centro da
                // celula
                if (arq.usaTabela == 1 && (arq.tabent.pmax - celula[i].pres) < (*vg1dSP).localtiny)
                    return 1e10;
                atualizaPeriPjusProd(i); // mera atualizacao de atributos que guardam valores de pressao
                // das celulas a esquerda e a direita
                for (int j = 0; j < arq.nvalvgas; j++) { // reavaliacao da vazao da valvula de gas lift, quando
                    // a celula tem uma.
                    // P.S. parece uma acao desnecessÃ¡ria e talvez atÃ© um complicador
                    // densecessario, em vavliacao
                    if (posicVGLP[j] == i) {
                        int k = posicVGLG[j];
                        calcVazGasPerm(k);
                    }
                }
                if (arq.tipoFluido == 0)
                    RenovaTransMassPerm(i - 1);
                else
                    RenovaTransMassPermGas(i - 1); // caso seja uma tabela PVTSim, calcula-se a
                // taxa de transferÃªncia de massa entre as fases para o uso no calculo de
                // calor latente da equacao de energia
                if (arq.ordperm > 1) { // correcao de segunda ordem
                    double D0presaux = celula[i].presaux - celula[i - 1].pres;
                    double D0pres = celula[i].pres - celula[i].presaux;
                    double D0temp = celula[i].temp - celula[i - 1].temp;
                    RenovaPresPermMon(i, 1);
                    atualizaPeriPmonProd(i);
                    RenovaMassPerm(i);
                    RenovaTempPerm(i, 1);
                    RenovaPresPermJus(i, 1);
                    celula[i].pres = 0.5 * (celula[i].presaux + D0pres + celula[i].pres);
                    celula[i].presaux = 0.5 * (celula[i - 1].pres + D0presaux + celula[i].presaux);
                    celula[i].temp = 0.5 * (celula[i - 1].temp + D0temp + celula[i].temp);
                    atualizaPeriPjusProd(i);
                    atualizaPeriPmonProd(i);
                    atualizaPeriTempProd(i);
                    RenovaMassPerm(i);
                    if (arq.tipoFluido == 0)
                        RenovaTransMassPerm(i - 1);
                    else
                        RenovaTransMassPermGas(i - 1);
                }
                // apÃ³s se atingir a pressao no centro da celula i, primeira iteracao de marcha
                // verifica-se se existe uma VGL em i e faz-se uma estimativa inicial da Vazao de
                // GL (caso exista linha de gas). Observar que isto sÃ³ Ã© feito para a iteracao zero.
                if (arq.lingas > 0 && arq.nvalvgas > 0 && iterperm == 0 && monitConvPerm > 0.1)
                    IniciaVazValvGasPerm(i);
                i++;
                // teste para verificar se a pressao do centro de celula ficou acima
                // da pressao estatica de uma eventual IPR ou ficou baixa demais
                if (celula[i - 1].pres <= 0.1 ||
                    (arq.usaTabela == 1 && (arq.tabent.pmin - celula[i - 1].pres) > (*vg1dSP).localtiny))
                    return -1e10;
                else if (celula[i - 1].acsr.tipo == 3 && ((celula[i - 1].acsr.ipr.Pres - celula[i - 1].pres) < 1e-15 && i == 1))
                    return 1e10;
                else if (celula[i - 1].acsr.tipo == 15 && ((celula[i - 1].acsr.radialPoro.pRes[0] - celula[i - 1].pres) < 1e-15 && i == 1))
                    return 1e10;
                else if (celula[i - 1].acsr.tipo == 16 && ((celula[i - 1].acsr.poroso2D.dados.pRes - celula[i - 1].pres) < 1e-15 && i == 1))
                    return 1e10;
                else if (arq.usaTabela == 1) {
                    if ((arq.tabent.pmax - celula[i - 1].pres) < (*vg1dSP).localtiny)
                        return 1e10;
                }
            }
            if (i == ncel + 1)
                corrigechute = 0; // fim da marcha
        }
        // apÃ³s o fim da marcha da linha de produÃ§Ã£o, Ã© feita a marcha da linha de gas
        // caso exista
        if (pchute > 0 && arq.lingas > 0 && arq.nvalvgas > 0) {
            if (celulaG[0].tipoCC == 0) {            // marcha para o caso, pressao de injecao
                if (arq.chokes.abertura[0] >= 0.2) { // choke de injecao inativo
                    for (int iter = 0; iter < 1; iter++)
                        marchaGasPerm1();
                } else
                    buscaGasPresPerm3(); // choke de injecao ativo
            } else
                buscaGasPresPerm2(); // marcha na linha de gas para o caso de vazao de injecao
        }

        if (arq.acopColAnulPermForte > 0 && arq.lingas > 0 && semTermo == 0) {
            atualizaProp();
            atualizaVelTermPerm();
            calcDTPseudoTrans();
            conectaColuna();
            for (int kontaPseudo = 0; kontaPseudo < arq.acopColAnulPermForte; kontaPseudo++) {
                for (int iterm = 0; iterm <= ncelGas; iterm++)
                    celulaG[iterm].tempini = celulaG[iterm].temp;
                for (int iterm = 1; iterm <= ncelGas; iterm++) {
                    calctempGas(iterm, celulaG[iterm - 1].tempini, 1);
                }
                celula[0].tempini = celula[0].temp;
                celula[1].tempLini = celula[1].tempL;
                celula[1].tempL = celula[0].temp;
                for (int iterm = 1; iterm <= ncel; iterm++) {
                    celula[iterm].tempini = celula[iterm].temp;
                }
                for (int iterm = 1; iterm <= ncel; iterm++) {
                    calctemp(iterm, celula[iterm].tempini, 1);
                }
                atualizaProp();
                calcDTPseudoTrans();
                conectaColuna();
            }
        }

        masfim = celula[ncel - 1].MC; // guarda valor de vazao para se calcular o erro, quando a
        // opcao de acelerador de convergencia esta desligado
        presteste = celula[ncel].pres; // guarda valor de pressao para se calcular o erro, quando a
        // opcao de acelerador de convergencia esta desligado
        iterperm++; // atualiza a ieteracao da marcha
        if (iterperm > 200 && arq.AP == 0)
            NumError("Convergencia em marchaProdPerm2 atingiu maximo de iteracoes");
        else if (iterperm > 200)
            return 1e10;
    }

    // nesta marcha, a condicao no fim da tubulacao nÃ£o e a pressao a montante do choke,
    // mas a pressao a jusante do choke. Neste caso, a condicao que se deseja convergir
    // e a vazao que passa pelo choke, definida a aprtir da diferenca entre a pressao
    // na ultima celula e a pressao a jusante do choke. Primeiro, portanto, deve-se
    // calcular a vazao que passa pelo choke e compara-la com a vazao massica total
    // na ultima celula
    double maxSup = 0.;
    if (derivaAnel != 0 && celula[ncel].pres > pGSup) { // se for o anel de GL, a vazao no final deve ser zero
        double tESup = celula[ncel].temp;
        double alfSup = celula[ncel].alf;
        double betSup = celula[ncel].bet;

        double masentrada = celula[ncel - 1].MR;
        double massgas = celula[ncel - 1].MR - celula[ncel - 1].MliqiniR;

        double tit;
        presfim = celula[ncel].pres;
        double rholp = celula[ncel].flui.MasEspLiq(celula[ncel].pres, celula[ncel].temp);
        double rholc = celula[ncel].fluicol.MasEspFlu(celula[ncel].pres, celula[ncel].temp);
        tit = fabs(massgas / masentrada);

        double masChk;

        double ypres = pGSup / presfim;
        masChk = chokeSup.vazmassSachd(ypres, presfim, tESup, alfSup, betSup, tit, celula[ncel - 1].flui,
                                       celula[ncel - 1].fluicol);
        maxSup = chokeSup.vazmaxSachd(presfim, tESup, alfSup, betSup, tit, celula[ncel - 1].flui, celula[ncel - 1].fluicol);
        if (fabs(ypres) > fabs(chokeSup.razpres))
            maxSup = masChk;
        // maxSup Ã© a vazao total passando pelo choke

        if (chokeSup.AreaGarg > (1e-3) * celula[ncel - 1].duto.area && ypres < 1.) {
            double cplM = (1. - betSup) * celula[ncel].flui.CalorLiq(presfim, tESup) -
                          betSup * celula[ncel].fluicol.CalorLiq(presfim, tESup);
            double jtlM = (1. - betSup) * celula[ncel].flui.JTL(presfim, tESup) - betSup / rholc;
            double cpg = celula[ncel].flui.CalorGas(presfim, tESup);
            double jtgM = celula[ncel].flui.JTG(presfim, tESup);
            arq.valTempChokeJus = tESup + ((1. - tit) * jtlM / cplM + tit * jtgM / cpg) * (pGSup - presfim) * 98066.52;
        }

    } else {
        maxSup = 0.;
        arq.valTempChokeJus = celula[ncel].temp;
    }

    if (fabs(masfim) > 1e-15)
        monitConvPermBase = fabs(masfim);
    else if (fabs(maxSup) > 1e-15)
        monitConvPermBase = fabs(maxSup);
    else
        monitConvPermBase = 1.;
    return (masfim - maxSup); // diferenca entre a vazao total na fronteira a esquerda da
    // penultima celula e a vazao que passa pelo choke. Se o chute de pressao for alto
    // maxSup>masfim, retorna valor negativo,
    // se for uma estimativa baixa de pressao de fundo, maxSup<masfim retirna valor positivo
}

double SProd::buscaProdPfundoPerm(double chute, int kontaTenta) {
    revPerm = 0;
    monitConvPerm = 1000.;
    // busca de dois chutes iniciais com valores com sinais opostos
    // para marchaProdPerm1 e assim iniciar o prpocesso de calculo de erro de funcao.
    double pchute = pGSup; // inicializando o valor de pchute com o valor da pressao a jusante
    // do choke, pchute sera o valor de chute de fato no processo de busca
    // se o valor de chute>0, pchute=chute, senao, ele e estimado
    double taux; // valor de temperatura auxiliar para o eventual calculo
    // de pchute
    double j = 0.;
    double rmis = 0.;
    double f1 = 0.;
    double perdafric = 0.;
    double betaChute = 0.;

    if (chute < 0) {

        if (celula[0].acsr.tipo == 2 && fabs(celula[0].acsr.injl.QLiq) > 0.) {
            betaChute = celula[0].acsr.injl.bet;
            // este espaco faz uma estimativa de quanto deve ser a perda de carga media
            // a partir do valor da vazao no inicio da tubulacao, isto e feito apenas
            // se existir uma fonte de liquido, celula[0].acsr.tipo == 2
            taux = arq.celp[0].textern; // a temperatura em que esta estimativa sera feita
            // e dada pela temperatura da fonte, a pressao para o calculo das propriedades
            // e feita por pGSup
            if (taux < arq.tmin)
                taux = arq.tmin;
            ///////////propriedades fisicas:
            double bet = celula[0].acsr.injl.bet;
            double visC = celula[0].acsr.injl.fluidocol.VisFlu(pchute, taux);
            double visP = celula[0].acsr.injl.FluidoPro.ViscOleo(pchute, taux);
            double visG = celula[0].acsr.injl.FluidoPro.ViscGas(pchute, taux);
            double visMis = (1 - bet) * visP + bet * visC;
            double rC = celula[0].acsr.injl.fluidocol.MasEspFlu(pchute, taux);
            double rP = celula[0].acsr.injl.FluidoPro.MasEspLiq(pchute, taux);
            double rG = celula[0].acsr.injl.FluidoPro.MasEspGas(pchute, taux);
            rmis = (1 - bet) * rP + bet * rC;
            double rlcA = celula[0].acsr.injl.fluidocol.MasEspFlu(1.001, 15.);
            // estimativa grosseira da vazao massica do liquido complementar
            double massicC = rlcA * celula[0].acsr.injl.QLiq * celula[0].acsr.injl.bet / 86400;
            // estimativa grosseira da vazao massica de liquido e gas produzidos
            double massic;
            // massas especificas, condicao standard
            double Rhogs = celula[0].acsr.injl.FluidoPro.Deng * 1.225; // cel[ind].acsr.injl.FluidoPro.MasEspGas(1, 15);
            double Rhols = (1000 * 141.5 / (131.5 + celula[0].acsr.injl.FluidoPro.API)) * (1 - celula[0].acsr.injl.FluidoPro.BSW) + 1000. * celula[0].acsr.injl.FluidoPro.Denag * celula[0].acsr.injl.FluidoPro.BSW;
            // multiplicador da vazao standard para se obter a Vazao massicagÃ¡s+liquido produzido
            double multiplicador = (Rhols + celula[0].acsr.injl.FluidoPro.RGO * Rhogs * (1 - celula[0].acsr.injl.FluidoPro.BSW));
            // massic *= multiplicador;//alteracao8
            massic = 1 * multiplicador * celula[0].acsr.injl.QLiq * (1. - celula[0].acsr.injl.bet) / 86400;
            // titulo do gas em relacao a misturaoleo+agua+gas
            double fracmasshidra = celula[0].acsr.injl.FluidoPro.FracMassHidra(pchute, taux);
            double massicP = (1. - fracmasshidra) * massic; // vazao massica de liquido produzido
            double massicG = fracmasshidra * massic;        // vazao massaica de gas
            /// estimativa grosseira da velocidade da mistura
            j = (massicP / rP + massicC / rC + massicG / rG) / celula[0].duto.area;
            // estimativa da fracao de vazio sem escorregamento
            double alfmis = (massicG / rG) / (massicP / rP + massicC / rC + massicG / rG);
            // propriedades de mistura
            rmis = (1 - alfmis) * rmis + alfmis * rG;
            visMis = (1 - alfmis) * visMis + alfmis * visG;
            // estimativa de numero de Reynolds
            double re;
            if (celula[0].duto.revest == 0)
                re = celula[0].Rey(celula[0].duto.a, j, rmis, visMis);
            else {
                double dhid = 4 * celula[0].duto.area / celula[0].duto.peri;
                re = celula[0].Rey(dhid, j, rmis, visMis);
            }
            // estimativa de um fator de friccao
            f1 = celula[0].fric(re, celula[0].duto.rug / celula[0].duto.a);
        }
        double tmparea = celula[0].duto.area;
        double tmpperi = celula[0].duto.peri;
        // estimativa da perda por friccao no sistema, se o acessorio no inicio da tubulacao
        // nao for uma fonte de liquido, esta estimativa sera zero
        perdafric = (f1 * rmis * j * fabs(j) / 2.) * tmpperi / tmparea;
        // se o acessorio for uma IPR, a estimativa serÃ¡ uma pressao prÃ³xima a uma vazao baixa
        // no fundo do poco
        // se nao for IPR, a estimativa continua, considerando a perda de carga e a hidrostatica,
        // que serÃ¡ avaliada neste laco
        for (int i = ncel; i > 0; i--) {
            taux = arq.celp[i].textern;
            if (taux < arq.tmin)
                taux = arq.tmin;
            double rhol = celula[i].flui.MasEspLiq(pchute, taux);
            double rhog = celula[i].flui.MasEspGas(pchute, taux);
            // se o sistema nao for um anel principal de GL
            // para a estimativa de pressao, se utilizara so a hidrostatica de liquido, o que dara um
            // chute inicial de pressao muito alta
            double alfa = 0.;
            if (betaChute < 0.5) {
                double tit = celula[i].flui.FracMassHidra(pchute, taux);
                alfa = tit * rhol / (rhog - tit * rhog + tit * rhol);
            }
            if (derivaAnel == 0)
                alfa = 1.; // se for o anel, so se tem gas
            else if ((*vg1dSP).chaverede == 1 && chuteHol < 0.5 && chuteHol > -1e-15)
                alfa = 1. - chuteHol * 2.;
            double rhomix = (1. - alfa) * rhol + alfa * rhog;
            double dxmed = 0.5 * (celula[i].dx + celula[i - 1].dx);
            // avanco da pressao por meio da hidrostatica e da perda por friccao estimada
            pchute += ((rhomix * 9.81 * sin(celula[i].duto.teta) * dxmed + perdafric * dxmed) / 98066.5);
            if (pchute < 0.8)
                pchute = 0.8;
            // incremento de pressao devido a algum ganho de pressao constante em alguma celula
            if (celula[i - 1].acsr.tipo == 7)
                pchute -= celula[i - 1].acsr.delp;
            // caso exista alguma IPR no meio do duto, verifica se a pressao estimada esta maior que
            // a pressao estatica, nÃ£o se trabalha com vazoes negativas neste solver
            // para evitar isto, se corrige a pressao para um valor proximo da
            // pressao estatica da IPR da celula
            if (celula[i - 1].acsr.tipo == 3 &&
                ((celula[i - 1].acsr.ipr.Pres - pchute) < 0.01 * celula[i - 1].acsr.ipr.Pres) && i == 1) {
                double qchute = 0.15 * celula[i - 1].duto.area * 86400;
                pchute = -(qchute / celula[i - 1].acsr.ipr.ip) + celula[i - 1].acsr.ipr.Pres;
                if (pchute > 0.99 * celula[i - 1].acsr.ipr.Pres)
                    pchute = 0.99 * celula[i - 1].acsr.ipr.Pres;
                if (pchute < 0.9 * celula[i - 1].acsr.ipr.Pres)
                    pchute = 0.9 * celula[i - 1].acsr.ipr.Pres;
            }
            // tambÃ©m se evita um chute com valores maiores que o limite maximo de uma tabela
            // no caso de se estar usando PVTSim
            if (arq.usaTabela == 1 && (arq.tabent.pmax - pchute) < (*vg1dSP).localtiny)
                pchute = 0.9 * arq.tabent.pmax;
        }

        if (pchute > 1000) {
            pchute = 1000; // pressao maxima de chute
        }
    } else
        pchute = chute; // caso chute nao seja negativo utiliza a estimativa enviada na
    // lista de parametro do metodo
    double pchute2;        // segundo chute de pressao da busca
    double pchuteAux = 0.; // auxiliar na busca de dos chutes de pressao
    // necessarios para se dar partida no metodo de calculo de raiz
    double val; // val recebe sempre o valor retornado pelo procedimento de marcha
    // neste caso, Ã© a pressao a montante do choke-a pressao da ultima celula, calculada pela
    // marcha
    val = marchaProdPerm1(pchute);
    buscaIni = 1;
    // a marcha pode dar problemas, ou a pressao em algum ponto deu acima da pressao estÃ¡tica de
    // de alguma IPR no meio do caminho, retorna 1e10,
    // ou antes de atingir a ultima celula, a pressao ficou proximo de zero, ou a pressao
    // retorna -1e10, ou a pressao, para o caso PVTSim, ficou acima da pressao maxima da tabela
    // retorna 1e10
    if (val < -0.9e10) { // pressao muito baixa na marcha, deve ser aumentado o valor de chute
        // faz-se uma nova estimativa, sÃ³ que agora admitindo uma hidrostÃ¡tica de Ã¡gua,
        // o que darÃ¡ uma pressao de fundpo mais alta
        pchuteAux = pGSup;
        for (int i = ncel; i > 0; i--) {
            taux = arq.celp[i].textern;
            double rhol = 1000 + 0 * celula[i].flui.MasEspLiq(pchuteAux, taux);
            double rhog = celula[i].flui.MasEspGas(pchuteAux, taux);
            double alfa = 0.;
            if (betaChute < 0.5) {
                double tit = celula[i].flui.FracMassHidra(pchute, taux);
                alfa = tit * rhol / (rhog - tit * rhog + tit * rhol);
                alfa *= 0.5;
            }
            if (derivaAnel == 0)
                alfa = 1.;
            else if ((*vg1dSP).chaverede == 1 && chuteHol < 0.5 && chuteHol > -1e-15)
                alfa = 1. - chuteHol * 2.;
            double rhomix = (1. - alfa) * rhol + alfa * rhog;
            double dxmed = 0.5 * (celula[i].dx + celula[i - 1].dx);
            pchuteAux += (rhomix * 9.81 * sin(celula[i].duto.teta) * dxmed + perdafric * dxmed) / 98066.5;
            if (celula[i - 1].acsr.tipo == 7)
                pchuteAux -= celula[i - 1].acsr.delp;
            if (celula[i - 1].acsr.tipo == 3 &&
                ((celula[i - 1].acsr.ipr.Pres - pchuteAux) < 0.01 * celula[i - 1].acsr.ipr.Pres && i == 1)) {
                pchuteAux = -(10 / celula[i - 1].acsr.ipr.ip) + celula[i - 1].acsr.ipr.Pres;
                if (pchuteAux < 0.99 * celula[i - 1].acsr.ipr.Pres)
                    pchuteAux = 0.99 * celula[i - 1].acsr.ipr.Pres;
            }
            if (arq.usaTabela == 1 && (arq.tabent.pmax - pchuteAux) < (*vg1dSP).localtiny)
                pchuteAux = 0.9 * arq.tabent.pmax;
        }
        if (pchuteAux > 1000) {
            pchuteAux = 1000; // limite de pchuteAux
        }
    } else if (val > 0.9e10) { // pressao em algum ponto ficou acima de alguma pressao estatica
        // deve-se diminuir o valor do chute
        pchuteAux = pGSup;
        for (int i = ncel; i > 0; i--) {
            taux = arq.celp[i].textern;
            double rhol = celula[i].flui.MasEspLiq(pchuteAux, taux);
            double rhog = celula[i].flui.MasEspGas(pchuteAux, taux);
            // neste caso, utiliza-se uma fracao de vazio alta para a hidrostÃ¡tica
            double alfa = 0.8;
            if (betaChute < 0.5) {
                double tit = celula[i].flui.FracMassHidra(pchute, taux);
                alfa = tit * rhol / (rhog - tit * rhog + tit * rhol);
                if (alfa > 0.9999)
                    alfa = 0.9999;
            }
            if (derivaAnel == 0)
                alfa = 1.;
            else if ((*vg1dSP).chaverede == 1 && chuteHol < 0.2 && chuteHol > -1e-15)
                alfa = 1. - chuteHol;
            double rhomix = (1. - alfa) * rhol + alfa * rhog;
            double dxmed = 0.5 * (celula[i].dx + celula[i - 1].dx);
            pchuteAux += (rhomix * 9.81 * sin(celula[i].duto.teta) * dxmed + perdafric * dxmed) / 98066.5;
            if (celula[i - 1].acsr.tipo == 7)
                pchuteAux -= celula[i - 1].acsr.delp;
            if (celula[i - 1].acsr.tipo == 3 &&
                ((celula[i - 1].acsr.ipr.Pres - pchuteAux) < 0.01 * celula[i - 1].acsr.ipr.Pres && i == 1)) {
                pchuteAux = -(10 / celula[i - 1].acsr.ipr.ip) + celula[i - 1].acsr.ipr.Pres;
                if (pchuteAux < 0.99 * celula[i - 1].acsr.ipr.Pres)
                    pchuteAux = 0.99 * celula[i - 1].acsr.ipr.Pres;
            }
            if (arq.usaTabela == 1 && (arq.tabent.pmax - pchuteAux) < (*vg1dSP).localtiny)
                pchuteAux = 0.9 * arq.tabent.pmax;
        }
        if (pchuteAux > 1000) {
            pchuteAux = 1000;
        }
    }

    int tipo = 1;

    // para o caso de ter dado eerado a primeira marcha, com pchuteAux faz-se uma nova tentativa
    int kontaiter = 0; // contador para o laco em que se tentara uma nova estimativa
    // em que ao menos os valores 1e10 ou 1e-10 nao seja retornados
    double pchuteAux0 = pchuteAux;
    if ((val < -0.9e10 || val > 0.9e10) && kontaiter < 50) {
        double valtemp;
        valtemp = marchaProdPerm1(pchuteAux); // marcha com pchuteAux
        if (fabs(valtemp) > 1.01e10) {
            cout << "#################PERMANENTE FALHOU EM SUA CONVERGÃŠNCIA##############################" << endl;
            if (kontaTenta < 0)
                logger.log(LOGGER_AVISO, LOG_ERR_PARSE_BUSINESS_RULE_VALIDATION,
                           "Busca de valores iniciais para calculo de zero de funcao em buscaProdPfundoPerm atingiu maximo de iteracoes",
                           "", "");
            if ((*vg1dSP).iterRede > 0)
                return -1.1e10;
            else
                return 1.1e10;
        }
        while (valtemp > 0.9e10 && val > 0.9e10) { // estimativa de pressao de fundo ainda alta
            pchuteAux *= 0.99;                     // reduzindo a estimativa
            valtemp = marchaProdPerm1(pchuteAux);
            if (fabs(valtemp) > 1.01e10) {
                cout << "#################PERMANENTE FALHOU EM SUA CONVERGÃŠNCIA##############################" << endl;
                if (kontaTenta < 0)
                    logger.log(LOGGER_AVISO, LOG_ERR_PARSE_BUSINESS_RULE_VALIDATION,
                               "Busca de valores iniciais para calculo de zero de funcao em buscaProdPfundoPerm atingiu maximo de iteracoes",
                               "", "");
                if ((*vg1dSP).iterRede > 0)
                    return -1.1e10;
                else
                    return 1.1e10;
            }
            kontaiter++; // 50 iteracoes no maximo
        }
        while (valtemp < -0.9e10 && val < -0.9e10 && kontaiter <= 50) { // estimativa de pressao de fundo ainda baixa
            if (celula[0].acsr.tipo == 1 || celula[0].acsr.tipo == 2 || celula[0].acsr.tipo == 10)
                pchuteAux *= 1.1;
            else
                pchuteAux *= 1.01; // aumentando a estimativa
            // verificando se este aumento ultrapassa o limite de pressao de uma eventual IPR no
            // fundo
            int limpres = 0;
            if (celula[0].acsr.tipo == 3 &&
                (celula[0].acsr.ipr.Pres - pchuteAux) < 0.01 * celula[0].acsr.ipr.Pres) {

                pchuteAux = -(10 / celula[0].acsr.ipr.ip) + celula[0].acsr.ipr.Pres;
                if (pchuteAux < 0.99 * celula[0].acsr.ipr.Pres)
                    pchuteAux = 0.99 * celula[0].acsr.ipr.Pres;

                limpres = 1; // indicadpor de que este avanÃ§o de pressao esta muito alto
                // outros avancos devem ser feitos em um passo menor
            }
            // verificando se este aumento de estimativa foca acima do valor maximo de pressao
            // de uma eventual tabela PVTSim
            if (arq.usaTabela == 1 && (arq.tabent.pmax - pchuteAux) < (*vg1dSP).localtiny)
                pchuteAux = 0.9 * arq.tabent.pmax;
            valtemp = marchaProdPerm1(pchuteAux); // nova tentativa
            if (fabs(valtemp) > 1.01e10) {
                cout << "#################PERMANENTE FALHOU EM SUA CONVERGÃŠNCIA##############################" << endl;
                if (kontaTenta < 0)
                    logger.log(LOGGER_AVISO, LOG_ERR_PARSE_BUSINESS_RULE_VALIDATION,
                               "Busca de valores iniciais para calculo de zero de funcao em buscaProdPfundoPerm atingiu maximo de iteracoes",
                               "", "");
                if ((*vg1dSP).iterRede > 0)
                    return -1.1e10;
                else
                    return 1.1e10;
            }
            if (valtemp < -0.9e10 && limpres == 1) { // continua alto e existe o indicador
                // de que deve-se usar um passo de aumento de pressao menor
                int iterpres = 0;
                while (valtemp < -0.9e10 && iterpres < 10) { // novo laco com um passo menor,
                    // maximo de 10 iteracoes
                    pchuteAux *= 1.001;
                    valtemp = marchaProdPerm1(pchuteAux);
                    if (fabs(valtemp) > 1.01e10) {
                        cout << "#################PERMANENTE FALHOU EM SUA CONVERGÃŠNCIA##############################" << endl;
                        if (kontaTenta < 0)
                            logger.log(LOGGER_AVISO, LOG_ERR_PARSE_BUSINESS_RULE_VALIDATION,
                                       "Busca de valores iniciais para calculo de zero de funcao em buscaProdPfundoPerm atingiu maximo de iteracoes",
                                       "", "");
                        if ((*vg1dSP).iterRede > 0)
                            return -1.1e10;
                        else
                            return 1.1e10;
                    }
                    iterpres++;
                }
                if (iterpres >= 10) {
                    // caso em que atingiu o maximo de passos de incremento de pressa em uma situacao
                    // de passo pequeno, retorna um aviso que deu problema ou finaliza a simulacao
                    if (arq.transiente == 0 && chute < 0 && arq.AP == 0) {
                        // neste caso, se finaliza a simulacao, nao tem um transiente
                        // a ser feito a seguir e nem se estÃ¡ em uma rede
                        NumError(
                            "Busca de valores iniciais para calculo de zero de funcao em buscaProdPfundoPerm atingiu maximo de iteracoes");
                        logger.log(LOGGER_AVISO, LOG_ERR_PARSE_BUSINESS_RULE_VALIDATION,
                                   "Busca de valores iniciais para calculo de zero de funcao em buscaProdPfundoPerm atingiu maximo de iteracoes",
                                   "", "");
                    } else {
                        // apresenta apenas um aviso
                        cout << "#################PERMANENTE FALHOU EM SUA CONVERGÃŠNCIA##############################" << endl;
                        if (kontaTenta < 0)
                            logger.log(LOGGER_AVISO, LOG_ERR_PARSE_BUSINESS_RULE_VALIDATION,
                                       "Busca de valores iniciais para calculo de zero de funcao em buscaProdPfundoPerm atingiu maximo de iteracoes",
                                       "", "");
                        // se for em uma iteracao de rede, apos a primeira iteracao
                        if ((*vg1dSP).iterRede > 0)
                            return -1.1e10;
                        // se logo apos tem uma simulacao transiente ou se esta na primeira iteracao de rede
                        else
                            return 1.1e10;
                    }
                }
            }
            if (kontaiter == 50) {
                pchuteAux = 0.5 * pchuteAux0;
            }
            kontaiter++;
        }
        if (valtemp > -0.9e10 && valtemp < 0.9e10) { // conseguiu fazer a marcha atÃƒÂ© o final
            val = valtemp;
            pchute = pchuteAux;
        }
    }
    if (kontaiter > 50) { // chegou ao limite da iteracao
        if ((*vg1dSP).chaverede == 0) {
            // neste caso, se finaliza a simulacao, nao tem um transiente
            // a ser feito a seguir e nem se estÃ¡ em uma rede
            if (arq.transiente == 0 && chute < 0 && arq.AP == 0) {
                NumError("Busca de valores iniciais para calculo de zero de funcao em buscaProdPfundoPerm atingiu maximo de iteracoes");
                logger.log(LOGGER_AVISO, LOG_ERR_PARSE_BUSINESS_RULE_VALIDATION,
                           "Busca de valores iniciais para calculo de zero de funcao em buscaProdPfundoPerm atingiu maximo de iteracoes",
                           "", "");
            } else {
                // apresenta apenas um aviso
                cout << "#################PERMANENTE FALHOU EM SUA CONVERGÃŠNCIA##############################" << endl;
                if (kontaTenta < 0)
                    logger.log(LOGGER_AVISO, LOG_ERR_PARSE_BUSINESS_RULE_VALIDATION,
                               "Busca de valores iniciais para calculo de zero de funcao em buscaProdPfundoPerm atingiu maximo de iteracoes",
                               "", "");
                // se for em uma iteracao de rede, apos a primeira iteracao
                if ((*vg1dSP).iterRede > 0)
                    return -1.1e10;
                // se logo apos tem uma simulacao transiente ou se esta na primeira iteracao de rede
                else
                    return 1.1e10;
            }
        } else {
            // se for em uma iteracao de rede, apos a primeira iteracao
            if ((*vg1dSP).iterRede > 0)
                return -1.1e10;
            // se logo apÃ³s tem uma simulacao transiente ou se esta na primeira iteracao de rede
            else
                return 1.1e10;
        }
    }

    // caso o laÃ§o anterior tenha levado a estimativa de um valor 1e10 para um valor -1e10
    // ou tenha levado para um valor de -1e10 para 1e10
    // ou seja, de um chute de pressao alto demais para finalizar a marcha
    // para um chute de pressao baixo demais para terminar a marcha ou vice versa
    while ((val < -0.9e10 || val > 0.9e10) && kontaiter < 50) {
        pchute = 0.5 * (pchute + pchuteAux); // busca-se um valor medio
        // entre o alto demais e o baixo demais
        if ((fabs(pchute - pchuteAux) / pchute) < 0.001 && val < -0.9e10) {
            pchute = 1.05 * pchute;
            if (celula[0].acsr.tipo == 3 && (celula[0].acsr.ipr.Pres - pchute) < 0.00 * celula[0].acsr.ipr.Pres) {
                pchute = -(10 / celula[0].acsr.ipr.ip) + celula[0].acsr.ipr.Pres;
                if (pchute < 0.99 * celula[0].acsr.ipr.Pres)
                    pchute = 0.99 * celula[0].acsr.ipr.Pres;
            }
            if (arq.usaTabela == 1 && (arq.tabent.pmax - pchute) < (*vg1dSP).localtiny)
                pchute = 0.9 * arq.tabent.pmax;
            pchuteAux = pchute;
        }
        val = marchaProdPerm1(pchute);
        if (fabs(val) > 1.01e10) {
            if (kontaTenta < 0)
                logger.log(LOGGER_AVISO, LOG_ERR_PARSE_BUSINESS_RULE_VALIDATION,
                           "Busca de valores iniciais para calculo de zero de funcao em buscaProdPfundoPerm atingiu maximo de iteracoes",
                           "", "");
            cout << "#################PERMANENTE FALHOU EM SUA CONVERGÃŠNCIA##############################" << endl;
            if ((*vg1dSP).iterRede > 0)
                return -1.1e10;
            else
                return 1.1e10;
        }
        kontaiter++;
    }
    if (kontaiter >= 50) {
        if ((*vg1dSP).chaverede == 0) {
            if (arq.transiente == 0 && chute < 0 && arq.AP == 0) {
                NumError("Busca de valores iniciais para calculo de zero de funcao em buscaProdPfundoPerm atingiu maximo de iteracoes");
                logger.log(LOGGER_AVISO, LOG_ERR_PARSE_BUSINESS_RULE_VALIDATION,
                           "Busca de valores iniciais para calculo de zero de funcao em buscaProdPfundoPerm atingiu maximo de iteracoes",
                           "", "");
            } else {
                cout << "#################PERMANENTE FALHOU EM SUA CONVERGÃŠNCIA##############################" << endl;
                if ((*vg1dSP).iterRede > 0)
                    return -1.1e10;
                else
                    return 1.1e10;
            }
        } else {
            if ((*vg1dSP).iterRede > 0)
                return -1.1e10;
            else
                return 1.1e10;
        }
    }
    // caso tenha sido possivel obter um chute de pressao em que foi possivel finalizar a marcha
    kontaiter = 0;
    pchute2 = pchute;
    double chuteNeg = 0.;
    double chutePos = 0.;
    double chutelim = 0.;
    double val0 = val;
    int reversao = 0;
    double atenua = 1.;
    double reduz = 1. - arq.buscaFC;
    double amplifica = 1. + arq.buscaFC;
    if (fabs(val) < 1e-3)
        return pchute;
    else {
        if (val < 0.) { // caso em que pressao a montante do choke < pressao da ultima celula, calculada pela
            // marcha, isto implica em pressao de chute alta , deve-se agora buscar
            // uma pressao de chute baixa para que val seja positivo e assim iniciar o processo
            // de calculo de zero de funcao
            chuteNeg = pchute; // armazenando o valor de chute de pressao que da o valor negativo
            // a cada nova busca em que val se aproxima de zero, mas ainda negativo
            // chuteNeg Ã© atualizado com a Ãºltima pressao de chute
            int kontaReverso = 0;
            while (val < 0) {
                if (fabs(pchute2 - pchute) / pchute < (1. - reduz) / 10. && kontaiter > 50 * 0.1 / arq.buscaFC) {
                    pchute2 *= 0.5;
                }
                pchuteAux = pchute2;
                pchute2 *= reduz; // Diminuindo a pressao na busca de val>0
                if (pchute2 <= chutelim)
                    pchute2 = 0.5 * (pchuteAux + chutelim); // chutelim inicialmente
                // e zero, mas pode acontecer de baixar demais pchute2 ao ponto de val=-1e10
                //(pressao abaixo de 0.5 no meio da marcha), neste caso, chutelim se torna este valor de
                // pchute2, pois, com isto, ja se sabe que nao se pode ir abaixo de chutelim
                val = marchaProdPerm1(pchute2);
                if (fabs(val) > 1.01e10) {
                    if (kontaTenta < 0)
                        logger.log(LOGGER_AVISO, LOG_ERR_PARSE_BUSINESS_RULE_VALIDATION,
                                   "Busca de valores iniciais para calculo de zero de funcao em buscaProdPfundoPerm atingiu maximo de iteracoes",
                                   "", "");
                    cout << "#################PERMANENTE FALHOU EM SUA CONVERGÃŠNCIA##############################" << endl;
                    if ((*vg1dSP).iterRede > 0)
                        return -1.1e10;
                    else
                        return 1.1e10;
                }
                if (val < 0 && val > -0.9e10) {
                    chuteNeg = pchute2; // atualizando o chuteNeg
                    if (val < val0 && celula[0].acsr.tipo == 3 && arq.lingas == 0) {

                        kontaReverso++;
                        if (kontaReverso == 2) {
                            reversao = 1;
                            val = 1;
                        } else {
                            reduz = 1. + arq.buscaFC;
                            amplifica = 1. - arq.buscaFC;
                            val0 = val;
                        }
                    } else
                        val0 = val;
                }
                kontaiter++;
                if (kontaiter > 50 * 0.1 / arq.buscaFC) { // limite de iteracoes, falha na busca do segundo chute
                    // fim da simulacao ou aviso de falha
                    if ((*vg1dSP).chaverede == 0) {
                        if (arq.transiente == 0 && chute < 0 && arq.AP == 0) {
                            NumError("Busca de valores iniciais para calculo de zero de funcao em buscaProdPfundoPerm atingiu maximo de iteracoes");
                            logger.log(LOGGER_AVISO, LOG_ERR_PARSE_BUSINESS_RULE_VALIDATION,
                                       "Busca de valores iniciais para calculo de zero de funcao em buscaProdPfundoPerm atingiu maximo de iteracoes",
                                       "", "");
                        } else {
                            if (kontaTenta < 0)
                                logger.log(LOGGER_AVISO, LOG_ERR_PARSE_BUSINESS_RULE_VALIDATION,
                                           "Busca de valores iniciais para calculo de zero de funcao em buscaProdPfundoPerm atingiu maximo de iteracoes",
                                           "", "");
                            cout << "#################PERMANENTE FALHOU EM SUA CONVERGENCIA##############################" << endl;
                            if ((*vg1dSP).iterRede > 0)
                                return -1.1e10;
                            else
                                return 1.1e10;
                        }
                    } else {
                        if ((*vg1dSP).iterRede > 0)
                            return -1.1e10;
                        else
                            return 1.1e10;
                    }
                }
                while (val < -0.9e10) { // a reduÃ§Ã£o de pressao foi demais e a marcha nÃ£o foi capaz
                    // de ir ate o final sem que a pressao ficasse inferior a 0.5kgf/cm2
                    // deve-se aumentar a estimativa de pressao baixa
                    chutelim = pchute2;
                    pchute2 = 0.5 * (pchute2 + pchuteAux); // valor intermediario entre a menor pressao
                    // que leva a val<0 e a pressao baixa demais
                    val = marchaProdPerm1(pchute2);
                    if (fabs(val) > 1.01e10) {
                        if (kontaTenta < 0)
                            logger.log(LOGGER_AVISO, LOG_ERR_PARSE_BUSINESS_RULE_VALIDATION,
                                       "Busca de valores iniciais para calculo de zero de funcao em buscaProdPfundoPerm atingiu maximo de iteracoes",
                                       "", "");
                        cout << "#################PERMANENTE FALHOU EM SUA CONVERGENCIA##############################" << endl;
                        if ((*vg1dSP).iterRede > 0)
                            return -1.1e10;
                        else
                            return 1.1e10;
                    }
                    if (val < 0 && val > -0.9e10) {
                        chuteNeg = pchute2;
                    }
                    kontaiter++;
                    if (kontaiter > 50 * 0.1 / arq.buscaFC) {
                        if ((*vg1dSP).chaverede == 0) {
                            if (arq.transiente == 0 && chute < 0 && arq.AP == 0)
                                if (kontaTenta < 0)
                                    logger.log(LOGGER_AVISO, LOG_ERR_PARSE_BUSINESS_RULE_VALIDATION,
                                               "Busca de valores iniciais para calculo de zero de funcao em buscaProdPfundoPerm atingiu maximo de iteracoes",
                                               "", "");
                                else {
                                    cout << "#################PERMANENTE FALHOU EM SUA CONVERGENCIA##############################" << endl;
                                    if ((*vg1dSP).iterRede > 0)
                                        return -1.1e10;
                                    else
                                        return 1.1e10;
                                }
                        } else {
                            if ((*vg1dSP).iterRede > 0)
                                return -1.1e10;
                            else
                                return 1.1e10;
                        }
                    }
                }
            }
            chutePos = pchute2;
        } else if (val > 0.) { // caso em que pressao a montante do choke > pressao da ultima celula,
            // calculada pela
            // marcha, isto implica em pressao de chute baixa , deve-se agora buscar
            // uma pressao de chute alta para que val seja negativo e assim iniciar o processo
            // de calculo de zero de funcao
            chutePos = pchute; // armazenando o valor de chute de pressao que da o valor positivo
            // a cada nova busca em que val se aproxima de zero, mas ainda positivo
            // chutePos e atualizado com a Ãºltima pressao de chute
            int kontaReverso = 0;
            while (val > 0) {
                pchuteAux = pchute2;
                pchute2 *= amplifica; // Aumentando a pressao na busca de val>0
                int limpres = 0;
                if (celula[0].acsr.tipo == 3 &&
                    (celula[0].acsr.ipr.Pres - pchute2) < 0.001 * celula[0].acsr.ipr.Pres) {
                    if (chute < 0) {
                        pchute2 = -(10 / celula[0].acsr.ipr.ip) + celula[0].acsr.ipr.Pres;
                        if (pchute2 < 0.999 * celula[0].acsr.ipr.Pres)
                            pchute2 = 0.999 * celula[0].acsr.ipr.Pres;
                        if (fabs(pchute2 - pchute) < 1e-15) {
                            pchute2 = -(1 / celula[0].acsr.ipr.ip) + celula[0].acsr.ipr.Pres;
                            if (pchute2 < 0.9999 * celula[0].acsr.ipr.Pres)
                                pchute2 = 0.9999 * celula[0].acsr.ipr.Pres;
                        }
                    } else {
                        pchute2 = pchuteAux * 1.0001;
                    }

                    limpres = 1;
                }
                val = marchaProdPerm1(pchute2);
                if (fabs(val) > 1.01e10) {
                    if (kontaTenta < 0)
                        logger.log(LOGGER_AVISO, LOG_ERR_PARSE_BUSINESS_RULE_VALIDATION,
                                   "Busca de valores iniciais para calculo de zero de funcao em buscaProdPfundoPerm atingiu maximo de iteracoes",
                                   "", "");
                    cout << "#################PERMANENTE FALHOU EM SUA CONVERGÃŠNCIA##############################" << endl;
                    if ((*vg1dSP).iterRede > 0)
                        return -1.1e10;
                    else
                        return 1.1e10;
                }
                if (val > 0. && limpres == 1) {
                    int iterpres = 0;
                    if (iterpres >= 10)
                        if (arq.transiente == 0 && chute < 0 && arq.AP == 0) {
                            NumError(
                                "Busca de valores iniciais para calculo de zero de funcao em buscaProdPfundoPerm atingiu maximo de iteracoes");
                            logger.log(LOGGER_AVISO, LOG_ERR_PARSE_BUSINESS_RULE_VALIDATION,
                                       "Busca de valores iniciais para calculo de zero de funcao em buscaProdPfundoPerm atingiu maximo de iteracoes",
                                       "", "");
                        } else {
                            if (kontaTenta < 0)
                                logger.log(LOGGER_AVISO, LOG_ERR_PARSE_BUSINESS_RULE_VALIDATION,
                                           "Busca de valores iniciais para calculo de zero de funcao em buscaProdPfundoPerm atingiu maximo de iteracoes",
                                           "", "");
                            cout << "#################PERMANENTE FALHOU EM SUA CONVERGÃŠNCIA##############################" << endl;
                            if ((*vg1dSP).iterRede > 0)
                                return -1.1e10;
                            else
                                return 1.1e10;
                        }
                }
                if (val > 0 && val < 0.9e10) {
                    chutePos = pchute2; // atualizando o chutePos
                    if (val > val0 && celula[0].acsr.tipo == 3 && arq.lingas == 0) {

                        kontaReverso++;
                        if (kontaReverso == 2) {
                            reversao = 1;
                            val = -1;
                        } else {
                            reduz = 1. + arq.buscaFC;
                            amplifica = 1. - arq.buscaFC;
                            val0 = val;
                        }

                    } else
                        val0 = val;
                }
                kontaiter++;
                if (kontaiter > 50 * 0.1 / arq.buscaFC) { // limite de iteracoes, falha na busca do segundo chute
                    // fim da simulacao ou aviso de falha
                    if ((*vg1dSP).chaverede == 0) {
                        if (arq.transiente == 0 && chute < 0 && arq.AP == 0) {
                            NumError("Busca de valores iniciais para calculo de zero de funcao em buscaProdPfundoPerm atingiu maximo de iteracoes");
                            logger.log(LOGGER_AVISO, LOG_ERR_PARSE_BUSINESS_RULE_VALIDATION,
                                       "Busca de valores iniciais para calculo de zero de funcao em buscaProdPfundoPerm atingiu maximo de iteracoes",
                                       "", "");
                        } else {
                            if (kontaTenta < 0)
                                logger.log(LOGGER_AVISO, LOG_ERR_PARSE_BUSINESS_RULE_VALIDATION,
                                           "Busca de valores iniciais para calculo de zero de funcao em buscaProdPfundoPerm atingiu maximo de iteracoes",
                                           "", "");
                            cout << "#################PERMANENTE FALHOU EM SUA CONVERGENCIA##############################" << endl;
                            if ((*vg1dSP).iterRede > 0)
                                return -1.1e10;
                            else
                                return 1.1e10;
                        }
                    } else {
                        if ((*vg1dSP).iterRede > 0)
                            return -1.1e10;
                        else
                            return 1.1e10;
                    }
                }
                while (val > 0.9e10) { // o incremento de pressao foi demais e a marcha nao foi capaz
                    // de ir ate o final sem que a pressao ficasse maior do que a pressao estatica
                    // em um eventual IPR no meio da marcha ou maior que o limitre maximo de pressao
                    // da tabela PVTSim, quando for este o caso
                    // deve-se diminuir a estimativa de pressao baixa
                    chutelim = pchute2;
                    pchute2 = 0.5 * (pchute2 + pchuteAux); // valor intermediario entre a maior pressao
                    // que leva a val>0 e a pressao alta demais
                    val = marchaProdPerm1(pchute2);
                    if (fabs(val) > 1.01e10) {
                        if (kontaTenta < 0)
                            logger.log(LOGGER_AVISO, LOG_ERR_PARSE_BUSINESS_RULE_VALIDATION,
                                       "Busca de valores iniciais para calculo de zero de funcao em buscaProdPfundoPerm atingiu maximo de iteracoes",
                                       "", "");
                        cout << "#################PERMANENTE FALHOU EM SUA CONVERGÃŠNCIA##############################" << endl;
                        if ((*vg1dSP).iterRede > 0)
                            return -1.1e10;
                        else
                            return 1.1e10;
                    }
                    if (val > 0 && val < 0.9e10)
                        chutePos = pchute2;
                    kontaiter++;
                    if (kontaiter > 50 * 0.1 / arq.buscaFC) {
                        if ((*vg1dSP).chaverede == 0) {
                            if (arq.transiente == 0 && chute < 0 && arq.AP == 0) {
                                NumError("Busca de valores iniciais para calculo de zero de funcao em buscaProdPfundoPerm atingiu maximo de iteracoes");
                                logger.log(LOGGER_AVISO, LOG_ERR_PARSE_BUSINESS_RULE_VALIDATION,
                                           "Busca de valores iniciais para calculo de zero de funcao em buscaProdPfundoPerm atingiu maximo de iteracoes",
                                           "", "");
                            } else {
                                if (kontaTenta < 0)
                                    logger.log(LOGGER_AVISO, LOG_ERR_PARSE_BUSINESS_RULE_VALIDATION,
                                               "Busca de valores iniciais para calculo de zero de funcao em buscaProdPfundoPerm atingiu maximo de iteracoes",
                                               "", "");
                                cout << "#################PERMANENTE FALHOU EM SUA CONVERGENCIA##############################" << endl;

                                if ((*vg1dSP).iterRede > 0)
                                    return -1.1e10;
                                else
                                    return 1.1e10;
                            }
                        } else {
                            if ((*vg1dSP).iterRede > 0)
                                return -1.1e10;
                            else
                                return 1.1e10;
                        }
                    }
                }
            }
            chuteNeg = pchute2;
        }

        if (reversao == 0)
            return zriddr(chuteNeg, chutePos, 1, 0); // com as duas estimativas de pressao
        // em posicoes de sinal contrario da curva, inicia-se o processo de calculo de zero
        // de funcao
        else
            return buscaProdPfundoPermRev(pchute * 1.);
    }
}

double SProd::buscaProdPfundoPermRev(double chute) {
    revPerm = 1;
    monitConvPerm = 1000.;
    // busca de dois chutes iniciais com valores com sinais opostos
    // para marchaProdPerm1 e assim iniciar o prpocesso de calculo de erro de funcao.
    double pchute = pGSup; // inicializando o valor de pchute com o valor da pressao a jusante
    // do choke, pchute sera o valor de chute de fato no processo de busca
    // se o valor de chute>0, pchute=chute, senao, ele e estimado
    double taux; // valor de temperatura auxiliar para o eventual calculo
    // de pchute
    double j = 0.;
    double rmis = 0.;
    double f1 = 0.;
    double perdafric = 0.;
    double betaChute = 0.;

    if (chute < 0) {

        if (celula[0].acsr.tipo == 2 && fabs(celula[0].acsr.injl.QLiq) > 0.) {
            // este espaco faz uma estimativa de quanto deve ser a perda de carga media
            // a partir do valor da vazao no inicio da tubulacao, isto e feito apenas
            // se existir uma fonte de liquido, celula[0].acsr.tipo == 2
            taux = arq.celp[0].textern; // a temperatura em que esta estimativa sera feita
            // e dada pela temperatura da fonte, a pressao para o calculo das propriedades
            // e feita por pGSup
            if (taux < arq.tmin)
                taux = arq.tmin;
            ///////////propriedades fisicas:
            double bet = celula[0].acsr.injl.bet;
            betaChute = bet;
            double visC = celula[0].acsr.injl.fluidocol.VisFlu(pchute, taux);
            double visP = celula[0].acsr.injl.FluidoPro.ViscOleo(pchute, taux);
            double visG = celula[0].acsr.injl.FluidoPro.ViscGas(pchute, taux);
            double visMis = (1 - bet) * visP + bet * visC;
            double rC = celula[0].acsr.injl.fluidocol.MasEspFlu(pchute, taux);
            double rP = celula[0].acsr.injl.FluidoPro.MasEspLiq(pchute, taux);
            double rG = celula[0].acsr.injl.FluidoPro.MasEspGas(pchute, taux);
            rmis = (1 - bet) * rP + bet * rC;
            double rlpA = celula[0].acsr.injl.FluidoPro.MasEspLiq(1., 15.);
            double rlcA = celula[0].acsr.injl.fluidocol.MasEspFlu(1.001, 15.);
            // estimativa grosseira da vazao massica do liquido complementar
            double massicC = rlcA * celula[0].acsr.injl.QLiq * celula[0].acsr.injl.bet / 86400;
            // estimativa grosseira da vazao massica de liquido e gas produzidos
            double massic;
            // massas especificas, condicao standard
            double Rhogs = celula[0].acsr.injl.FluidoPro.Deng * 1.225; // cel[ind].acsr.injl.FluidoPro.MasEspGas(1, 15);
            double Rhols = (1000 * 141.5 / (131.5 + celula[0].acsr.injl.FluidoPro.API)) * (1 - celula[0].acsr.injl.FluidoPro.BSW) + 1000. * celula[0].acsr.injl.FluidoPro.Denag * celula[0].acsr.injl.FluidoPro.BSW;
            // multiplicador da vazao standard para se obter a Vazao massicagÃ¡s+liquido produzido
            double multiplicador = (Rhols + celula[0].acsr.injl.FluidoPro.RGO * Rhogs * (1 - celula[0].acsr.injl.FluidoPro.BSW));
            // massic *= multiplicador;//alteracao8
            massic = 1 * multiplicador * celula[0].acsr.injl.QLiq * (1. - celula[0].acsr.injl.bet) / 86400;
            // titulo do gas em relacao a misturaoleo+agua+gas
            double fracmasshidra = celula[0].acsr.injl.FluidoPro.FracMassHidra(pchute, taux);
            double massicP = (1. - fracmasshidra) * massic; // vazao massica de liquido produzido
            double massicG = fracmasshidra * massic;        // vazao massaica de gas
            /// estimativa grosseira da velocidade da mistura
            j = (massicP / rP + massicC / rC + massicG / rG) / celula[0].duto.area;
            // estimativa da fracao de vazio sem escorregamento
            double alfmis = (massicG / rG) / (massicP / rP + massicC / rC + massicG / rG);
            // propriedades de mistura
            rmis = (1 - alfmis) * rmis + alfmis * rG;
            visMis = (1 - alfmis) * visMis + alfmis * visG;
            // estimativa de numero de Reynolds
            double re;
            if (celula[0].duto.revest == 0)
                re = celula[0].Rey(celula[0].duto.a, j, rmis, visMis);
            else {
                double dhid = 4 * celula[0].duto.area / celula[0].duto.peri;
                re = celula[0].Rey(dhid, j, rmis, visMis);
            }
            // estimativa de um fator de friccao
            f1 = celula[0].fric(re, celula[0].duto.rug / celula[0].duto.a);
        }
        double tmparea = celula[0].duto.area;
        double tmpperi = celula[0].duto.peri;
        // estimativa da perda por friccao no sistema, se o acessorio no inicio da tubulacao
        // nao for uma fonte de liquido, esta estimativa sera zero
        perdafric = (f1 * rmis * j * fabs(j) / 2.) * tmpperi / tmparea;
        // se o acessorio for uma IPR, a estimativa serÃ¡ uma pressao prÃ³xima a uma vazao baixa
        // no fundo do poco
        // se nao for IPR, a estimativa continua, considerando a perda de carga e a hidrostatica,
        // que serÃ¡ avaliada neste laco
        for (int i = ncel; i > 0; i--) {
            taux = arq.celp[i].textern;
            if (taux < arq.tmin)
                taux = arq.tmin;
            double rhol = celula[i].flui.MasEspLiq(pchute, taux);
            double rhog = celula[i].flui.MasEspGas(pchute, taux);
            // se o sistema nao for um anel principal de GL
            // para a estimativa de pressao, se utilizara so a hidrostatica de liquido, o que dara um
            // chute inicial de pressao muito alta
            double alfa = 0.;
            if (betaChute < 0.5) {
                double tit = celula[i].flui.FracMassHidra(pchute, taux);
                alfa = tit * rhol / (rhog - tit * rhog + tit * rhol);
            }
            if (derivaAnel == 0)
                alfa = 1.; // se for o anel, so se tem gas
            else if ((*vg1dSP).chaverede == 1 && chuteHol < 0.5 && chuteHol > -1e-15)
                alfa = 1. - chuteHol * 2.;
            double rhomix = (1. - alfa) * rhol + alfa * rhog;
            double dxmed = 0.5 * (celula[i].dx + celula[i - 1].dx);
            // avanco da pressao por meio da hidrostatica e da perda por friccao estimada
            pchute += ((rhomix * 9.81 * sin(celula[i].duto.teta) * dxmed + perdafric * dxmed) / 98066.5);
            // incremento de pressao devido a algum ganho de pressao constante em alguma celula
            if (celula[i - 1].acsr.tipo == 7)
                pchute += celula[i - 1].acsr.delp;
            // caso exista alguma IPR no meio do duto, verifica se a pressao estimada esta maior que
            // a pressao estatica, nÃ£o se trabalha com vazoes negativas neste solver
            // para evitar isto, se corrige a pressao para um valor proximo da
            // pressao estatica da IPR da celula
            if (celula[i - 1].acsr.tipo == 3 &&
                ((celula[i - 1].acsr.ipr.Pres - pchute) > -0.01 * celula[i - 1].acsr.ipr.Pres) && i == 1) {
                pchute = (10 / celula[i - 1].acsr.ipr.ip) + celula[i - 1].acsr.ipr.Pres;
                if (pchute > 1.1 * celula[i - 1].acsr.ipr.Pres)
                    pchute = 1.1 * celula[i - 1].acsr.ipr.Pres;
                if (pchute < 1.01 * celula[i - 1].acsr.ipr.Pres)
                    pchute = 1.01 * celula[i - 1].acsr.ipr.Pres;
            }
            // tambÃ©m se evita um chute com valores maiores que o limite maximo de uma tabela
            // no caso de se estar usando PVTSim
            if (arq.usaTabela == 1 && (arq.tabent.pmax - pchute) < (*vg1dSP).localtiny)
                pchute = 0.9 * arq.tabent.pmax;
        }

        if (pchute > 1000)
            pchute = 1000; // pressao maxima de chute
    } else
        pchute = chute; // caso chute nao seja negativo utiliza a estimativa enviada na
    // lista de parametro do metodo
    double pchute2;        // segundo chute de pressao da busca
    double pchuteAux = 0.; // auxiliar na busca de dos chutes de pressao
    // necessarios para se dar partida no metodo de calculo de raiz
    double val; // val recebe sempre o valor retornado pelo procedimento de marcha
    // neste caso, Ã© a pressao a montante do choke-a pressao da ultima celula, calculada pela
    // marcha
    val = marchaProdPerm1Rev(pchute);
    buscaIni = 1;
    // a marcha pode dar problemas, ou a pressao em algum ponto deu acima da pressao estÃ¡tica de
    // de alguma IPR no meio do caminho, retorna 1e10,
    // ou antes de atingir a ultima celula, a pressao ficou proximo de zero, ou a pressao
    // retorna -1e10, ou a pressao, para o caso PVTSim, ficou acima da pressao maxima da tabela
    // retorna 1e10
    if (val < -0.9e10) { // pressao muito baixa na marcha, deve ser aumentado o valor de chute
        // faz-se uma nova estimativa, sÃ³ que agora admitindo uma hidrostÃ¡tica de Ã¡gua,
        // o que darÃ¡ uma pressao de fundpo mais alta
        pchuteAux = pGSup;
        for (int i = ncel; i > 0; i--) {
            taux = arq.celp[i].textern;
            double rhol = 1000 + 0 * celula[i].flui.MasEspLiq(pchuteAux, taux);
            double rhog = celula[i].flui.MasEspGas(pchuteAux, taux);
            double alfa = 0.;
            if (derivaAnel == 0)
                alfa = 1.;
            else if ((*vg1dSP).chaverede == 1 && chuteHol < 0.5 && chuteHol > -1e-15)
                alfa = 1. - chuteHol * 2.;
            double rhomix = (1. - alfa) * rhol + alfa * rhog;
            double dxmed = 0.5 * (celula[i].dx + celula[i - 1].dx);
            pchuteAux += (rhomix * 9.81 * sin(celula[i].duto.teta) * dxmed + perdafric * dxmed) / 98066.5;
            if (celula[i - 1].acsr.tipo == 7)
                pchuteAux -= celula[i - 1].acsr.delp;
            if (celula[i - 1].acsr.tipo == 3 &&
                ((celula[i - 1].acsr.ipr.Pres - pchuteAux) > -0.01 * celula[i - 1].acsr.ipr.Pres && i == 1)) {
                pchuteAux = (10 / celula[i - 1].acsr.ipr.ip) + celula[i - 1].acsr.ipr.Pres;
                if (pchuteAux > 1.01 * celula[i - 1].acsr.ipr.Pres)
                    pchuteAux = 1.01 * celula[i - 1].acsr.ipr.Pres;
            }
            if (arq.usaTabela == 1 && (arq.tabent.pmax - pchuteAux) < (*vg1dSP).localtiny)
                pchuteAux = 0.9 * arq.tabent.pmax;
        }
        if (pchuteAux > 1100)
            pchuteAux = 1100;  // limite de pchuteAux
    } else if (val > 0.9e10) { // pressÃƒÂ£o em algum ponto ficou acima de alguma pressao estatica
        // deve-se diminuir o valor do chute
        pchuteAux = pGSup;
        for (int i = ncel; i > 0; i--) {
            taux = arq.celp[i].textern;
            double rhol = celula[i].flui.MasEspLiq(pchuteAux, taux);
            double rhog = celula[i].flui.MasEspGas(pchuteAux, taux);
            // neste caso, utiliza-se uma fraÃ§Ã£o de vazio alta para a hidrostÃ¡tica
            double alfa = 0.8;
            if (derivaAnel == 0)
                alfa = 1.;
            else if ((*vg1dSP).chaverede == 1 && chuteHol < 0.2 && chuteHol > -1e-15)
                alfa = 1. - chuteHol;
            double rhomix = (1. - alfa) * rhol + alfa * rhog;
            double dxmed = 0.5 * (celula[i].dx + celula[i - 1].dx);
            pchuteAux += (rhomix * 9.81 * sin(celula[i].duto.teta) * dxmed + perdafric * dxmed) / 98066.5;
            if (celula[i - 1].acsr.tipo == 7)
                pchuteAux -= celula[i - 1].acsr.delp;
            if (celula[i - 1].acsr.tipo == 3 &&
                ((celula[i - 1].acsr.ipr.Pres - pchuteAux) > -0.01 * celula[i - 1].acsr.ipr.Pres && i == 1)) {
                pchuteAux = (10 / celula[i - 1].acsr.ipr.ip) + celula[i - 1].acsr.ipr.Pres;
                if (pchuteAux > 1.01 * celula[i - 1].acsr.ipr.Pres)
                    pchuteAux = 1.01 * celula[i - 1].acsr.ipr.Pres;
            }
            if (arq.usaTabela == 1 && (arq.tabent.pmax - pchuteAux) < (*vg1dSP).localtiny)
                pchuteAux = 0.9 * arq.tabent.pmax;
        }
        if (pchuteAux > 1100)
            pchuteAux = 1100;
    }

    double mult1 = 0.9;
    double mult2 = 1.1;
    int tipo = 1;

    // para o caso de ter dado eerado a primeira marcha, com pchuteAux faz-se uma nova tentativa
    int kontaiter = 0; // contador para o laco em que se tentara uma nova estimativa
    // em que ao menos os valores 1e10 ou 1e-10 nÃ£o seja retornados
    double pchuteAux0 = pchuteAux;
    if ((val < -0.9e10 || val > 0.9e10) && kontaiter <= 100) {
        double valtemp;
        valtemp = marchaProdPerm1Rev(pchuteAux);   // marcha com pchuteAux
        while (valtemp > 0.9e10 && val > 0.9e10) { // estimativa de pressao de fundo ainda alta
            pchuteAux *= 0.99;                     // reduzindo a estimativa
            valtemp = marchaProdPerm1Rev(pchuteAux);
            kontaiter++; // 50 iteracoes no maximo
        }
        while (valtemp < -0.9e10 && val < -0.9e10 && kontaiter < 100) { // estimativa de pressao de fundo ainda baixa
            if (celula[0].acsr.tipo == 1 || celula[0].acsr.tipo == 2 || celula[0].acsr.tipo == 10)
                pchuteAux *= 1.1;
            else
                pchuteAux *= 1.01; // aumentando a estimativa
            // verificando se este aumento ultrapassa o limite de pressao de uma eventual IPR no
            // fundo
            int limpres = 0;
            if (celula[0].acsr.tipo == 3 &&
                (celula[0].acsr.ipr.Pres - pchuteAux) < -0.01 * celula[0].acsr.ipr.Pres) {

                pchuteAux = (10 / celula[0].acsr.ipr.ip) + celula[0].acsr.ipr.Pres;
                if (pchuteAux > 1.01 * celula[0].acsr.ipr.Pres)
                    pchuteAux = 1.01 * celula[0].acsr.ipr.Pres;

                limpres = 1; // indicadpor de que este avanÃ§o de pressao esta muito alto
                // outros avancos devem ser feitos em um passo menor
            }
            // verificando se este aumento de estimativa foca acima do valor maximo de pressao
            // de uma eventual tabela PVTSim
            if (arq.usaTabela == 1 && (arq.tabent.pmax - pchuteAux) < (*vg1dSP).localtiny)
                pchuteAux = 0.9 * arq.tabent.pmax;
            valtemp = marchaProdPerm1Rev(pchuteAux); // nova tentativa
            if (valtemp < -0.9e10 && limpres == 1) { // continua alto e existe o indicador
                // de que deve-se usar um passo de aumento de pressao menor
                int iterpres = 0;
                while (valtemp < -0.9e10 && iterpres < 10) { // novo laco com um passo menor,
                    // maximo de 10 iteracoes
                    pchuteAux *= 1.001;
                    valtemp = marchaProdPerm1Rev(pchuteAux);
                    iterpres++;
                }
                if (iterpres >= 10) {
                    // caso em que atingiu o maximo de passos de incremento de pressa em uma situacao
                    // de passo pequeno, retorna um aviso que deu problema ou finaliza a simulacao
                    if (arq.transiente == 0 && chute < 0 && arq.AP == 0)
                        // neste caso, se finaliza a simulacao, nao tem um transiente
                        // a ser feito a seguir e nem se estÃ¡ em uma rede
                        NumError(
                            "Busca de valores iniciais para calculo de zero de funcao em buscaProdPfundoPerm atingiu maximo de iteracoes");
                    else {
                        // apresenta apenas um aviso
                        cout << "#################PERMANENTE FALHOU EM SUA CONVERGÃŠNCIA##############################" << endl;
                        // se for em uma iteracao de rede, apos a primeira iteracao
                        if ((*vg1dSP).iterRede > 0)
                            return -1.1e10;
                        // se logo apÃƒÂ³s tem uma simulacao transiente ou se esta na primeira iteracao de rede
                        else
                            return 1.1e10;
                    }
                }
            }
            if (kontaiter == 100) {
                pchuteAux = 0.5 * pchuteAux0;
            }
            kontaiter++;
        }
        if (valtemp > -0.9e10 && valtemp < 0.9e10) { // conseguiu fazer a marcha atÃƒÂ© o final
            val = valtemp;
            pchute = pchuteAux;
        }
    }
    if (kontaiter > 100) { // chegou ao limite da iteracao
        if ((*vg1dSP).chaverede == 0) {
            // neste caso, se finaliza a simulacao, nao tem um transiente
            // a ser feito a seguir e nem se estÃ¡ em uma rede
            if (arq.transiente == 0 && chute < 0 && arq.AP == 0)
                NumError("Busca de valores iniciais para calculo de zero de funcao em buscaProdPfundoPerm atingiu maximo de iteracoes");
            else {
                // apresenta apenas um aviso
                cout << "#################PERMANENTE FALHOU EM SUA CONVERGÃŠNCIA##############################" << endl;
                // se for em uma iteracao de rede, apos a primeira iteracao
                if ((*vg1dSP).iterRede > 0)
                    return -1.1e10;
                // se logo apos tem uma simulacao transiente ou se esta na primeira iteracao de rede
                else
                    return 1.1e10;
            }
        } else {
            // se for em uma iteracao de rede, apos a primeira iteracao
            if ((*vg1dSP).iterRede > 0)
                return -1.1e10;
            // se logo apÃ³s tem uma simulacao transiente ou se esta na primeira iteracao de rede
            else
                return 1.1e10;
        }
    }

    // caso o laÃ§o anterior tenha levado a estimativa de um valor 1e10 para um valor -1e10
    // ou tenha levado para um valor de -1e10 para 1e10
    // ou seja, de um chute de pressao alto demais para finalizar a marcha
    // para um chute de pressao baixo demais para terminar a marcha ou vice versa
    while ((val < -0.9e10 || val > 0.9e10) && kontaiter < 100) {
        pchute = 0.5 * (pchute + pchuteAux); // busca-se um valor medio
        // entre o alto demais e o baixo demais
        if ((fabs(pchute - pchuteAux) / pchute) < 0.001 && val < -0.9e10) {
            pchute = 1.05 * pchute;
            if (celula[0].acsr.tipo == 3 && (celula[0].acsr.ipr.Pres - pchute) > 0.00 * celula[0].acsr.ipr.Pres) {
                pchute = (10 / celula[0].acsr.ipr.ip) + celula[0].acsr.ipr.Pres;
                if (pchute > 1.01 * celula[0].acsr.ipr.Pres)
                    pchute = 1.01 * celula[0].acsr.ipr.Pres;
            }
            if (arq.usaTabela == 1 && (arq.tabent.pmax - pchute) < (*vg1dSP).localtiny)
                pchute = 0.9 * arq.tabent.pmax;
            pchuteAux = pchute;
        }
        val = marchaProdPerm1Rev(pchute);
        kontaiter++;
    }
    if (kontaiter >= 100) {
        if ((*vg1dSP).chaverede == 0) {
            if (arq.transiente == 0 && chute < 0 && arq.AP == 0)
                NumError("Busca de valores iniciais para calculo de zero de funcao em buscaProdPfundoPerm atingiu maximo de iteracoes");
            else {
                cout << "#################PERMANENTE FALHOU EM SUA CONVERGÃŠNCIA##############################" << endl;
                if ((*vg1dSP).iterRede > 0)
                    return -1.1e10;
                else
                    return 1.1e10;
            }
        } else {
            if ((*vg1dSP).iterRede > 0)
                return -1.1e10;
            else
                return 1.1e10;
        }
    }
    // caso tenha sido possivel obter um chute de pressao em que foi possivel finalizar a marcha
    kontaiter = 0;
    pchute2 = pchute;
    double chuteNeg = 0.;
    double chutePos = 0.;
    double chutelim = 0.;
    arq.buscaFC = fabs(arq.buscaFC);
    double reduz = 1. - arq.buscaFC;
    double amplifica = 1. + arq.buscaFC;
    double aumenta = amplifica;
    if (fabs(val) < 1e-3)
        return pchute;
    else {
        if (val < 0.) { // caso em que pressao a montante do choke < pressao da ultima celula, calculada pela
            // marcha, isto implica em pressao de chute alta , deve-se agora buscar
            // uma pressao de chute baixa para que val seja positivo e assim iniciar o processo
            // de calculo de zero de funcao
            chuteNeg = pchute; // armazenando o valor de chute de pressao que da o valor negativo
            // a cada nova busca em que val se aproxima de zero, mas ainda negativo
            // chuteNeg Ã© atualizado com a Ãºltima pressao de chute
            while (val < 0) {
                if (fabs(pchute2 - pchute) / pchute < (1. - reduz) / 10. && kontaiter > 100) {
                    pchute2 *= 0.5;
                }
                pchuteAux = pchute2;
                pchute2 *= reduz; // Diminuindo a pressao na busca de val>0
                if (pchute2 <= chutelim)
                    pchute2 = 0.5 * (pchuteAux + chutelim); // chutelim inicialmente
                // e zero, mas pode acontecer de baixar demais pchute2 ao ponto de val=-1e10
                //(pressao abaixo de 0.5 no meio da marcha), neste caso, chutelim se torna este valor de
                // pchute2, pois, com isto, ja se sabe que nao se pode ir abaixo de chutelim
                val = marchaProdPerm1Rev(pchute2);
                if (val < 0 && val > -0.9e10)
                    chuteNeg = pchute2; // atualizando o chuteNeg
                kontaiter++;
                if (kontaiter > 100) { // limite de iteracoes, falha na busca do segundo chute
                    // fim da simulacao ou aviso de falha
                    if ((*vg1dSP).chaverede == 0) {
                        if (arq.transiente == 0 && chute < 0 && arq.AP == 0)
                            NumError("Busca de valores iniciais para calculo de zero de funcao em buscaProdPfundoPerm atingiu maximo de iteracoes");
                        else {
                            cout << "#################PERMANENTE FALHOU EM SUA CONVERGENCIA##############################" << endl;
                            if ((*vg1dSP).iterRede > 0)
                                return -1.1e10;
                            else
                                return 1.1e10;
                        }
                    } else {
                        if ((*vg1dSP).iterRede > 0)
                            return -1.1e10;
                        else
                            return 1.1e10;
                    }
                }
                while (val < -0.9e10) { // a reduÃ§Ã£o de pressao foi demais e a marcha nÃ£o foi capaz
                    // de ir ate o final sem que a pressao ficasse inferior a 0.5kgf/cm2
                    // deve-se aumentar a estimativa de pressao baixa
                    chutelim = pchute2;
                    pchute2 = 0.5 * (pchute2 + pchuteAux); // valor intermediario entre a menor pressao
                    // que leva a val<0 e a pressao baixa demais
                    val = marchaProdPerm1Rev(pchute2);
                    if (val < 0 && val > -0.9e10)
                        chuteNeg = pchute2;
                    kontaiter++;
                    if (kontaiter > 100) {
                        if ((*vg1dSP).chaverede == 0) {
                            if (arq.transiente == 0 && chute < 0 && arq.AP == 0)
                                NumError("Busca de valores iniciais para calculo de zero de funcao em buscaProdPfundoPerm atingiu maximo de iteracoes");
                            else {
                                cout << "#################PERMANENTE FALHOU EM SUA CONVERGENCIA##############################" << endl;
                                if ((*vg1dSP).iterRede > 0)
                                    return -1.1e10;
                                else
                                    return 1.1e10;
                            }
                        } else {
                            if ((*vg1dSP).iterRede > 0)
                                return -1.1e10;
                            else
                                return 1.1e10;
                        }
                    }
                }
            }
            chutePos = pchute2;
        } else if (val > 0.) { // caso em que pressao a montante do choke > pressao da ultima celula,
            // calculada pela
            // marcha, isto implica em pressao de chute baixa , deve-se agora buscar
            // uma pressao de chute alta para que val seja negativo e assim iniciar o processo
            // de calculo de zero de funcao
            chutePos = pchute; // armazenando o valor de chute de pressao que da o valor positivo
            // a cada nova busca em que val se aproxima de zero, mas ainda positivo
            // chutePos e atualizado com a Ãºltima pressao de chute
            while (val > 0) {
                pchuteAux = pchute2;
                pchute2 *= aumenta; // Aumentando a pressao na busca de val>0
                int limpres = 0;
                val = marchaProdPerm1Rev(pchute2);
                if (val > 0 && val < 0.9e10)
                    chutePos = pchute2; // atualizando o chutePos
                kontaiter++;
                if (kontaiter > 100) { // limite de iteracoes, falha na busca do segundo chute
                    // fim da simulacao ou aviso de falha
                    if ((*vg1dSP).chaverede == 0) {
                        if (arq.transiente == 0 && chute < 0 && arq.AP == 0)
                            NumError("Busca de valores iniciais para calculo de zero de funcao em buscaProdPfundoPerm atingiu maximo de iteracoes");
                        else {
                            cout << "#################PERMANENTE FALHOU EM SUA CONVERGENCIA##############################" << endl;
                            if ((*vg1dSP).iterRede > 0)
                                return -1.1e10;
                            else
                                return 1.1e10;
                        }
                    } else {
                        if ((*vg1dSP).iterRede > 0)
                            return -1.1e10;
                        else
                            return 1.1e10;
                    }
                }
                while (val > 0.9e10) { // o incremento de pressao foi demais e a marcha nao foi capaz
                    // de ir ate o final sem que a pressao ficasse maior do que a pressao estatica
                    // em um eventual IPR no meio da marcha ou maior que o limitre maximo de pressao
                    // da tabela PVTSim, quando for este o caso
                    // deve-se diminuir a estimativa de pressao baixa
                    chutelim = pchute2;
                    pchute2 = 0.5 * (pchute2 + pchuteAux); // valor intermediario entre a maior pressao
                    // que leva a val>0 e a pressao alta demais
                    val = marchaProdPerm1Rev(pchute2);
                    if (val > 0 && val < 0.9e10)
                        chutePos = pchute2;
                    kontaiter++;
                    if (kontaiter > 100) {
                        if ((*vg1dSP).chaverede == 0) {
                            if (arq.transiente == 0 && chute < 0 && arq.AP == 0)
                                NumError("Busca de valores iniciais para calculo de zero de funcao em buscaProdPfundoPerm atingiu maximo de iteracoes");
                            else {
                                cout << "#################PERMANENTE FALHOU EM SUA CONVERGENCIA##############################" << endl;

                                if ((*vg1dSP).iterRede > 0)
                                    return -1.1e10;
                                else
                                    return 1.1e10;
                            }
                        } else {
                            if ((*vg1dSP).iterRede > 0)
                                return -1.1e10;
                            else
                                return 1.1e10;
                        }
                    }
                }
            }
            chuteNeg = pchute2;
        }

        return zriddr(chuteNeg, chutePos, 1, 0); // com as duas estimativas de pressao
        // em posicoes de sinal contrario da curva, inicia-se o processo de calculo de zero
        // de funcao
    }
}

double SProd::buscaProdPfundoPerm2(double chute, int kontaTenta) {
    // busca de dois chutes iniciais com valores com sinais opostos
    // para marchaProdPerm1 e assim iniciar o prpocesso de calculo de erro de funcao.
    revPerm = 0;
    monitConvPerm = 1000.;
    double pchute = pGSup; // inicializando o valor de pchute com o valor da pressao a jusante
    // do choke, pchute sera o valor de chute de fato no processo de busca
    // se o valor de chute>0, pchute=chute, senao, ele e estimado
    double taux; // valor de temperatura auxiliar para o eventual calculo
    // de pchute
    double j = 0.;
    double rmis = 0.;
    double f1 = 0.;
    double perdafric = 0.;
    double betaChute = 0.;

    if (chute < 0) {
        if (celula[0].acsr.tipo == 2 && fabs(celula[0].acsr.injl.QLiq) > 0.) {
            // este espaco faz uma estimativa de quanto deve ser a perda de carga media
            // a partir do valor da vazao no inicio da tubulacao, isto e feito apenas
            // se existir uma fonte de liquido, celula[0].acsr.tipo == 2
            taux = arq.celp[0].textern;
            // a temperatura em que esta estimativa sera feita
            // e dada pela temperatura da fonte, a pressao para o calculo das propriedades
            // e feita por pGSup
            if (taux < arq.tmin)
                taux = arq.tmin;
            ///////////propriedades fisicas:
            double bet = celula[0].acsr.injl.bet;
            betaChute = bet;
            double visC = celula[0].acsr.injl.fluidocol.VisFlu(pchute, taux);
            double visP = celula[0].acsr.injl.FluidoPro.ViscOleo(pchute, taux);
            double visG = celula[0].acsr.injl.FluidoPro.ViscGas(pchute, taux);
            double visMis = (1 - bet) * visP + bet * visC;
            double rC = celula[0].acsr.injl.fluidocol.MasEspFlu(pchute, taux);
            double rP = celula[0].acsr.injl.FluidoPro.MasEspLiq(pchute, taux);
            double rG = celula[0].acsr.injl.FluidoPro.MasEspGas(pchute, taux);
            rmis = (1 - bet) * rP + bet * rC;
            double rlpA = celula[0].acsr.injl.FluidoPro.MasEspLiq(1., 15.);
            double rlcA = celula[0].acsr.injl.fluidocol.MasEspFlu(1.001, 15.);
            // estimativa grosseira da vazao massica do liquido complementar
            double massicC = rlcA * celula[0].acsr.injl.QLiq * celula[0].acsr.injl.bet / 86400;
            // estimativa grosseira da vazao massica de liquido e gas produzidos
            double massic = rlpA * celula[0].acsr.injl.QLiq * (1. - celula[0].acsr.injl.bet) / 86400;
            // massas especificas, condicao standard
            double Rhogs = celula[0].acsr.injl.FluidoPro.Deng * 1.225; // cel[ind].acsr.injl.FluidoPro.MasEspGas(1, 15);
            double Rhols = (1000 * 141.5 / (131.5 + celula[0].acsr.injl.FluidoPro.API)) * (1 - celula[0].acsr.injl.FluidoPro.BSW) + 1000. * celula[0].acsr.injl.FluidoPro.Denag * celula[0].acsr.injl.FluidoPro.BSW;
            // multiplicador da vazao standard para se obter a Vazao massicagÃ¡s+liquido produzido
            double multiplicador = (Rhols + celula[0].acsr.injl.FluidoPro.RGO * Rhogs * (1 - celula[0].acsr.injl.FluidoPro.BSW));
            // massic *= multiplicador;//alteracao8
            if ((*vg1dSP).chaverede == 1)
                massic = 1 * multiplicador * celula[0].acsr.injl.QLiq * (1. - celula[0].acsr.injl.bet) / 86400;
            else
                massic = 1 * multiplicador * celula[0].acsr.injl.QLiq * (1. - celula[0].acsr.injl.bet) / 86400;
            // titulo do gas em relacao a misturaoleo+agua+gas
            double fracmasshidra = celula[0].acsr.injl.FluidoPro.FracMassHidra(pchute, taux);
            double massicP = (1. - fracmasshidra) * massic; // vazao massica de liquido produzido
            double massicG = fracmasshidra * massic;        // vazao massaica de gas
            /// estimativa grosseira da velocidade da mistura
            j = (massicP / rP + massicC / rC + massicG / rG) / celula[0].duto.area;
            // estimativa da fracao de vazio sem escorregamento
            double alfmis = (massicG / rG) / (massicP / rP + massicC / rC + massicG / rG);
            // propriedades de mistura
            rmis = (1 - alfmis) * rmis + alfmis * rG;
            visMis = (1 - alfmis) * visMis + alfmis * visG;
            // estimativa de numero de Reynolds
            double re;
            if (celula[0].duto.revest == 0)
                re = celula[0].Rey(celula[0].duto.a, j, rmis, visMis);
            else {
                double dhid = 4 * celula[0].duto.area / celula[0].duto.peri;
                re = celula[0].Rey(dhid, j, rmis, visMis);
            }
            // estimativa de um fator de friccao
            f1 = celula[0].fric(re, celula[0].duto.rug / celula[0].duto.a);
        }
        // estimativa da perda por friccao no sistema, se o acessorio no inicio da tubulacao
        // nao for uma fonte de liquido, esta estimativa sera zero
        perdafric = (f1 * rmis * j * fabs(j) / 2.) * celula[0].duto.peri / celula[0].duto.area;
        // se o acessorio for uma IPR, a estimativa serÃ¡ uma pressao prÃ³xima a uma vazao baixa
        // no fundo do poco
        // se nao for IPR, a estimativa continua, considerando a perda de carga e a hidrostatica,
        // que serÃ¡ avaliada neste laco
        for (int i = ncel; i > 0; i--) {
            taux = arq.celp[i].textern;
            if (taux < arq.tmin)
                taux = arq.tmin;
            double rhol = celula[i].flui.MasEspLiq(pchute, taux);
            double rhog = celula[i].flui.MasEspGas(pchute, taux);
            // se o sistema nao for um anel principal de GL
            // para a estimativa de pressao, se utilizara so a hidrostatica de liquido, o que dara um
            // chute inicial de pressao muito alta
            double alfa = 0.;
            if (betaChute < 0.5) {
                double tit = celula[i].flui.FracMassHidra(pchute, taux);
                alfa = tit * rhol / (rhog - tit * rhog + tit * rhol);
            }
            if (derivaAnel == 0)
                alfa = 1.; // se for o anel, so se tem gas
            else if ((*vg1dSP).chaverede == 0 && chuteHol > -1e-15)
                alfa = 1. - chuteHol;
            else if ((*vg1dSP).chaverede == 1 && chuteHol < 0.5 && chuteHol > -1e-15)
                alfa = 1. - chuteHol * 2.;
            double rhomix = (1. - alfa) * rhol + alfa * rhog;
            double dxmed = 0.5 * (celula[i].dx + celula[i - 1].dx);
            // avanco da pressao por meio da hidrostatica e da perda por friccao estimada
            pchute += (rhomix * 9.81 * sin(celula[i].duto.teta) * dxmed + perdafric * dxmed) / 98066.5;
            // caso exista alguma IPR no meio do duto, verifica se a pressao estimada esta maior que
            // a pressao estatica, nÃ£o se trabalha com vazoes negativas neste solver
            // para evitar isto, se corrige a pressao para um valor proximo da
            // pressao estatica da IPR da celula
            if (celula[i - 1].acsr.tipo == 3 &&
                ((celula[i - 1].acsr.ipr.Pres - pchute) < 0.01 * celula[i - 1].acsr.ipr.Pres && i == 1)) {
                double qchute = 0.15 * celula[i - 1].duto.area * 86400;
                pchute = -(qchute / celula[i - 1].acsr.ipr.ip) + celula[i - 1].acsr.ipr.Pres;
                if (pchute > 0.99 * celula[i - 1].acsr.ipr.Pres)
                    pchute = 0.99 * celula[i - 1].acsr.ipr.Pres;
                if (pchute < 0.9 * celula[i - 1].acsr.ipr.Pres)
                    pchute = 0.9 * celula[i - 1].acsr.ipr.Pres;
            }
            // tambÃ©m se evita um chute com valores maiores que o limite maximo de uma tabela
            // no caso de se estar usando PVTSim
            if (arq.usaTabela == 1 && (arq.tabent.pmax - pchute) < (*vg1dSP).localtiny)
                pchute = 0.9 * arq.tabent.pmax;
        }

        if (pchute > 1000)
            pchute = 1000.; // pressao maxima de chute
    } else
        pchute = chute; // caso chute nao seja negativo utiliza a estimativa enviada na
    // lista de parametro do metodo
    double pchute2;        // segundo chute de pressao da busca
    double pchuteAux = 0.; // auxiliar na busca de dos chutes de pressao
    // necessarios para se dar partida no metodo de calculo de raiz
    double val; // val recebe sempre o valor retornado pelo procedimento de marcha
    // neste caso, Ã© a pressao a montante do choke-a pressao da ultima celula, calculada pela
    // marcha
    val = marchaProdPerm2(pchute);
    buscaIni = 1;
    // a marcha pode dar problemas, ou a pressao em algum ponto deu acima da pressao estatica de
    // de alguma IPR no meio do caminho, retorna 1e10,
    // ou antes de atingir a ultima celula, a pressao ficou proximo de zero, ou a pressao
    // retorna -1e10, ou a pressao, para o caso PVTSim, ficou acima da pressao maxima da tabela
    // retorna 1e10
    if (val < -0.9e10) { // pressao muito baixa na marcha, deve ser aumentado o valor de chute
        // faz-se uma nova estimativa, sÃ³ que agora admitindo uma hidrostÃ¡tica de Ã¡gua,
        // o que darÃ¡ uma pressao de fundpo mais alta
        pchuteAux = pGSup;
        for (int i = ncel; i > 0; i--) {
            taux = arq.celp[i].textern;
            double rhol = 1000 + 0 * celula[i].flui.MasEspLiq(pchuteAux, taux);
            double rhog = celula[i].flui.MasEspGas(pchuteAux, taux);
            double alfa = 0.;
            if (derivaAnel == 0)
                alfa = 1.;
            else if ((*vg1dSP).chaverede == 1 && chuteHol < 0.5 && chuteHol > -1e-15)
                alfa = 1. - chuteHol * 2.;
            double rhomix = (1. - alfa) * rhol + alfa * rhog;
            double dxmed = 0.5 * (celula[i].dx + celula[i - 1].dx);
            pchuteAux += (rhomix * 9.81 * sin(celula[i].duto.teta) * dxmed + perdafric * dxmed) / 98066.5;
            if (celula[i - 1].acsr.tipo == 3 &&
                ((celula[i - 1].acsr.ipr.Pres - pchuteAux) < 0.01 * celula[i - 1].acsr.ipr.Pres && i == 1)) {
                pchuteAux = -(10 / celula[i - 1].acsr.ipr.ip) + celula[i - 1].acsr.ipr.Pres;
                if (pchuteAux < 0.99 * celula[i - 1].acsr.ipr.Pres)
                    pchuteAux = 0.99 * celula[i - 1].acsr.ipr.Pres;
            }
            if (arq.usaTabela == 1 && (arq.tabent.pmax - pchuteAux) < (*vg1dSP).localtiny)
                pchuteAux = 0.9 * arq.tabent.pmax;
        }
        if (pchuteAux > 1100)
            pchuteAux = 1100;  // limite de pchuteAux
    } else if (val > 0.9e10) { // pressao em algum ponto ficou acima de alguma pressao estatica
        // deve-se diminuir o valor do chute
        pchuteAux = pGSup;
        for (int i = ncel; i > 0; i--) {
            taux = arq.celp[i].textern;
            double rhol = celula[i].flui.MasEspLiq(pchuteAux, taux);
            double rhog = celula[i].flui.MasEspGas(pchuteAux, taux);
            // neste caso, utiliza-se uma fraÃ§Ã£o de vazio alta para a hidrostÃ¡tica
            double alfa = 0.8;
            if (derivaAnel == 0)
                alfa = 1.;
            else if ((*vg1dSP).chaverede == 1 && chuteHol < 0.2 && chuteHol > -1e-15)
                alfa = 1. - chuteHol;
            double rhomix = (1. - alfa) * rhol + alfa * rhog;
            double dxmed = 0.5 * (celula[i].dx + celula[i - 1].dx);
            pchuteAux += (rhomix * 9.81 * sin(celula[i].duto.teta) * dxmed + perdafric * dxmed) / 98066.5;
            if (celula[i - 1].acsr.tipo == 3 &&
                ((celula[i - 1].acsr.ipr.Pres - pchuteAux) < 0.01 * celula[i - 1].acsr.ipr.Pres && i == 1)) {
                pchuteAux = -(10 / celula[i - 1].acsr.ipr.ip) + celula[i - 1].acsr.ipr.Pres;
                if (pchuteAux < 0.99 * celula[i - 1].acsr.ipr.Pres)
                    pchuteAux = 0.99 * celula[i - 1].acsr.ipr.Pres;
            }
            if (arq.usaTabela == 1 && (arq.tabent.pmax - pchuteAux) < (*vg1dSP).localtiny)
                pchuteAux = 0.9 * arq.tabent.pmax;
        }
        if (pchuteAux > 1100)
            pchuteAux = 1100;
    }

    double mult1 = 0.9;
    double mult2 = 1.1;

    // para o caso de ter dado eerado a primeira marcha, com pchuteAux faz-se uma nova tentativa
    int kontaiter = 0; // contador para o laco em que se tentara uma nova estimativa
    // em que ao menos os valores 1e10 ou 1e-10 nÃ£o seja retornados
    double pchuteAux0 = pchuteAux;
    if (val < -0.9e10 || val > 0.9e10) {
        double valtemp;
        valtemp = marchaProdPerm2(pchuteAux); // marcha com pchuteAux
        if (fabs(valtemp) > 1.01e10) {
            cout << "#################PERMANENTE FALHOU EM SUA CONVERGÃŠNCIA##############################" << endl;
            if ((*vg1dSP).iterRede > 0)
                return -1.1e10;
            else
                return 1.1e10;
        }
        while (valtemp > 0.9e10 && val > 0.9e10 && kontaiter < 50) { // estimativa de pressao de fundo ainda alta
            pchuteAux *= 0.99;                                       // reduzindo a estimativa
            valtemp = marchaProdPerm2(pchuteAux);
            if (fabs(valtemp) > 1.01e10) {
                cout << "#################PERMANENTE FALHOU EM SUA CONVERGÃŠNCIA##############################" << endl;
                if ((*vg1dSP).iterRede > 0)
                    return -1.1e10;
                else
                    return 1.1e10;
            }
            kontaiter++; // 50 iteracoes no maximo
        }
        while (valtemp < -0.9e10 && val < -0.9e10 && kontaiter <= 50) { // estimativa de pressao de fundo ainda baixa
            if (celula[0].acsr.tipo == 1 || celula[0].acsr.tipo == 2 || celula[0].acsr.tipo == 10)
                pchuteAux *= 1.1;
            else
                pchuteAux *= 1.01; // aumentando a estimativa
            // verificando se este aumento ultrapassa o limite de pressao de uma eventual IPR no
            // fundo
            if (celula[0].acsr.tipo == 3 &&
                (celula[0].acsr.ipr.Pres - pchuteAux) < 0.01 * celula[0].acsr.ipr.Pres) {
                pchuteAux = -(10 / celula[0].acsr.ipr.ip) + celula[0].acsr.ipr.Pres;
                if (pchuteAux < 0.99 * celula[0].acsr.ipr.Pres)
                    pchuteAux = 0.99 * celula[0].acsr.ipr.Pres;
            }
            // verificando se este aumento de estimativa foca acima do valor maximo de pressao
            // de uma eventual tabela PVTSim
            if (arq.usaTabela == 1 && (arq.tabent.pmax - pchuteAux) < (*vg1dSP).localtiny)
                pchuteAux = 0.9 * arq.tabent.pmax;
            valtemp = marchaProdPerm2(pchuteAux); // nova tentativa
            if (fabs(valtemp) > 1.01e10) {
                cout << "#################PERMANENTE FALHOU EM SUA CONVERGÃŠNCIA##############################" << endl;
                if ((*vg1dSP).iterRede > 0)
                    return -1.1e10;
                else
                    return 1.1e10;
            }
            if (kontaiter == 50) {
                pchuteAux = 0.5 * pchuteAux0;
            }
            kontaiter++;
        }
        valtemp = marchaProdPerm2(pchuteAux);
        if (fabs(valtemp) > 1.01e10) {
            cout << "#################PERMANENTE FALHOU EM SUA CONVERGÃŠNCIA##############################" << endl;
            if ((*vg1dSP).iterRede > 0)
                return -1.1e10;
            else
                return 1.1e10;
        }
        if (valtemp > -0.9e10 && valtemp < 0.9e10) { // conseguiu fazer a marcha atÃƒÂ© o final
            val = valtemp;
            pchute = pchuteAux;
        }
    }
    if (kontaiter > 50) { // chegou ao limite da iteracao
        if ((*vg1dSP).chaverede == 0) {
            // neste caso, se finaliza a simulacao, nao tem um transiente
            // a ser feito a seguir e nem se estÃ¡ em uma rede
            if (arq.transiente == 0 && chute < 0 && arq.AP == 0)
                NumError("Busca de valores iniciais para calculo de zero de funcao em buscaProdPfundoPerm atingiu maximo de iteracoes");
            else {
                cout << "#################PERMANENTE FALHOU EM SUA CONVERGÃŠNCIA##############################" << endl;
                if ((*vg1dSP).iterRede > 0)
                    return -1.1e10;
                else
                    return 1.1e10;
            }
        } else {
            // se for em uma iteracao de rede, apos a primeira iteracao
            if ((*vg1dSP).iterRede > 0)
                return -1.1e10;
            // se logo apÃ³s tem uma simulacao transiente ou se esta na primeira iteracao de rede
            else
                return 1.1e10;
        }
    }
    // caso o laÃ§o anterior tenha levado a estimativa de um valor 1e10 para um valor -1e10
    // ou tenha levado para um valor de -1e10 para 1e10
    // ou seja, de um chute de pressao alto demais para finalizar a marcha
    // para um chute de pressao baixo demais para terminar a marcha ou vice versa
    while ((val < -0.9e10 || val > 0.9e10) && kontaiter <= 50) {
        pchute = 0.5 * (pchute + pchuteAux); // busca-se um valor medio
        // entre o alto demais e o baixo demais
        if ((fabs(pchute - pchuteAux) / pchute) < 0.001 && val < -0.9e10) {
            pchute = 1.05 * pchute;
            if (celula[0].acsr.tipo == 3 &&
                (celula[0].acsr.ipr.Pres - pchute) < 0.01 * celula[0].acsr.ipr.Pres) {
                pchute = -(10 / celula[0].acsr.ipr.ip) + celula[0].acsr.ipr.Pres;
                if (pchute < 0.99 * celula[0].acsr.ipr.Pres)
                    pchute = 0.99 * celula[0].acsr.ipr.Pres;
            }
            if (arq.usaTabela == 1 && (arq.tabent.pmax - pchute) < (*vg1dSP).localtiny)
                pchute = 0.9 * arq.tabent.pmax;
            pchuteAux = pchute;
        }

        val = marchaProdPerm2(pchute);
        if (fabs(val) > 1.01e10) {
            cout << "#################PERMANENTE FALHOU EM SUA CONVERGÃŠNCIA##############################" << endl;
            if ((*vg1dSP).iterRede > 0)
                return -1.1e10;
            else
                return 1.1e10;
        }
        kontaiter++;
    }
    if (kontaiter > 50) {
        if ((*vg1dSP).chaverede == 0) {
            if (arq.transiente == 0 && chute < 0 && arq.AP == 0)
                NumError("Busca de valores iniciais para calculo de zero de funcao em buscaProdPfundoPerm atingiu maximo de iteracoes");
            else {
                cout << "#################PERMANENTE FALHOU EM SUA CONVERGÃŠNCIA##############################" << endl;
                if ((*vg1dSP).iterRede > 0)
                    return -1.1e10;
                else
                    return 1.1e10;
            }
        } else {
            if ((*vg1dSP).iterRede > 0)
                return -1.1e10;
            else
                return 1.1e10;
        }
    }

    // caso tenha sido possivel obter um chute de pressao em que foi possivel finalizar a marcha
    kontaiter = 0;
    pchute2 = pchute;
    double chutelim = 0.;
    double chuteNeg = 0.;
    double chutePos = 0.;
    double atenua = 1.;
    double reduz = 1. - arq.buscaFC;
    double amplifica = 1. + arq.buscaFC;
    if (fabs(val) < 1e-3)
        return pchute;
    else {
        if (val < 0.) { // caso em que o chute de pressao foi alto
            // Vazao no choke>Vazao da mistura na tubulaÃ§Ã£o
            // calculada pela marcha, isto implica em pressao de chute alta , deve-se agora buscar
            // uma pressao de chute baixa para que val seja positivo e assim iniciar o processo
            // de calculo de zero de funcao
            chuteNeg = pchute; // armazenando o valor de chute de pressao que da o valor negativo
            // a cada nova busca em que val se aproxima de zero, mas ainda negativo
            // chuteNeg Ã© atualizado com a Ãºltima pressao de chute
            while (val < 0) {
                if (fabs(pchute2 - pchute) / pchute < (1. - reduz) / 10. && kontaiter > 50) {
                    pchute2 *= 0.5;
                }
                pchuteAux = pchute2;
                if ((*vg1dSP).chaverede == 0)
                    pchute2 *= reduz; // Diminuindo a pressao na busca de val>0
                else
                    pchute2 *= mult1; // Diminuindo a pressao na busca de val>0
                if (pchute2 <= chutelim)
                    pchute2 = 0.5 * (pchuteAux + chutelim); // chutelim inicialmente
                // e zero, mas pode acontecer de baixar demais pchute2 ao ponto de val=-1e10
                //(pressao abaixo de 0.5 no meio da marcha), neste caso, chutelim se torna este valor de
                // pchute2, pois, com isto, ja se sabe que nao se pode ir abaixo de chutelim
                if (arq.usaTabela == 1 && (arq.tabent.pmax - pchute2) < (*vg1dSP).localtiny)
                    pchute2 = 0.9 * arq.tabent.pmax;
                if (celula[0].acsr.tipo == 3 &&
                    (celula[0].acsr.ipr.Pres - pchute2) < 0.001 * celula[0].acsr.ipr.Pres) {
                    pchute2 = -(10 / celula[0].acsr.ipr.ip) + celula[0].acsr.ipr.Pres;
                    if (pchute2 < 0.999 * celula[0].acsr.ipr.Pres)
                        pchute2 = 0.999 * celula[0].acsr.ipr.Pres;
                }
                val = marchaProdPerm2(pchute2);
                if (fabs(val) > 1.01e10) {
                    cout << "#################PERMANENTE FALHOU EM SUA CONVERGÃŠNCIA##############################" << endl;
                    if ((*vg1dSP).iterRede > 0)
                        return -1.1e10;
                    else
                        return 1.1e10;
                }
                if (val < 0 && val > -0.9e10)
                    chuteNeg = pchute2; // atualizando o chuteNeg
                kontaiter++;
                if (kontaiter > 50) { // limite de iteracoes, falha na busca do segundo chute
                    // fim da simulacao ou aviso de falha
                    if ((*vg1dSP).chaverede == 0) {
                        if (arq.transiente == 0 && chute < 0 && arq.AP == 0)
                            NumError("Busca de valores iniciais para calculo de zero de funcao em buscaProdPfundoPerm2 atingiu maximo de iteracoees");
                        else {
                            cout << "#################PERMANENTE FALHOU EM SUA CONVERGENCIA##############################" << endl;
                            if ((*vg1dSP).iterRede > 0)
                                return -1.1e10;
                            else
                                return 1.1e10;
                        }
                    } else {
                        if ((*vg1dSP).iterRede > 0)
                            return -1.1e10;
                        else
                            return 1.1e10;
                    }
                }
                while (val < -0.9e10) { // a reduÃ§Ã£o de pressao foi demais e a marcha nÃ£o foi capaz
                    // de ir ate o final sem que a pressao ficasse inferior a 0.5kgf/cm2
                    // deve-se aumentar a estimativa de pressao baixa
                    chutelim = pchute2;
                    pchute2 = 0.5 * (pchute2 + pchuteAux); // valor intermediario entre a menor pressao
                    // que leva a val<0 e a pressao baixa demais
                    if (arq.usaTabela == 1 && (arq.tabent.pmax - pchute2) < (*vg1dSP).localtiny)
                        pchute2 = 0.9 * arq.tabent.pmax;
                    if (celula[0].acsr.tipo == 3 &&
                        (celula[0].acsr.ipr.Pres - pchute2) < 0.001 * celula[0].acsr.ipr.Pres) {
                        pchute2 = -(10 / celula[0].acsr.ipr.ip) + celula[0].acsr.ipr.Pres;
                        if (pchute2 < 0.999 * celula[0].acsr.ipr.Pres)
                            pchute2 = 0.999 * celula[0].acsr.ipr.Pres;
                    }
                    val = marchaProdPerm2(pchute2);
                    if (fabs(val) > 1.01e10) {
                        cout << "#################PERMANENTE FALHOU EM SUA CONVERGÃŠNCIA##############################" << endl;
                        if ((*vg1dSP).iterRede > 0)
                            return -1.1e10;
                        else
                            return 1.1e10;
                    }
                    if (val < 0 && val > -0.9e10)
                        chuteNeg = pchute2;
                    kontaiter++;
                    if (kontaiter > 50) {
                        if ((*vg1dSP).chaverede == 0) {
                            if (arq.transiente == 0 && chute < 0 && arq.AP == 0)
                                NumError(
                                    "Busca de valores iniciais para calculo de zero de funcao em buscaProdPfundoPerm2 atingiu maximo de iteracoes");
                            else {
                                cout << "#################PERMANENTE FALHOU EM SUA CONVERGENCIA##############################" << endl;
                                if ((*vg1dSP).iterRede > 0)
                                    return -1.1e10;
                                else
                                    return 1.1e10;
                            }
                        } else {
                            if ((*vg1dSP).iterRede > 0)
                                return -1.1e10;
                            else
                                return 1.1e10;
                        }
                    }
                }
            }
            chutePos = pchute2;
        } else if (val > 0.) { // caso em que Vazao no choke<Vazao da mistura na tubulaÃ§Ã£o,
            // isto implica em pressao de chute baixa , deve-se agora buscar
            // uma pressao de chute alta para que val seja negativo e assim iniciar o processo
            // de calculo de zero de funcao
            chutePos = pchute; // armazenando o valor de chute de pressao que da o valor positivo
            // a cada nova busca em que val se aproxima de zero, mas ainda positivo
            // chutePos e atualizado com a Ãºltima pressao de chute
            while (val > 0) {
                pchuteAux = pchute2;
                if ((*vg1dSP).chaverede == 0)
                    pchute2 *= amplifica; // Aumentando a pressao na busca de val>0
                else
                    pchute2 *= mult2; // Aumentando a pressao na busca de val>0
                if (arq.usaTabela == 1 && (arq.tabent.pmax - pchute2) < (*vg1dSP).localtiny)
                    pchute2 = 0.9 * arq.tabent.pmax;
                int limpres = 0;
                if (celula[0].acsr.tipo == 3 &&
                    (celula[0].acsr.ipr.Pres - pchute2) < 0.001 * celula[0].acsr.ipr.Pres) {
                    if (chute < 0) {
                        pchute2 = -(10 / celula[0].acsr.ipr.ip) + celula[0].acsr.ipr.Pres;
                        if (pchute2 < 0.999 * celula[0].acsr.ipr.Pres)
                            pchute2 = 0.999 * celula[0].acsr.ipr.Pres;
                        if (fabs(pchute2 - pchute) < 1e-15) {
                            pchute2 = -(1 / celula[0].acsr.ipr.ip) + celula[0].acsr.ipr.Pres;
                            if (pchute2 < 0.999 * celula[0].acsr.ipr.Pres)
                                pchute2 = 0.999 * celula[0].acsr.ipr.Pres;
                        }
                    } else {
                        pchute2 = pchuteAux * 1.0001;
                    }
                    limpres = 1;
                }
                val = marchaProdPerm2(pchute2);
                if (fabs(val) > 1.01e10) {
                    cout << "#################PERMANENTE FALHOU EM SUA CONVERGÃŠNCIA##############################" << endl;
                    if ((*vg1dSP).iterRede > 0)
                        return -1.1e10;
                    else
                        return 1.1e10;
                }
                if (val > 0. && limpres == 1) {
                    int iterpres = 0;
                    while (val > 0 && iterpres < 10) {
                        pchute2 *= 1.001;
                        val = marchaProdPerm2(pchute2);
                        if (fabs(val) > 1.01e10) {
                            cout << "#################PERMANENTE FALHOU EM SUA CONVERGÃŠNCIA##############################" << endl;
                            if ((*vg1dSP).iterRede > 0)
                                return -1.1e10;
                            else
                                return 1.1e10;
                        }
                        iterpres++;
                    }
                    if (iterpres >= 10) {
                        if (arq.transiente == 0 && chute < 0 && arq.AP == 0)
                            NumError(
                                "Busca de valores iniciais para calculo de zero de funcao em buscaProdPfundoPerm2 atingiu maximo de iteracoes");
                        else {
                            cout << "#################PERMANENTE FALHOU EM SUA CONVERGENCIA##############################" << endl;
                            if ((*vg1dSP).iterRede > 0)
                                return -1.1e10;
                            else
                                return 1.1e10;
                        }
                    }
                }
                if (val > 0 && val < 0.9e10)
                    chutePos = pchute2; // atualizando o chutePos
                kontaiter++;
                if (kontaiter > 50) { // limite de iteracoes, falha na busca do segundo chute
                    // fim da simulacao ou aviso de falha
                    if ((*vg1dSP).chaverede == 0) {
                        if (arq.transiente == 0 && chute < 0 && arq.AP == 0)
                            NumError(
                                "Busca de valores iniciais para calculo de zero de funcao em buscaProdPfundoPerm2 atingiu maximo de iteracoes");
                        else {
                            cout << "#################PERMANENTE FALHOU EM SUA CONVERGENCIA##############################" << endl;
                            if ((*vg1dSP).iterRede > 0)
                                return -1.1e10;
                            else
                                return 1.1e10;
                        }
                    } else {
                        if ((*vg1dSP).iterRede > 0)
                            return -1.1e10;
                        else
                            return 1.1e10;
                    }
                }
                while (val > 0.9e10) { // o incremento de pressao foi demais e a marcha nao foi capaz
                    // de ir ate o final sem que a pressao ficasse maior do que a pressao estatica
                    // em um eventual IPR no meio da marcha ou maior que o limitre maximo de pressao
                    // da tabela PVTSim, quando for este o caso
                    // deve-se diminuir a estimativa de pressao baixa
                    chutelim = pchute2;
                    pchute2 = 0.5 * (pchute2 + pchuteAux); // valor intermediario entre a maior pressao
                    // que leva a val>0 e a pressao alta demais
                    if (arq.usaTabela == 1 && (arq.tabent.pmax - pchute2) < (*vg1dSP).localtiny)
                        pchute2 = 0.9 * arq.tabent.pmax;
                    if (celula[0].acsr.tipo == 3 &&
                        (celula[0].acsr.ipr.Pres - pchute2) < 0.001 * celula[0].acsr.ipr.Pres) {
                        pchute2 = -(10 / celula[0].acsr.ipr.ip) + celula[0].acsr.ipr.Pres;
                        if (pchute2 < 0.999 * celula[0].acsr.ipr.Pres)
                            pchute2 = 0.999 * celula[0].acsr.ipr.Pres;
                    }
                    val = marchaProdPerm2(pchute2);
                    if (fabs(val) > 1.01e10) {
                        cout << "#################PERMANENTE FALHOU EM SUA CONVERGÃŠNCIA##############################" << endl;
                        if ((*vg1dSP).iterRede > 0)
                            return -1.1e10;
                        else
                            return 1.1e10;
                    }
                    if (val > 0 && val < 0.9e10)
                        chutePos = pchute2;
                    kontaiter++;

                    if (kontaiter > 50) {
                        if ((*vg1dSP).chaverede == 0) {
                            if (arq.transiente == 0 && chute < 0 && arq.AP == 0)
                                NumError(
                                    "Busca de valores iniciais para calculo de zero de funcao em buscaProdPfundoPerm2 atingiu maximo de iteracoes");
                            else {
                                cout << "#################PERMANENTE FALHOU EM SUA CONVERGENCIA##############################" << endl;
                                if ((*vg1dSP).iterRede > 0)
                                    return -1.1e10;
                                else
                                    return 1.1e10;
                            }
                        } else {
                            if ((*vg1dSP).iterRede > 0)
                                return -1.1e10;
                            else
                                return 1.1e10;
                        }
                    }
                }
            }
            chuteNeg = pchute2;
        }
        return zriddr(chuteNeg, chutePos, 1, 1); // com as duas estimativas de pressao
        // em posicoes de sinal contrario da curva, inicia-se o processo de calculo de zero
        // de funcao
    }
}

double SProd::buscaProdPfundoPerm3(double pentrada) {
    revPerm = 0;
    monitConvPerm = 1000.;
    double alfini;
    double betini;

    // estimativa da fracao de vazio na primeira celula do sistema
    // fonte de massa no inicio da tubulacao
    // da mesma maneira que no caso de fonte de liquido, fracao de vazio= sem escorregamento
    celula[0].temp = celula[0].acsr.injm.temp;
    if (arq.flashCompleto == 2) {
        if (arq.tabelaDinamica == 0)
            celula[0].flui.atualizaPropComp(pentrada, celula[0].temp);
        celula[0].acsr.injm.FluidoPro.atualizaPropComp(pentrada, celula[0].temp);
    }
    celula[0].acsr.injm.condTermo = 0;
    celula[0].pres = pentrada;
    renovaFonte(0);
    double qgas = celula[0].acsr.injm.MassG /
                  celula[0].acsr.injm.FluidoPro.MasEspGas(pentrada, celula[0].temp);
    double qliq = celula[0].acsr.injm.MassP /
                      celula[0].acsr.injm.FluidoPro.MasEspLiq(pentrada, celula[0].temp) +
                  celula[0].acsr.injm.MassC /
                      celula[0].acsr.injm.fluidocol.MasEspFlu(pentrada, celula[0].temp);
    celula[0].acsr.injm.FluidoPro.MasEspLiq(pentrada, celula[0].temp);
    double qcomp = celula[0].acsr.injm.MassC /
                   celula[0].acsr.injm.fluidocol.MasEspFlu(pentrada, celula[0].temp);
    alfini = qgas / (qliq + qgas);
    if ((fabs(qcomp) + fabs(qliq)) > 1e-15)
        betini = fabs(qcomp) / (fabs(qcomp) + fabs(qliq));
    else
        betini = 0.;

    // esta marcha e feita para quando se tem alguma fonte no inicio da tubulacao,
    // portanto, admite-se que o duto esta fechado e coloca-se uma fonte no centro da
    // primeira celula. As vazoes na fronteira esquerda da celula sÃ£o portanto = 0
    celula[0].tempL = celula[0].temp;
    celula[1].tempL = celula[0].temp;
    celula[0].tempini = celula[0].temp;

    celula[0].ML = 0.;
    celula[0].MC = 0.;
    celula[1].ML = 0.;
    celula[0].MliqiniL = 0.;
    celula[0].Mliqini = 0.;
    celula[1].MliqiniL = 0.;
    celula[0].MComp = 0.;
    celula[0].QLL = 0.;
    celula[0].QL = 0;
    celula[1].QLL = 0.;
    celula[0].QG = 0.;
    double masfim = 1.;
    double masfim0 = -10;
    double presteste = 1.;
    double presteste0 = -10;
    iterperm = 0;

    int limIter = 200; // limite de iteracoes quando a opcao de aceleracao da convergencia esta desligado. desaconselhavel
    // desligar esta opcao, os ganhos sao pouco e a convergencia se torna instavel, principalmente
    // quando o tramo faz perte de um sistema de redes
    if (arq.AceleraConvergPerm == 1) { // opcao aceleracao de convergencia ligada
        limIter = 2;                   // em geral faz-se apenas duas iteracoes de marcha para um determinado chute
        if (arq.lingas == 1 && arq.gasinj.tipoCC == 0)
            limIter = 3; // no caso de se ter
        // uma condicao de contorno na injecao de gas = pressao, observou-se que o acoplamento dinamico
        // entre a linha de gas e de producao e mais difoicil, para se conseguir um sistema
        // melhor acoplado, deve-se fazer uma marcha iterativa a mais
    }
    // arq.CriterioConvergPerm Ã© um criterio de convergencia da marcha, so faz sentido
    // quando a aceleracao de convergencia esta desligada. Observe que esta convergencia nÃ£o
    // e de fato a conevregencia do problema, e apenas um repeticao de marcha para um determinado
    // chute de pressao ou de vazao no inicio da tubulacao. O que a convergencia busca de fato e
    // determinar qual a pressao ou vazao de fundo que satisfaz as condicoes de contorno no fim
    // da tubulacao, esta busca e feita nos metodos de busca.
    while ((fabs(masfim - masfim0) / fabs(masfim) > arq.CriterioConvergPerm ||
            fabs(presteste - presteste0) / fabs(presteste) > arq.CriterioConvergPerm) &&
           iterperm < limIter) {

        masfim0 = masfim;
        presteste0 = presteste;
        if (iterperm == 0 && arq.lingas > 0 && arq.nvalvgas > 0 && verificaAcop == 1)
            IniciaconectaColunaPerm(); // antes de iniciar a primeira iteracao de marcha,
        // faz-se uma estimativa inicial de como se da o acopamento termico entre a coluna e o anular,
        // caso se tenha linha de gas
        else if (arq.lingas > 0 && arq.nvalvgas > 0 && verificaAcop == 1)
            conectaColunaPerm(); // acoplamento termico feito com valores de pressao e temperatura
        // obtidas na primeira iteracao de marcha
        int i;
        int corrigechute = 1;
        while (corrigechute == 1) { // opcao antiga, ja nao tem mais efeito
            // efetivamente, este while sempre so e feito uma vez, quando a marcha consegue ir ate
            // a ultima celula sem problemas, caso ocorra algum problema, a marcha e finalizada e
            // sai do metodo retornando ou 1e10 ou -1e10

            // inicializando as pressoes e fracoes volumetricas das celulas iniciais, centro de celula
            // e fronteira de celula
            celula[0].presauxL = pentrada;
            celula[0].presLini = pentrada;
            celula[0].presL = pentrada;
            celula[0].pres = pentrada;
            celula[1].presL = pentrada;
            celula[0].presini = pentrada;
            celula[1].presLini = pentrada;
            celula[0].presaux = pentrada;
            celula[1].presauxL = pentrada;

            celula[0].alf = alfini;
            celula[0].alfini = alfini;
            celula[0].bet = betini;
            celula[0].betini = betini;
            celula[1].alfL = celula[0].alf;
            celula[1].alfLini = celula[0].alf;
            celula[0].alfPigD = celula[0].alf;
            celula[0].alfPigDini = celula[0].alf;
            celula[0].alfPigE = celula[0].alf;
            celula[0].alfPigEini = celula[0].alf;
            celula[1].betL = celula[0].bet;
            celula[1].betLini = celula[0].bet;
            celula[0].betPigD = celula[0].bet;
            celula[0].betPigDini = celula[0].bet;
            celula[0].betPigE = celula[0].bet;
            celula[0].betPigEini = celula[0].bet;
            celula[0].betI = celula[0].bet;
            celula[1].betLI = celula[0].bet;

            // verifica se ja existe algum problema no inicio da marcha
            if (celula[0].pres <= 0.1 ||
                (arq.usaTabela == 1 && (arq.tabent.pmin - celula[0].pres) > (*vg1dSP).localtiny))
                return -1e10;
            else if ((celula[0].acsr.tipo == 3 &&
                      (celula[0].acsr.ipr.Pres - celula[0].pres) < (*vg1dSP).localtiny))
                return 1e10;
            else if ((celula[0].acsr.tipo == 15 &&
                      (celula[0].acsr.radialPoro.pRes[0] - celula[0].pres) < (*vg1dSP).localtiny))
                return 1e10;
            else if ((celula[0].acsr.tipo == 16 &&
                      (celula[0].acsr.poroso2D.dados.pRes - celula[0].pres) < (*vg1dSP).localtiny))
                return 1e10;
            // IniciaVazValvGasPerm e um metodo que faz uma estimativa da vazao na valvula de GL
            // quando ainda nao foi feita a marcha na linha de gas. Neste caso, ele recebe o
            // indice da celula de producao e verifica se nesta celula existe uma VGL, se existir,
            // caso a condicao na linha de gas seja vazao injetada, divide a vazao injetada pelo numero de
            // valvulas e indica este valor para a VGL relacionada a celula de producao
            // caso a condicao seja pressao de injecao, faz-se uma estimativa da pressao na linha de gas
            // na posicao da VGL por hidrotatica e com isto se calcula a vazao de injecao da VGL
            if (arq.lingas > 0 && arq.nvalvgas > 0 && iterperm == 0)
                IniciaVazValvGasPerm(0);
            i = 1;
            // inicio da marcha propriamente dita
            while (i <= ncel && celula[i - 1].pres >= 0.1 && fabs(pentrada - celula[0].pres) < (*vg1dSP).localtiny) {

                RenovaPresPermMon(i, 0); // avanco da marcha para obter a pressao na fronteira esquerda
                // da celula i
                // teste para ver se ocorreu algum problema:
                if (arq.usaTabela == 1 && (arq.tabent.pmax - celula[i].presaux) < (*vg1dSP).localtiny)
                    return 1e10;
                if (celula[i].presaux <= 0.1 ||
                    (arq.usaTabela == 1 && (arq.tabent.pmin - celula[i].presaux) > (*vg1dSP).localtiny)) {
                    return -1e10;
                }
                atualizaPeriPmonProd(i); // atualizacao da pressao da fronteira esquerda,
                // caso exista alguma BCS ou incremento de pressao
                if (arq.flashCompleto != 2)
                    RenovaMassPerm(i); // verifica se existe alguma fonte na celula anterior, com isto, atualiza
                // as vazoes massica na fronteira a esquerda, alÃ©m das propriedades dos fluidos,
                // densidade do gas, RGO, API, BSW, beta
                else
                    RenovaMassPermComp(i);
                RenovaTempPerm(i, 0); // faz o avanco da temperatura, da celula i-1 para a celula i
                // verifica se teve algum problema nos limites de temperatura
                // caso se esteja trabalhando com tabela PVTSim
                if (isnan(celula[i].temp))
                    NumError("Temperatrura na linha de producao com valor NaN");
                if (arq.usaTabela == 1 && (celula[i].temp - arq.tabent.tmin) < (*vg1dSP).localtiny)
                    celula[i].temp = arq.tabent.tmin;
                atualizaPeriTempProd(i); // mera atualizacao de atributos de temperatura a esquerda e a direita
                RenovaPresPermJus(i, 0); // evolui a pressao  fronteira a esquerda da celula i para o
                // seu centro de celula
                // verifica se ocorreu algum problema nesta evolucao de de pressao no centro da
                // celula
                if (arq.usaTabela == 1 && (arq.tabent.pmax - celula[i].pres) < (*vg1dSP).localtiny) {
                    return 1e10;
                }
                if (celula[i].pres <= 0.1 ||
                    (arq.usaTabela == 1 && (arq.tabent.pmin - celula[i].pres) > (*vg1dSP).localtiny)) {
                    return -1e10;
                }
                atualizaPeriPjusProd(i); // mera atualizacao de atributos que guardam valores de pressao
                // das celulas a esquerda e a direita
                for (int j = 0; j < arq.nvalvgas; j++) { // reavaliacao da vazao da valvula de gas lift, quando
                    // a celula tem uma.
                    // P.S. parece uma acao desnecessÃ¡ria e talvez atÃ© um complicador
                    // densecessario, em vavliacao
                    if (posicVGLP[j] == i) {
                        int k = posicVGLG[j];
                        calcVazGasPerm(k);
                    }
                }
                if (arq.tipoFluido == 0)
                    RenovaTransMassPerm(i - 1);
                else
                    RenovaTransMassPermGas(i - 1); // caso seja uma tabela PVTSim, calcula-se a
                // taxa de transferÃªncia de massa entre as fases para o uso no calculo de
                // calor latente da equacao de energia
                if (arq.ordperm > 1) { // correcao de segunda ordem
                    double D0presaux = celula[i].presaux - celula[i - 1].pres;
                    double D0pres = celula[i].pres - celula[i].presaux;
                    double D0temp = celula[i].temp - celula[i - 1].temp;
                    RenovaPresPermMon(i, 1);
                    atualizaPeriPmonProd(i);
                    RenovaMassPerm(i);
                    RenovaTempPerm(i, 1);
                    RenovaPresPermJus(i, 1);
                    celula[i].pres = 0.5 * (celula[i].presaux + D0pres + celula[i].pres);
                    celula[i].presaux = 0.5 * (celula[i - 1].pres + D0presaux + celula[i].presaux);
                    celula[i].temp = 0.5 * (celula[i - 1].temp + D0temp + celula[i].temp);
                    atualizaPeriPjusProd(i);
                    atualizaPeriPmonProd(i);
                    atualizaPeriTempProd(i);
                    RenovaMassPerm(i);
                    if (arq.tipoFluido == 0)
                        RenovaTransMassPerm(i - 1);
                    else
                        RenovaTransMassPermGas(i - 1);
                }

                // apÃ³s se atingir a pressao no centro da celula i, primeira iteracao de marcha
                // verifica-se se existe uma VGL em i e faz-se uma estimativa inicial da Vazao de
                // GL (caso exista linha de gas). Observar que isto sÃ³ Ã© feito para a iteracao zero.
                if (arq.lingas > 0 && arq.nvalvgas > 0 && iterperm == 0)
                    IniciaVazValvGasPerm(i);
                i++;

                // teste para verificar se a pressao do centro de celula ficou acima
                // da pressao estatica de uma eventual IPR
                if (celula[i - 1].pres <= 0.1 ||
                    (arq.usaTabela == 1 && (arq.tabent.pmin - celula[i - 1].pres) > (*vg1dSP).localtiny)) {
                    return -1e10;
                } else if ((celula[i - 1].acsr.tipo == 3 &&
                            ((celula[i - 1].acsr.ipr.Pres - celula[i - 1].pres) < (*vg1dSP).localtiny) && i == 1)) {
                    return 1e10;
                } else if ((celula[i - 1].acsr.tipo == 15 &&
                            ((celula[i - 1].acsr.radialPoro.pRes[0] - celula[i - 1].pres) < (*vg1dSP).localtiny) && i == 1)) {
                    return 1e10;
                } else if ((celula[i - 1].acsr.tipo == 16 &&
                            ((celula[i - 1].acsr.poroso2D.dados.pRes - celula[i - 1].pres) < (*vg1dSP).localtiny) && i == 1)) {
                    return 1e10;
                }
            }
            if (i == ncel + 1)
                corrigechute = 0; // fim da marcha
        }
        // apÃ³s o fim da marcha da linha de produÃ§Ã£o, Ã© feita a marcha da linha de gas
        // caso exista
        if (pentrada > 0 && arq.lingas > 0 && arq.nvalvgas > 0) {
            if (celulaG[0].tipoCC == 0) {            // marcha para o caso, pressao de injecao
                if (arq.chokes.abertura[0] >= 0.2) { // choke de injecao inativo
                    for (int iter = 0; iter < 1; iter++) {
                        marchaGasPerm1();
                    }
                } else
                    buscaGasPresPerm3(); // choke de injecao ativo
            } else
                buscaGasPresPerm2(); // marcha na linha de gas para o caso de vazao de injecao
        }

        if (arq.acopColAnulPermForte > 0 && arq.lingas > 0) {
            atualizaProp();
            atualizaVelTermPerm();
            calcDTPseudoTrans();
            conectaColuna();
            for (int kontaPseudo = 0; kontaPseudo < arq.acopColAnulPermForte; kontaPseudo++) {
                for (int i = 0; i <= ncelGas; i++)
                    celulaG[i].tempini = celulaG[i].temp;
                for (int i = 1; i <= ncelGas; i++) {
                    calctempGas(i, celulaG[i - 1].tempini, 1);
                }
                celula[0].tempini = celula[0].temp;
                celula[1].tempLini = celula[1].tempL;
                celula[1].tempL = celula[0].temp;
                for (int i = 1; i <= ncel; i++) {
                    celula[i].tempini = celula[i].temp;
                }
                for (int i = 1; i <= ncel; i++) {
                    calctemp(i, celula[i].tempini, 1);
                }
                atualizaProp();
                calcDTPseudoTrans();
                conectaColuna();
            }
        }

        masfim = celula[ncel - 1].MC; // guarda valor de vazao para se calcular o erro, quando a
        // opcao de acelerador de convergencia esta desligado
        presteste = celula[ncel].pres; // guarda valor de pressao para se calcular o erro, quando a
        // opcao de acelerador de convergencia esta desligado
        iterperm++; // atualiza a ieteracao da marcha
        if (iterperm > 200 && arq.AP == 0)
            NumError("ConvergÃƒÂªncia em marchaProdPerm1 atingiu maximo de iteracoes");
        else if (iterperm > 200)
            return 1.1e10;
    }

    double corrigePresF = 0.;
    if (((*vg1dSP).chaverede == 0 || noextremo == 1 || (*vg1dSP).chaveRedeParalela == 1) && arq.corrigeContSep == 1)
        corrigePresF = RenovaPresPermNcel();

    pGSup = (celula[ncel].pres + corrigePresF);

    return celula[ncel].pres; // caso a marcha tenha conseguido ir atÃ© a Ãºltima celula,
    // retorna a pressao da ultima celula calculada pela marcha
}

double SProd::marchaProdPresPres1(double mchute) {

    int corrigechute = 1;
    double alfini = 0.;
    double betini = 0.;

    if (celula[0].acsr.tipo == 1) {
        celula[0].temp = celula[0].acsr.injg.temp;
        if (arq.flashCompleto == 2) {
            if (arq.tabelaDinamica == 0)
                celula[0].flui.atualizaPropComp(celula[0].pres, celula[0].temp);
            celula[0].acsr.injg.FluidoPro.atualizaPropComp(celula[0].pres, celula[0].temp, -1, NULL, NULL, celula[0].acsr.injg.seco);
        }
        celula[0].acsr.injg.QGas = mchute;
    } else if (celula[0].acsr.tipo == 2) {
        celula[0].temp = celula[0].acsr.injl.temp;
        if (arq.flashCompleto == 2) {
            if (arq.tabelaDinamica == 0)
                celula[0].flui.atualizaPropComp(celula[0].pres, celula[0].temp);
            celula[0].acsr.injl.FluidoPro.atualizaPropComp(celula[0].pres, celula[0].temp);
        }
        celula[0].acsr.injl.QLiq = mchute;
    }

    if (celula[0].acsr.tipo == 1) {
        if (celula[0].acsr.injg.seco == 1) {
            alfini = 1.;
            betini = 0.;
        } else {
            double masgas = celula[0].acsr.injg.VMas(celula[0].pres, celula[0].temp);
            double tit;
            if (arq.flashCompleto != 2)
                tit = celula[0].acsr.injg.FluidoPro.FracMassHidra(1., 20.);
            else
                tit = celula[0].acsr.injg.FluidoPro.dStockTankVaporMassFraction;
            double masT = masgas / tit;
            tit = celula[0].acsr.injg.FluidoPro.FracMassHidra(celula[0].pres, celula[0].temp);
            double qgas = masT * tit /
                          celula[0].acsr.injg.FluidoPro.MasEspGas(celula[0].pres, celula[0].temp);
            double qliq = masT * (1. - tit) /
                          celula[0].acsr.injg.FluidoPro.MasEspLiq(celula[0].pres, celula[0].temp);
            double qcomp = celula[0].acsr.injg.razCompGas *
                           celula[0].acsr.injg.QGas * celula[0].acsr.injg.fluidocol.MasEspFlu(1., 20.) /
                           celula[0].acsr.injg.fluidocol.MasEspFlu(celula[0].pres, celula[0].temp);
            qcomp /= 86400.;
            alfini = qgas / (qliq + qcomp + qgas);
            if ((fabs(qcomp) + fabs(qliq)) > 1e-15)
                betini = fabs(qcomp) / (fabs(qcomp) + fabs(qliq));
            else
                betini = 0.;
        }
    } else if (celula[0].acsr.tipo == 2) {
        double qgas = celula[0].acsr.injl.QLiq * (1 - celula[0].acsr.injl.bet) *
                      (1. - celula[0].acsr.injl.FluidoPro.BSW) *
                      (celula[0].acsr.injl.FluidoPro.RGO -
                       celula[0].acsr.injl.FluidoPro.rDgD * celula[0].acsr.injl.FluidoPro.RS(celula[0].pres, celula[0].temp) * 6.29 / 35.31467) *
                      celula[0].acsr.injl.FluidoPro.Deng * 1.225 / celula[0].acsr.injl.FluidoPro.MasEspGas(celula[0].pres, celula[0].temp);
        double qliq = celula[0].acsr.injl.QLiq * (1 - celula[0].acsr.injl.bet) *
                          (1. - celula[0].acsr.injl.FluidoPro.BSW) * celula[0].acsr.injl.FluidoPro.BOFunc(celula[0].pres, celula[0].temp) +
                      celula[0].acsr.injl.QLiq * (1 - celula[0].acsr.injl.bet) *
                          celula[0].acsr.injl.FluidoPro.BSW * celula[0].acsr.injl.FluidoPro.BAFunc(celula[0].pres, celula[0].temp) +
                      celula[0].acsr.injl.QLiq * celula[0].acsr.injl.bet;
        alfini = qgas / (qliq + qgas);
        betini = celula[0].acsr.injl.bet;
    }

    celula[0].tempL = celula[0].temp;
    celula[1].tempL = celula[0].temp;
    celula[0].tempini = celula[0].temp;

    celula[0].ML = 0.;
    celula[0].MC = 0.;
    celula[1].ML = 0.;
    celula[0].MliqiniL = 0.;
    celula[0].Mliqini = 0.;
    celula[1].MliqiniL = 0.;
    celula[0].MComp = 0.;
    celula[0].QLL = 0.;
    celula[0].QL = 0;
    celula[1].QLL = 0.;
    celula[0].QG = 0.;

    int i;

    celula[0].presauxL = celula[0].pres;
    celula[0].presLini = celula[0].pres;
    celula[0].presL = celula[0].pres;
    celula[1].presL = celula[0].pres;
    celula[0].presini = celula[0].pres;
    celula[1].presLini = celula[0].pres;
    celula[0].presaux = celula[0].pres;
    celula[1].presauxL = celula[0].pres;

    celula[0].alf = alfini;
    celula[0].alfini = alfini;
    celula[0].bet = betini;
    celula[0].betini = betini;
    celula[1].alfL = celula[0].alf;
    celula[1].alfLini = celula[0].alf;
    celula[0].alfPigD = celula[0].alf;
    celula[0].alfPigDini = celula[0].alf;
    celula[0].alfPigE = celula[0].alf;
    celula[0].alfPigEini = celula[0].alf;
    celula[1].betL = celula[0].bet;
    celula[1].betLini = celula[0].bet;
    celula[0].betPigD = celula[0].bet;
    celula[0].betPigDini = celula[0].bet;
    celula[0].betPigE = celula[0].bet;
    celula[0].betPigEini = celula[0].bet;
    celula[0].betI = celula[0].bet;
    celula[1].betLI = celula[0].bet;

    iterperm = 0;
    while (iterperm < 3) {
        i = 1;
        while (i <= ncel && celula[i - 1].pres >= 1.) {

            RenovaPresPermMon(i, 0);
            atualizaPeriPmonProd(i);
            if (arq.flashCompleto != 2)
                RenovaMassPerm(i);
            else
                RenovaMassPermComp(i);
            RenovaTempPerm(i, 0);
            if (i > 1160) {
                int para;
                para = 0;
            }
            if (arq.usaTabela == 1 && (celula[i].temp - arq.tabent.tmin) < (*vg1dSP).localtiny)
                celula[i].temp = arq.tabent.tmin;
            atualizaPeriTempProd(i);
            RenovaPresPermJus(i, 0);
            atualizaPeriPjusProd(i);
            if (arq.tipoFluido == 0)
                RenovaTransMassPerm(i - 1);
            else
                RenovaTransMassPermGas(i - 1);
            if (arq.ordperm > 1) {
                double D0presaux = celula[i].presaux - celula[i - 1].pres;
                double D0pres = celula[i].pres - celula[i].presaux;
                double D0temp = celula[i].temp - celula[i - 1].temp;
                RenovaPresPermMon(i, 1);
                atualizaPeriPmonProd(i);
                RenovaMassPerm(i);
                RenovaTempPerm(i, 1);
                if (isnan(celula[i].temp))
                    NumError("Temperatrura na linha de producao com valor NaN");
                RenovaPresPermJus(i, 1);
                celula[i].pres = 0.5 * (celula[i].presaux + D0pres + celula[i].pres);
                celula[i].presaux = 0.5 * (celula[i - 1].pres + D0presaux + celula[i].presaux);
                celula[i].temp = 0.5 * (celula[i - 1].temp + D0temp + celula[i].temp);
                atualizaPeriPjusProd(i);
                atualizaPeriPmonProd(i);
                atualizaPeriTempProd(i);
                RenovaMassPerm(i);
                if (arq.tipoFluido == 0)
                    RenovaTransMassPerm(i - 1);
                else
                    RenovaTransMassPermGas(i - 1);
            }
            i++;
            if (celula[i - 1].pres <= 1)
                return -1e10;
        }

        iterperm++;
    }

    double corrigePresF = 0.;
    if ((*vg1dSP).chaverede == 0 || noextremo == 1 || (*vg1dSP).chaveRedeParalela == 1)
        corrigePresF = RenovaPresPermNcel();

    monitConvPermBase = pGSup;
    return celula[ncel].pres + corrigePresF - pGSup;
}

double SProd::marchaProdPresPres1Rev(double mchute) {

    double alfini = 0.;
    double betini = 0.;
    trocaTermicaLenta = 0.05;

    if (celula[0].acsr.tipo == 1) {
        celula[0].temp = celula[0].acsr.injg.temp;
        if (arq.flashCompleto == 2) {
            if (arq.tabelaDinamica == 0)
                celula[0].flui.atualizaPropComp(celula[0].pres, celula[0].temp);
            celula[0].acsr.injg.FluidoPro.atualizaPropComp(celula[0].pres, celula[0].temp, -1, NULL, NULL, celula[0].acsr.injg.seco);
        }
        celula[0].acsr.injg.QGas = mchute;
    } else if (celula[0].acsr.tipo == 2) {
        celula[0].temp = celula[0].acsr.injl.temp;
        if (arq.flashCompleto == 2) {
            if (arq.tabelaDinamica == 0)
                celula[0].flui.atualizaPropComp(celula[0].pres, celula[0].temp);
            celula[0].acsr.injl.FluidoPro.atualizaPropComp(celula[0].pres, celula[0].temp);
        }
        celula[0].acsr.injl.QLiq = mchute;
    }

    if (celula[0].acsr.tipo == 1) {
        if (celula[0].acsr.injg.seco == 1) {
            alfini = 1.;
            betini = 0.;
        } else {
            double masgas = celula[0].acsr.injg.VMas(celula[0].pres, celula[0].temp);
            double tit;
            if (arq.flashCompleto != 2)
                tit = celula[0].acsr.injg.FluidoPro.FracMassHidra(1., 20.);
            else
                tit = celula[0].acsr.injg.FluidoPro.dStockTankVaporMassFraction;
            double masT = masgas / tit;
            tit = celula[0].acsr.injg.FluidoPro.FracMassHidra(celula[0].pres, celula[0].temp);
            double qgas = masT * tit /
                          celula[0].acsr.injg.FluidoPro.MasEspGas(celula[0].pres, celula[0].temp);
            double qliq = masT * (1. - tit) /
                          celula[0].acsr.injg.FluidoPro.MasEspLiq(celula[0].pres, celula[0].temp);
            double qcomp = celula[0].acsr.injg.razCompGas *
                           celula[0].acsr.injg.QGas * celula[0].acsr.injg.fluidocol.MasEspFlu(1., 20.) /
                           celula[0].acsr.injg.fluidocol.MasEspFlu(celula[0].pres, celula[0].temp);
            qcomp /= 86400.;
            alfini = qgas / (qliq + qcomp + qgas);
            if ((fabs(qcomp) + fabs(qliq)) > 1e-15)
                betini = fabs(qcomp) / (fabs(qcomp) + fabs(qliq));
            else
                betini = 0.;
        }
    } else if (celula[0].acsr.tipo == 2) {
        double qgas = celula[0].acsr.injl.QLiq * (1 - celula[0].acsr.injl.bet) *
                      (1. - celula[0].acsr.injl.FluidoPro.BSW) *
                      (celula[0].acsr.injl.FluidoPro.RGO -
                       celula[0].acsr.injl.FluidoPro.rDgD * celula[0].acsr.injl.FluidoPro.RS(celula[0].pres, celula[0].temp) * 6.29 / 35.31467) *
                      celula[0].acsr.injl.FluidoPro.Deng * 1.225 / celula[0].acsr.injl.FluidoPro.MasEspGas(celula[0].pres, celula[0].temp);
        double qliq = celula[0].acsr.injl.QLiq * (1 - celula[0].acsr.injl.bet) *
                          (1. - celula[0].acsr.injl.FluidoPro.BSW) * celula[0].acsr.injl.FluidoPro.BOFunc(celula[0].pres, celula[0].temp) +
                      celula[0].acsr.injl.QLiq * (1 - celula[0].acsr.injl.bet) *
                          celula[0].acsr.injl.FluidoPro.BSW * celula[0].acsr.injl.FluidoPro.BAFunc(celula[0].pres, celula[0].temp) +
                      celula[0].acsr.injl.QLiq * celula[0].acsr.injl.bet;
        alfini = qgas / (qliq + qgas);
        betini = celula[0].acsr.injl.bet;
    }

    celula[0].tempL = celula[0].temp;
    celula[1].tempL = celula[0].temp;
    celula[0].tempini = celula[0].temp;

    celula[0].ML = 0.;
    celula[0].MC = 0.;
    celula[1].ML = 0.;
    celula[0].MliqiniL = 0.;
    celula[0].Mliqini = 0.;
    celula[1].MliqiniL = 0.;
    celula[0].MComp = 0.;
    celula[0].QLL = 0.;
    celula[0].QL = 0;
    celula[1].QLL = 0.;
    celula[0].QG = 0.;

    int i;

    celula[0].presauxL = celula[0].pres;
    celula[0].presLini = celula[0].pres;
    celula[0].presL = celula[0].pres;
    celula[1].presL = celula[0].pres;
    celula[0].presini = celula[0].pres;
    celula[1].presLini = celula[0].pres;
    celula[0].presaux = celula[0].pres;
    celula[1].presauxL = celula[0].pres;

    celula[0].alf = alfini;
    celula[0].alfini = alfini;
    celula[0].bet = betini;
    celula[0].betini = betini;
    celula[1].alfL = celula[0].alf;
    celula[1].alfLini = celula[0].alf;
    celula[0].alfPigD = celula[0].alf;
    celula[0].alfPigDini = celula[0].alf;
    celula[0].alfPigE = celula[0].alf;
    celula[0].alfPigEini = celula[0].alf;
    celula[1].betL = celula[0].bet;
    celula[1].betLini = celula[0].bet;
    celula[0].betPigD = celula[0].bet;
    celula[0].betPigDini = celula[0].bet;
    celula[0].betPigE = celula[0].bet;
    celula[0].betPigEini = celula[0].bet;
    celula[0].betI = celula[0].bet;
    celula[1].betLI = celula[0].bet;

    iterperm = 0;
    double tempteste = celula[0].temp;
    double tempteste0 = -1000;
    while (iterperm < 3 || fabs(tempteste - tempteste0) / ((tempteste) + 273) > 0.001) {
        i = 1;
        tempteste0 = tempteste;
        while (i <= ncel && celula[i - 1].pres >= 1.) {

            RenovaPresPermMon(i, 0);
            atualizaPeriPmonProd(i);
            if (arq.flashCompleto != 2)
                RenovaMassPerm(i);
            else
                RenovaMassPermComp(i);
            if (isnan(celula[i].temp))
                NumError("Temperatrura na linha de producao com valor NaN");
            if (arq.usaTabela == 1 && (celula[i].temp - arq.tabent.tmin) < (*vg1dSP).localtiny)
                celula[i].temp = arq.tabent.tmin;
            atualizaPeriTempProd(i);
            RenovaPresPermJus(i, 0);
            atualizaPeriPjusProd(i);
            if (arq.tipoFluido == 0)
                RenovaTransMassPerm(i - 1);
            else
                RenovaTransMassPermGas(i - 1);
            if (arq.ordperm > 1) {
                double D0presaux = celula[i].presaux - celula[i - 1].pres;
                double D0pres = celula[i].pres - celula[i].presaux;
                double D0temp = celula[i].temp - celula[i - 1].temp;
                RenovaPresPermMon(i, 1);
                atualizaPeriPmonProd(i);
                RenovaMassPerm(i);
                RenovaPresPermJus(i, 1);
                celula[i].pres = 0.5 * (celula[i].presaux + D0pres + celula[i].pres);
                celula[i].presaux = 0.5 * (celula[i - 1].pres + D0presaux + celula[i].presaux);
                celula[i].temp = 0.5 * (celula[i - 1].temp + D0temp + celula[i].temp);
                atualizaPeriPjusProd(i);
                atualizaPeriPmonProd(i);
                atualizaPeriTempProd(i);
                RenovaMassPerm(i);
                if (arq.tipoFluido == 0)
                    RenovaTransMassPerm(i - 1);
                else
                    RenovaTransMassPermGas(i - 1);
            }
            i++;
            if (celula[i - 1].pres <= 1)
                return -1e10;
        }

        iterperm++;
        if (iterperm > 200 && arq.AP == 0)
            NumError("ConvergÃƒÂªncia em marchaProdPerm1 atingiu maximo de iteracoes");
        else if (iterperm > 200)
            return 1.1e10;
        if (arq.tipoFluido != 10000) {
            celula[ncel].temp = tempRev;
            if (iterperm < 100) {
                int lento = 0;
                trocaTermicaLenta = 0;
                for (int ktemp = ncel - 1; ktemp >= 0; ktemp--) {

                    double area = celula[ktemp].duto.area;
                    double ugsmed;
                    ugsmed = fabs(celula[ktemp].QG) / area; // velocidade superficial de gas
                    double ulsmed;
                    ulsmed = fabs(celula[ktemp].QL) / area; // velocidade superficial de liquido
                    if (fabs(ugsmed + ulsmed) <= 0.1)
                        lento += 1;
                }
                if (iterperm > 10 && trocaTermicaLenta < 0.01) {
                    trocaTermicaLenta -= 0.01;
                    iterperm = 0;
                }
                for (int ktemp = ncel - 1; ktemp >= 0; ktemp--) {
                    RenovaTempPermRev(ktemp, 0);
                    if (arq.usaTabela == 1 && (celula[ktemp].temp - arq.tabent.tmin) < (*vg1dSP).localtiny)
                        celula[ktemp].temp = arq.tabent.tmin;
                    atualizaPeriTempProd(ktemp); // mera atualizacao de atributos de temperatura a esquerda e a direita
                }
            }
            tempteste = celula[0].temp;
        } else {
            atualizaProp();
            atualizaVelTermPerm();
            calcDTPseudoTrans();
            for (int kontaPseudo = 0; kontaPseudo < 20; kontaPseudo++) {
                celula[0].tempini = celula[0].temp;
                celula[1].tempLini = celula[1].tempL;
                celula[1].tempL = celula[0].temp;
                celula[ncel].temp = tempRev;
                for (int i = 0; i < ncel; i++) {
                    celula[i].tempini = celula[i].temp;
                }
                for (int itemp = 1; itemp <= ncel; itemp++) {
                    calctemp(itemp, celula[itemp].tempini, 1);
                }
                atualizaProp();
                calcDTPseudoTrans();
            }
        }
    }
    double corrigePresF = 0.;
    if ((*vg1dSP).chaverede == 0 || noextremo == 1 || (*vg1dSP).chaveRedeParalela == 1)
        corrigePresF = RenovaPresPermNcel();
    monitConvPermBase = pGSup;
    return celula[ncel].pres + corrigePresF - pGSup;
}

double SProd::buscaProdPresPresPerm(double chute, double maxvaz, int kontaiter) {
    revPerm = 0;
    monitConvPerm = 1000.;
    double mchute = chute;
    double val = marchaProdPresPres1(mchute);
    buscaIni = 1;
    if (val < -0.9e10) {
        while (val < -0.9e10 && kontaiter < 800) {
            mchute *= 0.9;
            val = marchaProdPresPres1(mchute);
            if (mchute < 1e-5) {
                if ((*vg1dSP).chaverede == 0 && arq.AP == 0)
                    NumError(
                        "Busca de valores iniciais para calculo de zero de funcao em buscaProdPresPresPerm atingiu maximo de iteracoes");
                else {
                    if ((*vg1dSP).iterRede > 0)
                        return -1.1e10;
                    else
                        return 1.1e10;
                }
            }
        }
        val = marchaProdPresPres1(mchute);
        kontaiter++;
    }
    double mchuteAux;
    double mchute2 = mchute;
    double chutelim = 0.;

    double chuteNeg = 0.;
    double chutePos = 0.;
    int testaEscoa = 1;
    double sentido = 1.;
    double val0 = val;
    int reversao = 0;
    int kontaReverso;
    if (fabs(val) < 1e-3)
        return mchute;
    else {
        if (val * sentido < 0.) {
            chuteNeg = mchute;
            kontaReverso = 0;
            while (val * sentido < 0) {
                mchuteAux = mchute2;
                mchute2 *= (1. - arq.buscaFC);
                val = marchaProdPresPres1(mchute2);
                if (val > -0.9e10) {
                    if (val < val0) {
                        kontaReverso++;
                        if (kontaReverso == 2) {
                            reversao = 1;
                            val = 1;
                        } else {
                            arq.buscaFC = -fabs(arq.buscaFC);
                            val0 = val;
                        }
                    } else
                        val0 = val;
                }
                if (val * sentido < 0 && val > -0.9e10)
                    chuteNeg = mchute2;
                kontaiter++;
                double vel = mchute2;
                double bet = celula[1].bet;
                double alf = celula[1].alf;
                double p1 = celula[0].pres;
                double t1 = celula[0].temp;
                double rC = celula[0].fluicol.MasEspFlu(p1, t1);
                double rP = celula[0].flui.MasEspLiq(p1, t1);
                double rG = celula[0].flui.MasEspGas(p1, t1);
                double rmisL = (1 - bet) * rP + bet * rC;
                double rmis = (1 - alf) * rmisL + alf * rG;
                double rCst = celula[0].fluicol.MasEspFlu(1., 20.);
                double rPst = celula[0].flui.MasEspLiq(1., 20.);
                double rGst = celula[0].flui.MasEspGas(1., 20.);
                double rmisLst = (1 - bet) * rPst + bet * rCst;
                double multiplica;
                if (celula[0].acsr.tipo == 2)
                    multiplica = rmisLst;
                else
                    multiplica = rGst;
                vel = mchute2 * multiplica / (rmis * celula[0].duto.area * 86400);
                if (kontaiter > 200 && vel > 0.01) {
                    if ((*vg1dSP).chaverede == 0 && arq.AP == 0)
                        NumError(
                            "Busca de valores iniciais para calculo de zero de funcao em buscaProdPresPresPerm atingiu maximo de iteracoes");
                    else {
                        if ((*vg1dSP).iterRede > 0)
                            return -1.1e10;
                        else
                            return 1.1e10;
                    }
                }
                if (vel <= 0.01) {
                    testaEscoa = 0;
                    val = 1.;
                }
                while (val < -0.9e10) {
                    chutelim = mchute2;
                    mchute2 = 0.5 * (mchute2 + mchuteAux);
                    val = marchaProdPresPres1(mchute2);
                    if (val * sentido < 0 && val > -0.9e10)
                        chuteNeg = mchute2;
                    kontaiter++;
                    if (kontaiter > 200) {
                        if ((*vg1dSP).chaverede == 0 && arq.AP == 0)
                            NumError(
                                "Busca de valores iniciais para calculo de zero de funcao em buscaProdPresPresPerm atingiu maximo de iteracoes");
                        else {
                            if ((*vg1dSP).iterRede > 0)
                                return -1.1e10;
                            else
                                return 1.1e10;
                        }
                    }
                }
            }
            chutePos = mchute2;
        } else if (val * sentido > 0.) {
            chutePos = mchute;
            kontaReverso = 0;
            while (val * sentido > 0) {
                mchuteAux = mchute2;
                mchute2 *= (1. + arq.buscaFC);
                val = marchaProdPresPres1(mchute2);
                if (val > -0.9e10) {
                    if (val > val0) {
                        kontaReverso++;
                        if (kontaReverso == 2) {
                            reversao = 1;
                            val = -1;
                        } else {
                            arq.buscaFC = -fabs(arq.buscaFC);
                            val0 = val;
                        }
                    } else
                        val0 = val;
                }
                if ((*vg1dSP).chaverede != 0 && mchute2 > maxvaz && maxvaz > 0) {
                    testaEscoa = 0;
                    val = -1.;
                }
                if (val * sentido > 0 && val > -0.9e10)
                    chutePos = mchute2;
                kontaiter++;
                if (kontaiter > 200) {
                    if ((*vg1dSP).chaverede == 0 && arq.AP == 0)
                        NumError(
                            "Busca de valores iniciais para calculo de zero de funcao em buscaProdPresPresPerm  atingiu maximo de iteracoes");
                    else {
                        if ((*vg1dSP).iterRede > 0)
                            return -1.1e10;
                        else
                            return 1.1e10;
                    }
                }
                while (val < -0.9e10) {
                    chutelim = mchute2;
                    mchute2 = 0.5 * (mchute2 + mchuteAux);
                    val = marchaProdPresPres1(mchute2);
                    if (val * sentido > 0 && val > -0.9e10)
                        chutePos = mchute2;
                    kontaiter++;

                    if (kontaiter > 200) {
                        if ((*vg1dSP).chaverede == 0 && arq.AP == 0)
                            NumError(
                                "Busca de valores iniciais para calculo de zero de funcao em buscaProdPresPresPerm atingiu maximo de iteracoes");
                        else {
                            if ((*vg1dSP).iterRede > 0)
                                return -1.1e10;
                            else
                                return 1.1e10;
                        }
                    }
                }
            }
            chuteNeg = mchute2;
        }
        if (testaEscoa == 1 && reversao == 0)
            return zriddr(chuteNeg, chutePos, 2, 0);
        else if (reversao == 0) {
            if (celula[0].acsr.tipo == 1) {
                celula[0].acsr.injg.QGas = -2121212121;
            } else if (celula[0].acsr.tipo == 2) {
                celula[0].acsr.injl.QLiq = -2121212121;
            }
            return 0.;
        } else {
            return buscaProdPresPresPermRev(-chute, -maxvaz, kontaiter);
        }
    }
}

double SProd::buscaProdPresPresPermRev(double chute, double maxvaz, int kontaiter) {
    revPerm = 1;
    monitConvPerm = 1000.;
    if (celula[0].acsr.tipo == 1) {
        celula[0].acsr.injg.FluidoPro = fluiRevRede;
    } else if (celula[0].acsr.tipo == 2) {
        celula[0].acsr.injl.FluidoPro = fluiRevRede;
    } else if (celula[0].acsr.tipo == 10) {
        celula[0].acsr.injm.FluidoPro = fluiRevRede;
    }
    double mchute = chute;

    double val = marchaProdPresPres1Rev(mchute);
    buscaIni = 1;
    if (val < -0.9e10) {
        if ((*vg1dSP).chaverede == 0 && arq.AP == 0)
            NumError(
                "Busca de valores iniciais para callculo de zero de funcao em buscaProdPresPresPermRev com problemas, pressao abaixo de 1 kgf/cm2 na marcha reversa");
        else {
            if ((*vg1dSP).iterRede > 0)
                return -1.1e10;
            else
                return 1.1e10;
        }
    }
    double mchuteAux;
    double mchute2 = mchute;
    double chutelim = 0.;
    arq.buscaFC = fabs(arq.buscaFC);

    double chuteNeg = 0.;
    double chutePos = 0.;
    int testaEscoa = 1;
    double val0 = val;
    int reversao = 0;
    if (fabs(val) < 1e-3)
        return mchute;
    else {
        if (val < 0.) {
            chuteNeg = mchute;
            while (val < 0) {
                mchuteAux = mchute2;
                mchute2 *= (1. + arq.buscaFC);
                val = marchaProdPresPres1Rev(mchute2);
                if (val > -0.9e10) {
                    if (val < val0) {
                        reversao = 1;
                        val = 1;
                    } else
                        val0 = val;
                }
                if (val < 0 && val > -0.9e10)
                    chuteNeg = mchute2;
                kontaiter++;
                double vel = mchute2;
                double bet = celula[1].bet;
                double alf = celula[1].alf;
                double p1 = celula[0].pres;
                double t1 = celula[0].temp;
                double rC = celula[0].fluicol.MasEspFlu(p1, t1);
                double rP = celula[0].flui.MasEspLiq(p1, t1);
                double rG = celula[0].flui.MasEspGas(p1, t1);
                double rmisL = (1 - bet) * rP + bet * rC;
                double rmis = (1 - alf) * rmisL + alf * rG;
                double rCst = celula[0].fluicol.MasEspFlu(1., 20.);
                double rPst = celula[0].flui.MasEspLiq(1., 20.);
                double rGst = celula[0].flui.MasEspGas(1., 20.);
                double rmisLst = (1 - bet) * rPst + bet * rCst;
                double multiplica;
                if (celula[0].acsr.tipo == 2)
                    multiplica = rmisLst;
                else
                    multiplica = rGst;
                vel = mchute2 * multiplica / (rmis * celula[0].duto.area * 86400);
                if (kontaiter > 200 && fabs(vel) > 0.01) {
                    if ((*vg1dSP).chaverede == 0 && arq.AP == 0)
                        NumError(
                            "Busca de valores iniciais para calculo de zero de funcao em buscaProdPresPresPermRev atingiu maximo de iteracoes");
                    else {
                        if ((*vg1dSP).iterRede > 0)
                            return -1.1e10;
                        else
                            return 1.1e10;
                    }
                }
                if (fabs(vel) <= 0.01) {
                    testaEscoa = 0;
                    val = 1.;
                }
            }
            chutePos = mchute2;
        } else if (val > 0.) {
            chutePos = mchute;
            while (val > 0) {
                mchuteAux = mchute2;
                mchute2 *= (1. - arq.buscaFC);
                val = marchaProdPresPres1Rev(mchute2);
                if (val > -0.9e10) {
                    if (val > val0) {
                        reversao = 1;
                        val = -1;
                    } else
                        val0 = val;
                }
                if (val > 0 && val > -0.9e10)
                    chutePos = mchute2;
                kontaiter++;
                if (kontaiter > 200) {
                    if ((*vg1dSP).chaverede == 0 && arq.AP == 0)
                        NumError(
                            "Busca de valores iniciais para calculo de zero de funcao em buscaProdPresPresPerm  atingiu maximo de iteracoes");
                    else {
                        if ((*vg1dSP).iterRede > 0)
                            return -1.1e10;
                        else
                            return 1.1e10;
                    }
                }
            }
            chuteNeg = mchute2;
        }
        if (testaEscoa == 1 && reversao == 0)
            return zriddr(chuteNeg, chutePos, 2, 0);
        else if (reversao == 0) {
            if (celula[0].acsr.tipo == 1) {
                celula[0].acsr.injg.QGas = 0.;
            } else if (celula[0].acsr.tipo == 2) {
                celula[0].acsr.injl.QLiq = 0.;
            }
            return 0.;
        } else {
            return buscaProdPresPresPerm(-chute, -maxvaz, kontaiter);
        }
    }
}

double SProd::marchaProdPresPres2(double mchute) {

    int corrigechute = 1;
    double alfini = 0.;
    double betini = 0.;

    if (celula[0].acsr.tipo == 1) {
        celula[0].temp = celula[0].acsr.injg.temp;
        if (arq.flashCompleto == 2) {
            if (arq.tabelaDinamica == 0)
                celula[0].flui.atualizaPropComp(celula[0].pres, celula[0].temp);
            celula[0].acsr.injg.FluidoPro.atualizaPropComp(celula[0].pres, celula[0].temp, -1, NULL, NULL, celula[0].acsr.injg.seco);
        }
        celula[0].acsr.injg.QGas = mchute;
    } else if (celula[0].acsr.tipo == 2) {
        celula[0].temp = celula[0].acsr.injl.temp;
        if (arq.flashCompleto == 2) {
            if (arq.tabelaDinamica == 0)
                celula[0].flui.atualizaPropComp(celula[0].pres, celula[0].temp);
            celula[0].acsr.injl.FluidoPro.atualizaPropComp(celula[0].pres, celula[0].temp);
        }
        celula[0].acsr.injl.QLiq = mchute;
    }

    if (celula[0].acsr.tipo == 1) {
        if (celula[0].acsr.injg.seco == 1) {
            alfini = 1.;
            betini = 0.;
        } else {
            double masgas = celula[0].acsr.injg.VMas(celula[0].pres, celula[0].temp);
            double tit;
            double masT;
            if (arq.ConContEntrada != 1) {
                if (arq.flashCompleto != 2)
                    tit = celula[0].acsr.injg.FluidoPro.FracMassHidra(1., 20.);
                else
                    tit = celula[0].acsr.injg.FluidoPro.dStockTankVaporMassFraction;
                masT = masgas / tit;
                tit = celula[0].acsr.injg.FluidoPro.FracMassHidra(celula[0].pres, celula[0].temp);
            } else {
                tit = titE;
                masT = masgas / tit;
            }
            double qgas = masT * tit /
                          celula[0].acsr.injg.FluidoPro.MasEspGas(celula[0].pres, celula[0].temp);
            double qliq = masT * (1. - tit) /
                          celula[0].acsr.injg.FluidoPro.MasEspLiq(celula[0].pres, celula[0].temp);
            double qcomp = celula[0].acsr.injg.razCompGas *
                           celula[0].acsr.injg.QGas * celula[0].acsr.injg.fluidocol.MasEspFlu(1., 20.) /
                           celula[0].acsr.injg.fluidocol.MasEspFlu(celula[0].pres, celula[0].temp);
            qcomp /= 86400.;
            if (fabs(qliq + qgas) > 1e-15)
                alfini = qgas / (qliq + qcomp + qgas);
            else
                alfini = titE;
            if ((fabs(qcomp) + fabs(qliq)) > 1e-15)
                betini = fabs(qcomp) / (fabs(qcomp) + fabs(qliq));
            else
                betini = 0.;
        }
    } else if (celula[0].acsr.tipo == 2) {
        double qgas = celula[0].acsr.injl.QLiq * (1 - celula[0].acsr.injl.bet) *
                      (1. - celula[0].acsr.injl.FluidoPro.BSW) *
                      (celula[0].acsr.injl.FluidoPro.RGO -
                       celula[0].acsr.injl.FluidoPro.rDgD * celula[0].acsr.injl.FluidoPro.RS(celula[0].pres, celula[0].temp) * 6.29 / 35.31467) *
                      celula[0].acsr.injl.FluidoPro.Deng * 1.225 / celula[0].acsr.injl.FluidoPro.MasEspGas(celula[0].pres, celula[0].temp);
        double qliq = celula[0].acsr.injl.QLiq * (1 - celula[0].acsr.injl.bet) *
                          (1. - celula[0].acsr.injl.FluidoPro.BSW) * celula[0].acsr.injl.FluidoPro.BOFunc(celula[0].pres, celula[0].temp) +
                      celula[0].acsr.injl.QLiq * (1 - celula[0].acsr.injl.bet) *
                          celula[0].acsr.injl.FluidoPro.BSW * celula[0].acsr.injl.FluidoPro.BAFunc(celula[0].pres, celula[0].temp) +
                      celula[0].acsr.injl.QLiq * celula[0].acsr.injl.bet;
        if (fabs(qliq + qgas) > 1e-15)
            alfini = fabs(qgas / (qliq + qgas));
        else
            alfini = titE;
        betini = celula[0].acsr.injl.bet;
    }

    celula[0].tempL = celula[0].temp;
    celula[1].tempL = celula[0].temp;
    celula[0].tempini = celula[0].temp;

    celula[0].ML = 0.;
    celula[0].MC = 0.;
    celula[1].ML = 0.;
    celula[0].MliqiniL = 0.;
    celula[0].Mliqini = 0.;
    celula[1].MliqiniL = 0.;
    celula[0].MComp = 0.;
    celula[0].QLL = 0.;
    celula[0].QL = 0;
    celula[1].QLL = 0.;
    celula[0].QG = 0.;

    int i;

    celula[0].presauxL = celula[0].pres;
    celula[0].presLini = celula[0].pres;
    celula[0].presL = celula[0].pres;
    celula[1].presL = celula[0].pres;
    celula[0].presini = celula[0].pres;
    celula[1].presLini = celula[0].pres;
    celula[0].presaux = celula[0].pres;
    celula[1].presauxL = celula[0].pres;

    celula[0].alf = alfini;
    celula[0].alfini = alfini;
    celula[0].bet = betini;
    celula[0].betini = betini;
    celula[1].alfL = celula[0].alf;
    celula[1].alfLini = celula[0].alf;
    celula[0].alfPigD = celula[0].alf;
    celula[0].alfPigDini = celula[0].alf;
    celula[0].alfPigE = celula[0].alf;
    celula[0].alfPigEini = celula[0].alf;
    celula[1].betL = celula[0].bet;
    celula[1].betLini = celula[0].bet;
    celula[0].betPigD = celula[0].bet;
    celula[0].betPigDini = celula[0].bet;
    celula[0].betPigE = celula[0].bet;
    celula[0].betPigEini = celula[0].bet;
    celula[0].betI = celula[0].bet;
    celula[1].betLI = celula[0].bet;

    iterperm = 0;
    while (iterperm < 3) {
        i = 1;
        while (i <= ncel && celula[i - 1].pres >= 1.) {

            RenovaPresPermMon(i, 0);
            atualizaPeriPmonProd(i);
            if (arq.flashCompleto != 2)
                RenovaMassPerm(i);
            else
                RenovaMassPermComp(i);
            RenovaTempPerm(i, 0);
            if (isnan(celula[i].temp))
                NumError("Temperatrura na linha de producao com valor NaN");
            if (arq.usaTabela == 1 && (celula[i].temp - arq.tabent.tmin) < (*vg1dSP).localtiny)
                celula[i].temp = arq.tabent.tmin;
            atualizaPeriTempProd(i);
            RenovaPresPermJus(i, 0);
            atualizaPeriPjusProd(i);
            if (arq.tipoFluido == 0)
                RenovaTransMassPerm(i - 1);
            else
                RenovaTransMassPermGas(i - 1);
            if (arq.ordperm > 1) {
                double D0presaux = celula[i].presaux - celula[i - 1].pres;
                double D0pres = celula[i].pres - celula[i].presaux;
                double D0temp = celula[i].temp - celula[i - 1].temp;
                RenovaPresPermMon(i, 1);
                atualizaPeriPmonProd(i);
                RenovaMassPerm(i);
                RenovaTempPerm(i, 1);
                RenovaPresPermJus(i, 1);
                celula[i].pres = 0.5 * (celula[i].presaux + D0pres + celula[i].pres);
                celula[i].presaux = 0.5 * (celula[i - 1].pres + D0presaux + celula[i].presaux);
                celula[i].temp = 0.5 * (celula[i - 1].temp + D0temp + celula[i].temp);
                atualizaPeriPjusProd(i);
                atualizaPeriPmonProd(i);
                atualizaPeriTempProd(i);
                RenovaMassPerm(i);
                if (arq.tipoFluido == 0)
                    RenovaTransMassPerm(i - 1);
                else
                    RenovaTransMassPermGas(i - 1);
            }

            i++;
        }
        iterperm++;
    }

    double maxSup;
    if (celula[ncel].pres >= pGSup) {
        double tESup = celula[ncel].temp;
        double alfSup = celula[ncel].alf;
        double betSup = celula[ncel].bet;

        double masentrada = celula[ncel - 1].MR;
        double massgas = celula[ncel - 1].MR - celula[ncel - 1].MliqiniR;
        maxSup = 0.;

        double tit;
        presfim = celula[ncel].pres;
        double rholp = celula[ncel].flui.MasEspLiq(celula[ncel].pres, celula[ncel].temp);
        double rholc = celula[ncel].fluicol.MasEspFlu(celula[ncel].pres, celula[ncel].temp);
        tit = fabs(massgas / masentrada);

        double masChk;

        double ypres = pGSup / presfim;
        masChk = chokeSup.vazmassSachd(ypres, presfim, tESup, alfSup, betSup, tit, celula[ncel - 1].flui,
                                       celula[ncel - 1].fluicol);
        maxSup = chokeSup.vazmaxSachd(presfim, tESup, alfSup, betSup, tit, celula[ncel - 1].flui, celula[ncel - 1].fluicol);
        if (fabs(ypres) > fabs(chokeSup.razpres))
            maxSup = masChk;

        if (chokeSup.AreaGarg > (1e-3) * celula[ncel - 1].duto.area && ypres < 1.) {
            double cplM = (1. - betSup) * celula[ncel].flui.CalorLiq(presfim, tESup) -
                          betSup * celula[ncel].fluicol.CalorLiq(presfim, tESup);
            double jtlM = (1. - betSup) * celula[ncel].flui.JTL(presfim, tESup) - betSup / rholc;
            double cpg = celula[ncel].flui.CalorGas(presfim, tESup);
            double jtgM = celula[ncel].flui.JTG(presfim, tESup);
            arq.valTempChokeJus = tESup + ((1. - tit) * jtlM / cplM + tit * jtgM / cpg) * (pGSup - presfim) * 98066.52;
        }
    } else {
        maxSup = 0.;
        arq.valTempChokeJus = celula[ncel].temp;
    }

    if (fabs(maxSup) > 1e-15)
        monitConvPermBase = fabs(maxSup);
    else
        monitConvPermBase = 1.;
    return maxSup - celula[ncel - 1].MR;
}

double SProd::buscaProdPresPresPerm2(double chute, double maxvaz) {
    revPerm = 0;
    monitConvPerm = 1000.;
    double mchute = chute;
    double val = marchaProdPresPres2(mchute);
    buscaIni = 1;
    int kontaiter = 0;
    if (val < -0.9e10) {
        while (val < -0.9e10 && kontaiter < 400) {
            mchute *= 0.9;
            val = marchaProdPresPres2(mchute);
            if (mchute < 1e-5) {
                if ((*vg1dSP).chaverede == 0 && arq.AP == 0)
                    NumError(
                        "Busca de valores iniciais para calculo de zero de funcao em buscaProdPresPresPerm atingiu maximo de iteracoes");
                else {
                    if ((*vg1dSP).iterRede > 0)
                        return -1.1e10;
                    else
                        return 1.1e10;
                }
            }
            val = marchaProdPresPres2(mchute);
            kontaiter++;
        }
    }
    double mchuteAux;
    double mchute2 = mchute;
    double chutelim = 0.;
    kontaiter = 0;

    double chuteNeg = 0.;
    double chutePos = 0.;

    int testaEscoa = 1;
    if (fabs(val) < 1e-3)
        return mchute;
    else {
        if (val < 0.) {
            chuteNeg = mchute;
            while (val < 0) {
                mchuteAux = mchute2;
                mchute2 *= (1. - arq.buscaFC);
                val = marchaProdPresPres2(mchute2);
                if (val < 0 && val > -0.9e10)
                    chuteNeg = mchute2;
                kontaiter++;
                double vel = mchute2;
                double bet = celula[1].bet;
                double alf = celula[1].alf;
                double p1 = celula[0].pres;
                double t1 = celula[0].temp;
                double rC = celula[0].fluicol.MasEspFlu(p1, t1);
                double rP = celula[0].flui.MasEspLiq(p1, t1);
                double rG = celula[0].flui.MasEspGas(p1, t1);
                double rmisL = (1 - bet) * rP + bet * rC;
                double rmis = (1 - alf) * rmisL + alf * rG;
                double rCst = celula[0].fluicol.MasEspFlu(1., 20.);
                double rPst = celula[0].flui.MasEspLiq(1., 20.);
                double rGst = celula[0].flui.MasEspGas(1., 20.);
                double rmisLst = (1 - bet) * rPst + bet * rCst;
                double multiplica;
                if (celula[0].acsr.tipo == 2)
                    multiplica = rmisLst;
                else
                    multiplica = rGst;
                vel = mchute2 * multiplica / (rmis * celula[0].duto.area * 86400);
                if (kontaiter > 200 && vel > 0.01) {
                    if ((*vg1dSP).chaverede == 0 && arq.AP == 0)
                        NumError(
                            "Busca de valores iniciais para calculo de zero de funcao em buscaProdPresPresPerm atingiu maximo de iteracoes");
                    else {
                        if ((*vg1dSP).iterRede > 0)
                            return -1.1e10;
                        else
                            return 1.1e10;
                    }
                }
                if (vel <= 0.01) {
                    testaEscoa = 0;
                    val = 1.;
                }
                while (val < -0.9e10) {
                    chutelim = mchute2;
                    mchute2 = 0.5 * (mchute2 + mchuteAux);
                    val = marchaProdPresPres2(mchute2);
                    if (val < 0 && val > -0.9e10)
                        chuteNeg = mchute2;
                    kontaiter++;
                    if (kontaiter > 200) {
                        if ((*vg1dSP).chaverede == 0 && arq.AP == 0)
                            NumError(
                                "Busca de valores iniciais para calculo de zero de funcao em buscaProdPresPresPerm atingiu maximo de iteracoes");
                        else {
                            if ((*vg1dSP).iterRede > 0)
                                return -1.1e10;
                            else
                                return 1.1e10;
                        }
                    }
                }
            }
            chutePos = mchute2;
        } else if (val > 0.) {
            chutePos = mchute;
            while (val > 0) {
                mchuteAux = mchute2;
                mchute2 *= (1. + arq.buscaFC);
                val = marchaProdPresPres2(mchute2);
                if ((*vg1dSP).chaverede != 0 && mchute2 > maxvaz) {
                    testaEscoa = 0;
                    val = -1.;
                }
                if (val > 0 && val < 0.9e10)
                    chutePos = mchute2;
                kontaiter++;
                if (kontaiter > 200) {
                    if ((*vg1dSP).chaverede == 0 && arq.AP == 0)
                        NumError(
                            "Busca de valores iniciais para calculo de zero de funcao em buscaProdPresPresPerm  atingiu maximo de iteracoes");
                    else {
                        if ((*vg1dSP).iterRede > 0)
                            return -1.1e10;
                        else
                            return 1.1e10;
                    }
                }
                while (val < -0.9e10) {
                    chutelim = mchute2;
                    mchute2 = 0.5 * (mchute2 + mchuteAux);
                    val = marchaProdPresPres2(mchute2);
                    if (val > 0 && val > -0.9e10)
                        chutePos = mchute2;
                    kontaiter++;

                    if (kontaiter > 200) {
                        if ((*vg1dSP).chaverede == 0 && arq.AP == 0)
                            NumError(
                                "Busca de valores iniciais para calculo de zero de funcao em buscaProdPresPresPerm atingiu maximo de iteracoes");
                        else {
                            if ((*vg1dSP).iterRede > 0)
                                return -1.1e10;
                            else
                                return 1.1e10;
                        }
                    }
                }
            }
            chuteNeg = mchute2;
        }
        if (testaEscoa == 1)
            return zriddr(chuteNeg, chutePos, 2, 1);
        else {
            if (celula[0].acsr.tipo == 1) {
                celula[0].acsr.injg.QGas = 0.;
            } else if (celula[0].acsr.tipo == 2) {
                celula[0].acsr.injl.QLiq = 0.;
            }
            return 0.;
        }
    }
}

