double SProd::buscaInjPfundoPerm2(double chute) {
    double pchute;
    if (chute < 0) {
        if (arq.flashCompleto < 1) {
            if (arq.condpocinj.tipoFlui < 2)
                pchute = celula[ncel].acsr.ipr.Pres + ((celula[0].acsr.injl.QLiq) / (celula[ncel].acsr.ipr.ij));
            else
                pchute = celula[ncel].acsr.ipr.Pres + ((celula[0].acsr.injl.QLiq) * celula[ncel].fluicol.MasEspFlu(1.01, 15.) / (celula[ncel].acsr.ipr.ij * celula[ncel].fluicol.MasEspFlu(celula[ncel].acsr.ipr.Pres, celula[ncel].calor.Textern1)));
            double taux = celula[0].calor.Textern1;
            double rmis;
            double j;
            double f1;

            double visC = celula[0].acsr.injl.fluidocol.VisFlu(pchute, taux);
            double visMis = visC;
            double rC = celula[0].acsr.injl.fluidocol.MasEspFlu(pchute, taux);
            rmis = rC;
            double rlcA = celula[0].acsr.injl.fluidocol.MasEspFlu(1.001, 15.);
            double massicC = rlcA * celula[0].acsr.injl.QLiq / 86400;
            j = (massicC / rC) / celula[0].duto.area;
            double re;
            if (celula[0].duto.revest == 0)
                re = celula[0].Rey(celula[0].duto.a, j, rmis, visMis);
            else {
                double dhid = 4 * celula[0].duto.area / celula[0].duto.peri;
                re = celula[0].Rey(dhid, j, rmis, visMis);
            }
            f1 = celula[0].fric(re, celula[0].duto.rug / celula[0].duto.a);

            double perdafric = (f1 * rmis * j * fabs(j) / 2.) * celula[0].duto.peri / celula[0].duto.area;
            for (int i = ncel; i > 0; i--) {
                double rhol = celula[i].fluicol.MasEspFlu(pchute, taux);
                double dxmed = 0.5 * (celula[i].dx + celula[i - 1].dx);
                pchute += (rhol * 9.81 * sin(celula[i].duto.teta) * dxmed + perdafric * dxmed) / 98066.5;
                if (celula[i - 1].acsr.tipo == 3 && (celula[i - 1].acsr.ipr.Pres - pchute) > -(*vg1dSP).localtiny)
                    pchute = 1.01 * celula[i - 1].acsr.ipr.Pres;
                taux = celula[i].calor.Textern1;
            }
        } else {
            pchute = celula[ncel].acsr.ipr.Pres + ((celula[0].acsr.injg.QGas) * (celula[0].flui.Deng * 1.225) / (celula[ncel].acsr.ipr.ij * celula[ncel].flui.MasEspGas(celula[ncel].acsr.ipr.Pres, celula[ncel].calor.Textern1)));
            double taux = celula[0].calor.Textern1;
            double rmis;
            double j;
            double f1;

            double visC = celula[0].acsr.injg.FluidoPro.ViscGas(pchute, taux);
            double visMis = visC;
            double rC = celula[0].acsr.injg.FluidoPro.MasEspGas(pchute, taux);
            rmis = rC;
            double rlcA = (celula[0].flui.Deng * 1.225);
            double massicC = rlcA * celula[0].acsr.injg.QGas / 86400;
            j = (massicC / rC) / celula[0].duto.area;
            double re;
            if (celula[0].duto.revest == 0)
                re = celula[0].Rey(celula[0].duto.a, j, rmis, visMis);
            else {
                double dhid = 4 * celula[0].duto.area / celula[0].duto.peri;
                re = celula[0].Rey(dhid, j, rmis, visMis);
            }
            f1 = celula[0].fric(re, celula[0].duto.rug / celula[0].duto.a);

            double perdafric = (f1 * rmis * j * fabs(j) / 2.) * celula[0].duto.peri / celula[0].duto.area;
            for (int i = ncel; i > 0; i--) {
                double rhol = celula[i].flui.MasEspGas(pchute, taux);
                double dxmed = 0.5 * (celula[i].dx + celula[i - 1].dx);
                pchute += (rhol * 9.81 * sin(celula[i].duto.teta) * dxmed + perdafric * dxmed) / 98066.5;
                if (celula[i - 1].acsr.tipo == 3 && (celula[i - 1].acsr.ipr.Pres - pchute) > -(*vg1dSP).localtiny)
                    pchute = 1.01 * celula[i - 1].acsr.ipr.Pres;
                taux = celula[i].calor.Textern1;
            }
        }
    } else
        pchute = chute;
    if (pchute <= 1)
        pchute = 1.01;
    double pchute2;
    double pchuteAux = 0.;
    double val;
    val = marchaInjPerm1(pchute);
    int kontaiter = 0;
    if (val < -0.9e10) {
        while (val < -0.9e10) {
            pchute *= 1.1;
            val = marchaInjPerm1(pchute);
            kontaiter++;
            if (kontaiter > 200) {
                if ((*vg1dSP).chaverede == 0 && arq.AP == 0)
                    NumError(
                        "PoÃ§o injetor com problemas na iteracao na busca de um chute de pressao inicial, perda de carga muito alta");
                else {
                    if ((*vg1dSP).iterRede > 0)
                        return -1.1e10;
                    else
                        return 1.1e10;
                }
            }
        }
    } else if (val > 0.9e10) {
        while (val > 0.9e10) {
            pchute *= 0.9;
            val = marchaInjPerm1(pchute);
            kontaiter++;
            if (kontaiter > 200) {
                if ((*vg1dSP).chaverede == 0 && arq.AP == 0)
                    NumError(
                        "PoÃ§o injetor com problemas na iteracao na busca de um chute de vazao inicial, pressao muito alta");
                else {
                    if ((*vg1dSP).iterRede > 0)
                        return -1.1e10;
                    else
                        return 1.1e10;
                }
            }
        }
    }
    kontaiter = 0;
    pchute2 = pchute;
    double chuteNeg = 0.;
    double chutePos = 0.;
    if (fabs(val) < 1e-15)
        return pchute;
    else {
        if (val < 0.) {
            chuteNeg = pchute;
            while (val < 0) {
                pchuteAux = pchute2;
                pchute2 *= 0.9;
                if (pchute2 < 1.) {
                    pchute2 = pchuteAux;
                    pchute2 *= 0.99;
                    if (pchute2 < 1. && arq.AP == 0)
                        NumError("Pressao de injecao abaixo da pressao atmosferica");
                    else if (pchute2 < 1.)
                        return 1.1e10;
                }
                val = marchaInjPerm1(pchute2);
                kontaiter++;
                if (kontaiter > 200) {
                    if ((*vg1dSP).chaverede == 0 && arq.AP == 0)
                        NumError(
                            "Busca de valores iniciais para calculo de zero de funcao em buscaInjPfundoPerm2 atingiu maximo de iteracoes");
                    else {
                        if ((*vg1dSP).iterRede > 0)
                            return -1.1e10;
                        else
                            return 1.1e10;
                    }
                }
                while (val < -0.9e10) {
                    pchute2 = 0.5 * (pchute2 + pchuteAux);
                    val = marchaInjPerm1(pchute2);
                    kontaiter++;
                    if (kontaiter > 200) {
                        if ((*vg1dSP).chaverede == 0 && arq.AP == 0)
                            NumError(
                                "Busca de valores iniciais para calculo de zero de funcao em buscaInjPfundoPerm2 atingiu maximo de iteracoes");
                        else {
                            if ((*vg1dSP).iterRede > 0)
                                return -1.1e10;
                            else
                                return 1.1e10;
                        }
                    }
                }
            }
            chutePos = pchute2;
        } else if (val > 0.) {
            chutePos = pchute;
            while (val > 0) {
                pchuteAux = pchute2;
                pchute2 *= 1.1;
                val = marchaInjPerm1(pchute2);
                kontaiter++;
                if (kontaiter > 200) {
                    if ((*vg1dSP).chaverede == 0 && arq.AP == 0)
                        NumError(
                            "Busca de valores iniciais para calculo de zero de funcao em buscaInjPfundoPerm2 atingiu maximo de iteracoes");
                    else {
                        if ((*vg1dSP).iterRede > 0)
                            return -1.1e10;
                        else
                            return 1.1e10;
                    }
                }
                while (val > 0.9e10) {
                    pchute2 = 0.5 * (pchute2 + pchuteAux);
                    val = marchaInjPerm1(pchute2);
                    kontaiter++;
                    if (kontaiter > 200) {
                        if ((*vg1dSP).chaverede == 0 && arq.AP == 0)
                            NumError(
                                "Busca de valores iniciais para calculo de zero de funcao em buscaInjPfundoPerm2 atingiu maximo de iteracoes");
                        else {
                            if ((*vg1dSP).iterRede > 0)
                                return -1.1e10;
                            else
                                return 1.1e10;
                        }
                    }
                }
            }
            chuteNeg = pchute2;
        }
        return zriddr(chuteNeg, chutePos, 1, 0);
    }
}

